('yuding-1','袍中詩','開元宮人','唐','御定全唐诗','yuding','','[]','沙場征戍客，寒苦若為眠。戰袍經手作，知落阿誰邊。',48,'御定全唐詩/json/797.json','["沙場征戍客，寒苦若為眠。戰袍經手作，知落阿誰邊。", "蓄意多添線，含情更著綿。今生已過也，結取後生緣。"]'),
('yuding-2','題洛苑梧葉上','天寶宮人','唐','御定全唐诗','yuding','','[]','舊寵悲秋扇，新恩寄早春。聊題一片葉，將寄接流人。',24,'御定全唐詩/json/797.json','["舊寵悲秋扇，新恩寄早春。聊題一片葉，將寄接流人。"]'),
('yuding-3','又題','天寶宮人','唐','御定全唐诗','yuding','','[]','一葉題詩出禁城，誰人酬和獨含情。',32,'御定全唐詩/json/797.json','["一葉題詩出禁城，誰人酬和獨含情。", "自嗟不及波中葉，蕩漾乘春取次行。"]'),
('yuding-4','題花葉詩','德宗宮人','唐','御定全唐诗','yuding','','[]','一入深宮裏，無由得見春。題詩花葉上，寄與接流人。',24,'御定全唐詩/json/797.json','["一入深宮裏，無由得見春。題詩花葉上，寄與接流人。"]'),
('yuding-5','題紅葉','宣宗宮人','唐','御定全唐诗','yuding','','[]','流水何太急，深宮盡日閑。殷勤謝紅葉，好去到人間。',24,'御定全唐詩/json/797.json','["流水何太急，深宮盡日閑。殷勤謝紅葉，好去到人間。"]'),
('yuding-6','金鎖詩','僖宗宮人','唐','御定全唐诗','yuding','','[]','玉燭制袍夜，金刀呵手裁。鎖寄千里客，鎖心終不開。',24,'御定全唐詩/json/797.json','["玉燭制袍夜，金刀呵手裁。鎖寄千里客，鎖心終不開。"]'),
('yuding-7','隨駕遊青城','李舜弦','唐','御定全唐诗','yuding','','[]','因隨八馬上仙山，頓隔塵埃物象閑。',32,'御定全唐詩/json/797.json','["因隨八馬上仙山，頓隔塵埃物象閑。", "只恐西追王母宴，卻憂難得到人間。"]'),
('yuding-8','蜀宮應制','李舜弦','唐','御定全唐诗','yuding','','[]','濃樹禁花開後庭，飲筵中散酒微醒。',32,'御定全唐詩/json/797.json','["濃樹禁花開後庭，飲筵中散酒微醒。", "濛濛雨草瑤階濕，鐘曉愁吟獨倚屏。"]'),
('yuding-9','釣魚不得','李舜弦','唐','御定全唐诗','yuding','','[]','盡日池邊釣錦鱗，芰荷香裏暗消魂。',32,'御定全唐詩/json/797.json','["盡日池邊釣錦鱗，芰荷香裏暗消魂。", "依稀縱有尋香餌，知是金鉤不肯吞。"]'),
('yuding-10','宮詞','李玉簫','唐','御定全唐诗','yuding','','[]','鴛鴦瓦上瞥然聲，晝寢宮娥夢裏驚。',32,'御定全唐詩/json/797.json','["鴛鴦瓦上瞥然聲，晝寢宮娥夢裏驚。", "元是我王金彈子，海棠花下打流鶯。"]'),
('yuding-11','太平詩','金真德','唐','御定全唐诗','yuding','','[]','大唐開鴻業，巍巍皇猷昌。止戈戎衣定，修文繼百王。',120,'御定全唐詩/json/797.json','["大唐開鴻業，巍巍皇猷昌。止戈戎衣定，修文繼百王。", "統天崇雨施，理物體含章。深仁諧日月，撫運邁時康。", "幡旗既赫赫，鉦鼓何鍠鍠。外夷違命者，翦覆被大殃。", "和風凝宇宙，遐邇競呈祥。四時調玉燭，七曜巡萬方。", "維嶽降宰輔，維帝用忠良。三五咸一德，昭我皇家唐。"]'),
('yuding-12','句','寶曆宮人','唐','御定全唐诗','yuding','','[]','寶帳香重重，一雙紅芙蓉。',12,'御定全唐詩/json/797.json','["寶帳香重重，一雙紅芙蓉。"]'),
('yuding-0','宮詞','花蕊夫人','唐','御定全唐诗','yuding','','[]','五雲樓閣鳳城間，花木長新日月閑。',384,'御定全唐詩/json/798.json','["五雲樓閣鳳城間，花木長新日月閑。", "三十六宮連內苑，太平天子住昆山。", "會真廣殿約宮牆，樓閣相扶倚太陽。", "淨甃玉階橫水岸，禦爐香氣撲龍床。", "龍池九曲遠相通，楊柳絲牽兩岸風。", "長似江南好風景，畫船來去碧波中。", "東內斜將紫禁通，龍池鳳苑夾城中。", "曉鐘聲斷嚴妝罷，院院紗窗海日紅。", "殿名新立號重光，島上亭台盡改張。", "但是一人行幸處，黃金閣子鎖牙床。", "夾城門與內門通，朝罷巡遊到苑中。", "每日日高祗候處，滿堤紅豔立春風。", "廚船進食簇時新，侍宴無非列近臣。", "日午殿頭宣索鱠，隔花催喚打魚人。", "立春日進內園花，紅蕊輕輕嫩淺霞。", "跪到玉階猶帶露，一時宣賜與宮娃。", "三面宮城盡夾牆，苑中池水白茫茫。", "直從獅子門前入，旋見亭台繞岸傍。", "離宮別院繞宮城，金版輕敲合鳳笙。", "夜夜月明花樹底，傍池長有按歌聲。", "禦制新翻曲子成，六宮才唱未知名。", "盡將觱篥來抄譜，先按君王玉笛聲。", "旋移紅樹斫新苔，宣使龍池更鑿開。", "展得綠波寬似海，水心樓殿勝蓬萊。"]'),
('yuding-1','述國亡詩','花蕊夫人','唐','御定全唐诗','yuding','','[]','君王城上豎降旗，妾在深宮那得知。',32,'御定全唐詩/json/798.json','["君王城上豎降旗，妾在深宮那得知。", "十四萬人齊解甲，寧無一個是男兒。"]'),
('yuding-0','新妝詩','楊容華','唐','御定全唐诗','yuding','','[]','啼鳥驚眠罷，房櫳乘曉開。鳳釵金作縷，鸞鏡玉為台。',48,'御定全唐詩/json/799.json','["啼鳥驚眠罷，房櫳乘曉開。鳳釵金作縷，鸞鏡玉為台。", "妝似臨池出，人疑向月來。自憐終不見，欲去複裴回。"]'),
('yuding-1','贈外','魏氏','唐','御定全唐诗','yuding','','[]','浮萍依綠水，弱蔦寄青松。與君結大義，移天得所從。',204,'御定全唐詩/json/799.json','["浮萍依綠水，弱蔦寄青松。與君結大義，移天得所從。", "翰林無雙鳥，劍水不分龍。諧和類琴瑟，堅固同膠漆。", "義重恩欲深，夷險貴如一。本自身不令，積多嬰痛疾。", "朝夕倦床枕，形體恥巾櫛。遊子倦風塵，從官初解巾。", "束裝赴南郢，脂駕出西秦。比翼終難遂，銜雌苦未因。", "徒悲楓岸遠，空對柳園春。男兒不重舊，丈夫多好新。", "新人喜新聘，朝朝臨粉鏡。兩鴛固無比，雙蛾誰與競。", "詎憐愁思人，銜啼嗟薄命。蕣華不足恃，松枝有餘勁。", "所願好九思，勿令虧百行。"]'),
('yuding-2','詠破簾','喬氏','唐','御定全唐诗','yuding','','[]','已漏風聲罷，繩持也不禁。一從經落後，無複有貞心。',24,'御定全唐詩/json/799.json','["已漏風聲罷，繩持也不禁。一從經落後，無複有貞心。"]'),
('yuding-3','送兄','七歲女子','唐','御定全唐诗','yuding','','[]','別路雲初起，離亭葉正飛。所嗟人異雁，不作一行歸。',24,'御定全唐詩/json/799.json','["別路雲初起，離亭葉正飛。所嗟人異雁，不作一行歸。"]'),
('yuding-4','送男左貶詩','林氏','唐','御定全唐诗','yuding','','[]','他日初投杼，勤王在飲冰。有辭期不罰，積毀竟相仍。',96,'御定全唐詩/json/799.json','["他日初投杼，勤王在飲冰。有辭期不罰，積毀竟相仍。", "謫宦今何在，銜冤猶未勝。天涯分越徼，驛騎速毗陵。", "腸斷腹非苦，書傳寫豈能。淚添江水遠，心劇海雲蒸。", "明月珠難識，甘泉賦可稱。但將忠報主，何懼點青蠅。"]'),
('yuding-5','古興','趙氏1','唐','御定全唐诗','yuding','','[]','郁蒸夏將半，暑氣扇飛閣。驟雨滿空來，當軒卷羅幕。',192,'御定全唐詩/json/799.json','["郁蒸夏將半，暑氣扇飛閣。驟雨滿空來，當軒卷羅幕。", "度雲開夕霽，宇宙何清廓。明月流素光，輕風換炎鑠。", "孤鸞傷對影，寶瑟悲別鶴。君子去不還，遙心欲何托。", "金菊延清霜，玉壺多美酒。良人猶不歸，芳菲豈常有。", "不惜芳菲歇，但傷別離久。含情罷斟酌，凝怨對窗牖。", "霽雪舒長野，寒雲半幽谷。嚴風振枯條，猿啼抱冰木。", "所嗟遊宦子，少小荷天祿。前程未雲至，悽愴對車僕。", "歲寒成詠歌，日暮棲林樸。不憚行險道，空悲年運促。"]'),
('yuding-6','寄夫','郭紹蘭','唐','御定全唐诗','yuding','','[]','我婿去重湖，臨窗泣血書。殷勤憑燕翼，寄與薄情夫。',24,'御定全唐詩/json/799.json','["我婿去重湖，臨窗泣血書。殷勤憑燕翼，寄與薄情夫。"]'),
('yuding-7','同夫游秦','王韞秀','唐','御定全唐诗','yuding','','[]','路掃饑寒跡，天哀志氣人。休零離別淚，攜手入西秦。',24,'御定全唐詩/json/799.json','["路掃饑寒跡，天哀志氣人。休零離別淚，攜手入西秦。"]'),
('yuding-8','夫入相寄姨妹','王韞秀','唐','御定全唐诗','yuding','','[]','相國已隨麟閣貴，家風第一右丞詩。',32,'御定全唐詩/json/799.json','["相國已隨麟閣貴，家風第一右丞詩。", "笄年解笑鳴機婦，恥見蘇秦富貴時。"]'),
('yuding-9','喻夫阻客','王韞秀','唐','御定全唐诗','yuding','','[]','楚竹燕歌動畫梁，春蘭重換舞衣裳。',32,'御定全唐詩/json/799.json','["楚竹燕歌動畫梁，春蘭重換舞衣裳。", "公孫開閣招嘉客，知道浮榮不久長。"]'),
('yuding-10','古意','張夫人','唐','御定全唐诗','yuding','','[]','轆轤曉轉素絲綆，桐聲夜落蒼苔磚。涓涓吹溜若時雨，',24,'御定全唐詩/json/799.json','["轆轤曉轉素絲綆，桐聲夜落蒼苔磚。涓涓吹溜若時雨，"]'),
('yuding-11','拜新月','張夫人','唐','御定全唐诗','yuding','','[]','拜新月，拜月出堂前。暗魄初籠桂，虛弓未引弦。拜新月，',50,'御定全唐詩/json/799.json','["拜新月，拜月出堂前。暗魄初籠桂，虛弓未引弦。拜新月，", "東家阿母亦拜月，一拜一悲聲斷絕。昔年拜月逞容輝，"]'),
('yuding-12','柳絮','張夫人','唐','御定全唐诗','yuding','','[]','靄靄芳春朝，雪絮起青條。或值花同舞，不因風自飄。',48,'御定全唐詩/json/799.json','["靄靄芳春朝，雪絮起青條。或值花同舞，不因風自飄。", "過尊浮綠醑，拂幌綴紅綃。那用持愁玩，春懷不自聊。"]'),
('yuding-13','拾得韋氏花鈿以詩寄贈','張夫人','唐','御定全唐诗','yuding','','[]','今朝妝閣前，拾得舊花鈿。粉污痕猶在，塵侵色尚鮮。',48,'御定全唐詩/json/799.json','["今朝妝閣前，拾得舊花鈿。粉污痕猶在，塵侵色尚鮮。", "曾經纖手裏，拈向翠眉邊。能助千金笑，如何忍棄捐。"]'),
('yuding-14','誚喜鵲','張夫人','唐','御定全唐诗','yuding','','[]','疇昔鴛鴦侶，朱門賀客多。如今無此事，好去莫相過。',24,'御定全唐詩/json/799.json','["疇昔鴛鴦侶，朱門賀客多。如今無此事，好去莫相過。"]'),
('yuding-15','句','張夫人','唐','御定全唐诗','yuding','','[]','游蜂乍起驚落墀，黃鳥銜來卻上枝。',40,'御定全唐詩/json/799.json','["游蜂乍起驚落墀，黃鳥銜來卻上枝。", "臨風重回首，掩淚向庭花。", "鏡中春色老，枕前秋夜長。"]'),
('yuding-16','書石壁','王氏','唐','御定全唐诗','yuding','','[]','何事潘郎戀別筵，歡情未斷妾心懸。',32,'御定全唐詩/json/799.json','["何事潘郎戀別筵，歡情未斷妾心懸。", "汰王灘下相思處，猿叫山山月滿船。"]'),
('yuding-17','答微之','裴淑','唐','御定全唐诗','yuding','','[]','侯門初擁節，御苑柳絲新。不是悲殊命，唯愁別近親。',48,'御定全唐詩/json/799.json','["侯門初擁節，御苑柳絲新。不是悲殊命，唯愁別近親。", "黃鶯遷古木，朱履從清塵。想到千山外，滄江正暮春。"]'),
('yuding-18','夫下第','趙氏2','唐','御定全唐诗','yuding','','[]','良人的的有奇才，何事年年被放回。',32,'御定全唐詩/json/799.json','["良人的的有奇才，何事年年被放回。", "如今妾面羞君面，君若來時近夜來。"]'),
('yuding-19','雜言寄杜羔','趙氏2','唐','御定全唐诗','yuding','','[]','君從淮海遊，再過蘭杜秋。歸來未須臾，又欲向梁州。',92,'御定全唐詩/json/799.json','["君從淮海遊，再過蘭杜秋。歸來未須臾，又欲向梁州。", "梁州秦嶺西，棧道與雲齊。羌蠻萬餘落，矛戟自高低。", "已念寡儔侶，複慮勞攀躋。丈夫重志氣，兒女空悲啼。", "臨邛滯遊地，肯顧濁水泥。人生賦命有厚薄，"]'),
('yuding-20','聞夫杜羔登第','趙氏2','唐','御定全唐诗','yuding','','[]','長安此去無多地，鬱鬱蔥蔥佳氣浮。',32,'御定全唐詩/json/799.json','["長安此去無多地，鬱鬱蔥蔥佳氣浮。", "良人得意正年少，今夜醉眠何處樓。"]'),
('yuding-21','雜言','趙氏2','唐','御定全唐诗','yuding','','[]','上林園中青青桂，折得一枝好夫婿。',32,'御定全唐詩/json/799.json','["上林園中青青桂，折得一枝好夫婿。", "杏花如雪柳垂絲，春風蕩颺不同枝。"]'),
('yuding-22','寄夫','張氏','唐','御定全唐诗','yuding','','[]','久無音信到羅幃，路遠迢迢遣問誰。',64,'御定全唐詩/json/799.json','["久無音信到羅幃，路遠迢迢遣問誰。", "聞君折得東堂桂，折罷那能不暫歸。", "驛使今朝過五湖，殷勤為我報狂夫。", "從來誇有龍泉劍，試割相思得斷無。"]'),
('yuding-23','贈鄭女郎','薛馧','唐','御定全唐诗','yuding','','[]','豔陽灼灼河洛神，珠簾繡戶青樓春。能彈箜篌弄纖指，',72,'御定全唐詩/json/799.json','["豔陽灼灼河洛神，珠簾繡戶青樓春。能彈箜篌弄纖指，", "朝理曲，暮理曲，獨坐窗前一片玉。行也嬌，坐也嬌，", "解佩時時歇歌管，芙蓉帳裏蘭麝滿。晚起羅衣香不斷，"]'),
('yuding-24','古意','薛馧','唐','御定全唐诗','yuding','','[]','昨夜巫山中，失卻陽臺女。朝來香閣裏，獨伴楚王語。',24,'御定全唐詩/json/799.json','["昨夜巫山中，失卻陽臺女。朝來香閣裏，獨伴楚王語。"]'),
('yuding-25','贈故人','薛馧','唐','御定全唐诗','yuding','','[]','昔別容如玉，今來鬢若絲。淚痕應共見，腸斷阿誰知。',24,'御定全唐詩/json/799.json','["昔別容如玉，今來鬢若絲。淚痕應共見，腸斷阿誰知。"]'),
('yuding-26','句','薛馧','唐','御定全唐诗','yuding','','[]','寂寞相思處，雕梁落燕泥。',12,'御定全唐詩/json/799.json','["寂寞相思處，雕梁落燕泥。"]'),
('yuding-27','題奉慈寺','楊德麟','唐','御定全唐诗','yuding','','[]','日月金輪動，旃檀碧樹秋。塔分鴻雁翅，鐘掛鳳凰樓。',24,'御定全唐詩/json/799.json','["日月金輪動，旃檀碧樹秋。塔分鴻雁翅，鐘掛鳳凰樓。"]'),
('yuding-28','述懷','崔氏','唐','御定全唐诗','yuding','','[]','不怨盧郎年紀大，不怨盧郎官職卑。',32,'御定全唐詩/json/799.json','["不怨盧郎年紀大，不怨盧郎官職卑。", "自恨妾身生較晚，不及盧郎年少時。"]'),
('yuding-29','寄夫','陳玉蘭','唐','御定全唐诗','yuding','','[]','夫戍邊關妾在吳，西風吹妾妾憂夫。',32,'御定全唐詩/json/799.json','["夫戍邊關妾在吳，西風吹妾妾憂夫。", "一行書信千行淚，寒到君邊衣到無。"]'),
('yuding-30','寫真寄夫','薛媛','唐','御定全唐诗','yuding','','[]','欲下丹青筆，先拈寶鏡寒。已經顏索寞，漸覺鬢凋殘。',48,'御定全唐詩/json/799.json','["欲下丹青筆，先拈寶鏡寒。已經顏索寞，漸覺鬢凋殘。", "淚眼描將易，愁腸寫出難。恐君渾忘卻，時展畫圖看。"]'),
('yuding-31','聞琴','孫氏','唐','御定全唐诗','yuding','','[]','玉指朱弦軋複清，湘妃愁怨最難聽。初疑颯颯涼風勁，',40,'御定全唐詩/json/799.json','["玉指朱弦軋複清，湘妃愁怨最難聽。初疑颯颯涼風勁，", "夜深彈罷堪惆悵，露濕叢蘭月滿庭。"]'),
('yuding-32','白蠟燭詩','孫氏','唐','御定全唐诗','yuding','','[]','景勝銀釭香比蘭，一條白玉偪人寒。',32,'御定全唐詩/json/799.json','["景勝銀釭香比蘭，一條白玉偪人寒。", "他時紫禁春風夜，醉草天書仔細看。"]'),
('yuding-33','謝人送酒','孫氏','唐','御定全唐诗','yuding','','[]','謝將清酒寄愁人，澄澈甘香氣味真。',32,'御定全唐詩/json/799.json','["謝將清酒寄愁人，澄澈甘香氣味真。", "好是綠窗風月夜，一杯搖盪滿懷春。"]'),
('yuding-34','詩','張立本女','唐','御定全唐诗','yuding','','[]','危冠廣袖楚宮妝，獨步閒庭逐夜涼。',32,'御定全唐詩/json/799.json','["危冠廣袖楚宮妝，獨步閒庭逐夜涼。", "自把玉簪敲砌竹，清歌一曲月如霜。"]'),
('yuding-35','繡龜形詩','侯氏','唐','御定全唐诗','yuding','','[]','暌離已是十秋強，對鏡那堪重理妝。聞雁幾回修尺素，',40,'御定全唐詩/json/799.json','["暌離已是十秋強，對鏡那堪重理妝。聞雁幾回修尺素，", "繡作龜形獻天子，願教征客早還鄉。"]'),
('yuding-36','感夫詩','慎氏','唐','御定全唐诗','yuding','','[]','當時心事已相關，雨散雲飛一餉間。',32,'御定全唐詩/json/799.json','["當時心事已相關，雨散雲飛一餉間。", "便是孤帆從此去，不堪重上望夫山。"]'),
('yuding-37','謠','薛瑤','唐','御定全唐诗','yuding','','[]','化雲心兮思淑貞，洞寂滅兮不見人。瑤草芳兮思芬蒀，',24,'御定全唐詩/json/799.json','["化雲心兮思淑貞，洞寂滅兮不見人。瑤草芳兮思芬蒀，"]'),
('yuding-38','題唐安寺閣壁','王霞卿','唐','御定全唐诗','yuding','','[]','春來引步暫尋遊，愁見風光倚寺樓。',32,'御定全唐詩/json/799.json','["春來引步暫尋遊，愁見風光倚寺樓。", "正好開懷對煙月，雙眉不覺自如鉤。"]'),
('yuding-39','答鄭殷彝','王霞卿','唐','御定全唐诗','yuding','','[]','君是煙霄折桂身，聖朝方切用儒珍。',32,'御定全唐詩/json/799.json','["君是煙霄折桂身，聖朝方切用儒珍。", "正堪西上文場戰，空向途中泥婦人。"]'),
('yuding-40','喜盧郎及第','竇梁賓','唐','御定全唐诗','yuding','','[]','曉妝初罷眼初瞤，小玉驚人踏破裙。',32,'御定全唐詩/json/799.json','["曉妝初罷眼初瞤，小玉驚人踏破裙。", "手把紅箋書一紙，上頭名字有郎君。"]'),
('yuding-41','雨中看牡丹','竇梁賓','唐','御定全唐诗','yuding','','[]','東風未放曉泥幹，紅藥花開不奈寒。',32,'御定全唐詩/json/799.json','["東風未放曉泥幹，紅藥花開不奈寒。", "待得天晴花已老，不如攜手雨中看。"]'),
('yuding-42','書桐葉','任氏','唐','御定全唐诗','yuding','','[]','拭翠斂蛾眉，鬱鬱心中事。搦管下庭除，書成相思字。',84,'御定全唐詩/json/799.json','["拭翠斂蛾眉，鬱鬱心中事。搦管下庭除，書成相思字。", "此字不書石，此字不書紙。書在桐葉上，願逐秋風起。", "天下有心人，盡解相思死。天下負心人，不識相思字。", "有心與負心，不知落何地。"]'),
('yuding-43','下獄貢詩','黃崇嘏','唐','御定全唐诗','yuding','','[]','偶辭幽隱在臨邛，行止堅貞比澗松。',32,'御定全唐詩/json/799.json','["偶辭幽隱在臨邛，行止堅貞比澗松。", "何事政清如水鏡，絆他野鶴在深籠。"]'),
('yuding-44','辭蜀相妻女詩','黃崇嘏','唐','御定全唐诗','yuding','','[]','一辭拾翠碧江湄，貧守蓬茅但賦詩。自服藍衫居郡掾，',40,'御定全唐詩/json/799.json','["一辭拾翠碧江湄，貧守蓬茅但賦詩。自服藍衫居郡掾，", "幕府若容為坦腹，願天速變作男兒。"]'),
('yuding-45','答諸姊妹戒飲','蔣氏','唐','御定全唐诗','yuding','','[]','平生偏好酒，勞爾勸吾餐。但得杯中滿，時光度不難。',24,'御定全唐詩/json/799.json','["平生偏好酒，勞爾勸吾餐。但得杯中滿，時光度不難。"]'),
('yuding-46','書壁','周仲美','唐','御定全唐诗','yuding','','[]','愛妾不愛子，為問此何理。棄官更棄妻，人情寧可已。',84,'御定全唐詩/json/799.json','["愛妾不愛子，為問此何理。棄官更棄妻，人情寧可已。", "永訣泗之濱，遺言空在耳。三載無朝昏，孤幃淚如洗。", "婦人義從夫，一節誓生死。江鄉感殘春，腸斷晚煙起。", "西望太華峰，不知幾千里。"]'),
('yuding-47','溪口雲','張文姬','唐','御定全唐诗','yuding','','[]','溶溶溪口雲，才向溪中吐。不復歸溪中，還作溪中雨。',24,'御定全唐詩/json/799.json','["溶溶溪口雲，才向溪中吐。不復歸溪中，還作溪中雨。"]'),
('yuding-48','池上竹','張文姬','唐','御定全唐诗','yuding','','[]','此君臨此池，枝低水相近。碧色綠波中，日日流不盡。',24,'御定全唐詩/json/799.json','["此君臨此池，枝低水相近。碧色綠波中，日日流不盡。"]'),
('yuding-49','沙上鷺','張文姬','唐','御定全唐诗','yuding','','[]','沙頭一水禽，鼓翼揚清音。只待高風便，非無雲漢心。',24,'御定全唐詩/json/799.json','["沙頭一水禽，鼓翼揚清音。只待高風便，非無雲漢心。"]'),
('yuding-50','雙槿樹','張文姬','唐','御定全唐诗','yuding','','[]','綠影競扶疏，紅姿相照灼。不學桃李花，亂向春風落。',24,'御定全唐詩/json/799.json','["綠影競扶疏，紅姿相照灼。不學桃李花，亂向春風落。"]'),
('yuding-51','獄中書情上使君','程長文','唐','御定全唐诗','yuding','','[]','妾家本住鄱陽曲，一片貞心比孤竹。當年二八盛容儀。',144,'御定全唐詩/json/799.json','["妾家本住鄱陽曲，一片貞心比孤竹。當年二八盛容儀。", "紅箋草隸恰如飛。盡日閑窗刺繡坐，有時極浦採蓮歸。", "誰道居貧守都邑，幽閨寂寞無人識。海燕朝歸衾枕寒，", "一命任從刀下死，千金豈受暗中欺。我心匪石情難轉，", "縣僚曾未知情緒，即便教人縶囹圄。朱唇滴瀝獨銜冤，", "高髻不梳雲已散，蛾眉罷掃月仍新。三尺嚴章難可越，"]'),
('yuding-52','銅雀台怨','程長文','唐','御定全唐诗','yuding','','[]','君王去後行人絕，簫箏不響歌喉咽。雄劍無威光彩沈，',40,'御定全唐詩/json/799.json','["君王去後行人絕，簫箏不響歌喉咽。雄劍無威光彩沈，", "當時歌舞人不回，化為今日西陵灰。"]'),
('yuding-53','春閨怨','程長文','唐','御定全唐诗','yuding','','[]','綺陌香飄柳如線，時光瞬息如流電。',32,'御定全唐詩/json/799.json','["綺陌香飄柳如線，時光瞬息如流電。", "良人何處事功名，十載相思不相見。"]'),
('yuding-0','答韓翃','柳氏','唐','御定全唐诗','yuding','','[]','楊柳枝，芳菲節，可恨年年贈離別。一葉隨風忽報秋，',24,'御定全唐詩/json/800.json','["楊柳枝，芳菲節，可恨年年贈離別。一葉隨風忽報秋，"]'),
('yuding-1','歸李江州後寄別王氏','程洛賓','唐','御定全唐诗','yuding','','[]','魚雁回時寫報音，難憑銼蘖數年心。',32,'御定全唐詩/json/800.json','["魚雁回時寫報音，難憑銼蘖數年心。", "雖然情斷沙吒後，爭奈平生怨恨深。"]'),
('yuding-2','憶崔生','紅綃妓','唐','御定全唐诗','yuding','','[]','深洞鶯啼恨阮郎，偷來花下解珠璫。',32,'御定全唐詩/json/800.json','["深洞鶯啼恨阮郎，偷來花下解珠璫。", "碧雲飄斷音書絕，空倚玉簫愁鳳凰。"]'),
('yuding-3','寄文茂','晁采','唐','御定全唐诗','yuding','','[]','花箋制葉寄郎邊，的的尋魚為妾傳。',32,'御定全唐詩/json/800.json','["花箋制葉寄郎邊，的的尋魚為妾傳。", "並蒂已看靈鵲報，倩郎早覓買花船。"]'),
('yuding-4','秋日再寄','晁采','唐','御定全唐诗','yuding','','[]','珍簟生涼夜漏餘，夢中恍惚覺來初。魂離不得空成病，',40,'御定全唐詩/json/800.json','["珍簟生涼夜漏餘，夢中恍惚覺來初。魂離不得空成病，", "此時最是思君處，腸斷寒猿定不如。"]'),
('yuding-5','春日送夫之長安','晁采','唐','御定全唐诗','yuding','','[]','思君遠別妾心愁，踏翠江邊送畫舟。',32,'御定全唐詩/json/800.json','["思君遠別妾心愁，踏翠江邊送畫舟。", "欲待相看遲此別，只憂紅日向西流。"]'),
('yuding-6','雨中憶夫','晁采','唐','御定全唐诗','yuding','','[]','窗前細雨日啾啾，妾在閨中獨自愁。',64,'御定全唐詩/json/800.json','["窗前細雨日啾啾，妾在閨中獨自愁。", "何事玉郎久離別，忘憂總對豈忘憂。", "春風送雨過窗東，忽憶良人在客中。", "安得妾身今似雨，也隨風去與郎同。"]'),
('yuding-7','子夜歌十八首','晁采','唐','御定全唐诗','yuding','','[]','儂既剪雲鬟，郎亦分絲發。覓向無人處，綰作同心結。',432,'御定全唐詩/json/800.json','["儂既剪雲鬟，郎亦分絲發。覓向無人處，綰作同心結。", "夜夜不成寐，擁被啼終夕。郎不信儂時，但看枕上跡。", "何時得成匹，離恨不復牽。金針刺菡萏，夜夜得見蓮。", "相逢逐涼候，黃花忽複香。顰眉臘月露，愁殺未成霜。", "明窗弄玉指，指甲如水晶。剪之特寄郎，聊當攜手行。", "寄語閨中娘，顏色不常好。含笑對棘實，歡娛須是棗。", "良會終有時，勸郎莫得怒。薑蘖畏春蠶，要綿須辛苦。", "醉夢幸逢郎，無奈烏啞啞。中山如有酒，敢借千金價。", "信使無虛日，玉醞寄盈觥。一年一日雨，底事太多晴。", "繡房擬會郎，四窗日離離。手自施屏障，恐有女伴窺。", "相思百餘日，相見苦無期。褰裳摘藕花，要蓮敢恨池。", "金盆盥素手，焚香誦普門。來生何所願，與郎為一身。", "花池多芳水，玉杯挹贈郎。避人藏袖裏，濕卻素羅裳。", "感郎金針贈，欲報物俱輕。一雙連素縷，與郎聊定情。", "寒風響枯木，通夕不得臥。早起遣問郎，昨宵何以過。", "得郎日嗣音，令人不可睹。熊膽磨作墨，書來字字苦。", "輕巾手自製，顏色爛含桃。先懷儂袖裏，然後約郎腰。", "儂贈綠絲衣，郎遺玉鉤子。即欲系儂心，儂思著郎體。"]'),
('yuding-8','答張生','崔鶯鶯','唐','御定全唐诗','yuding','','[]','待月西廂下，迎風戶半開。拂牆花影動，疑是玉人來。',24,'御定全唐詩/json/800.json','["待月西廂下，迎風戶半開。拂牆花影動，疑是玉人來。"]'),
('yuding-9','寄詩','崔鶯鶯','唐','御定全唐诗','yuding','','[]','自從銷瘦減容光，萬轉千回懶下床。',32,'御定全唐詩/json/800.json','["自從銷瘦減容光，萬轉千回懶下床。", "不為傍人羞不起，為郎憔悴卻羞郎。"]'),
('yuding-10','告絕詩','崔鶯鶯','唐','御定全唐诗','yuding','','[]','棄置今何道，當時且自親。還將舊來意，憐取眼前人。',24,'御定全唐詩/json/800.json','["棄置今何道，當時且自親。還將舊來意，憐取眼前人。"]'),
('yuding-11','答趙子','步非煙','唐','御定全唐诗','yuding','','[]','綠慘雙蛾不自持，只緣幽恨在新詩。',32,'御定全唐詩/json/800.json','["綠慘雙蛾不自持，只緣幽恨在新詩。", "郎心應似琴心怨，脈脈春情更泥誰。"]'),
('yuding-12','又答趙象獨坐','步非煙','唐','御定全唐诗','yuding','','[]','無力嚴妝倚繡櫳，暗題蟬錦思難窮。',32,'御定全唐詩/json/800.json','["無力嚴妝倚繡櫳，暗題蟬錦思難窮。", "近來贏得傷春病，柳弱花欹怯曉風。"]'),
('yuding-13','寄懷','步非煙','唐','御定全唐诗','yuding','','[]','畫簷春燕須同宿，蘭浦雙鴛肯獨飛。',32,'御定全唐詩/json/800.json','["畫簷春燕須同宿，蘭浦雙鴛肯獨飛。", "長恨桃源諸女伴，等閒花裏送郎歸。"]'),
('yuding-14','答趙象','步非煙','唐','御定全唐诗','yuding','','[]','相思只恨難相見，相見還愁卻別君。',32,'御定全唐詩/json/800.json','["相思只恨難相見，相見還愁卻別君。", "願得化為松上鶴，一雙飛去入行雲。"]'),
('yuding-15','臨行獻李尚書','崔紫雲','唐','御定全唐诗','yuding','','[]','從來學制斐然詩，不料霜台禦史知。',32,'御定全唐詩/json/800.json','["從來學制斐然詩，不料霜台禦史知。", "忽見便教隨命去，戀恩腸斷出門時。"]'),
('yuding-16','怨詩效徐淑體','姚月華','唐','御定全唐诗','yuding','','[]','妾生兮不辰，盛年兮逢屯。寒暑兮心結，夙夜兮眉顰。',216,'御定全唐詩/json/800.json','["妾生兮不辰，盛年兮逢屯。寒暑兮心結，夙夜兮眉顰。", "迴圈兮不息，如彼兮車輪。車輪兮可歇，妾心兮焉伸。", "雜遝兮無緒，如彼兮絲棼。絲棼兮可理，妾心兮焉分。", "空閨兮岑寂，妝閣兮生塵。萱草兮徒樹，茲憂兮豈泯。", "幸逢兮君子，許結兮殷勤。分香兮剪發，贈玉兮共珍。", "指天兮結誓，願為兮一身。所遭兮多舛，玉體兮難親。", "損餐兮減寢，帶緩兮羅裙。菱鑒兮慵啟，博爐兮焉熏。", "整襪兮欲舉，塞路兮荊榛。逢人兮欲語，鞈匝兮頑嚚。", "煩冤兮憑胸，何時兮可論。願君兮見察，妾死兮何瞋。"]'),
('yuding-17','制履贈楊達','姚月華','唐','御定全唐诗','yuding','','[]','金刀剪紫絨，與郎作輕履。願化雙仙鳧，飛來入閨裏。',24,'御定全唐詩/json/800.json','["金刀剪紫絨，與郎作輕履。願化雙仙鳧，飛來入閨裏。"]'),
('yuding-18','有期不至','姚月華','唐','御定全唐诗','yuding','','[]','銀燭清尊久延佇，出門入門天欲曙。',32,'御定全唐詩/json/800.json','["銀燭清尊久延佇，出門入門天欲曙。", "月落星稀竟不來，煙柳朧朣鵲飛去。"]'),
('yuding-19','怨詩寄楊達','姚月華','唐','御定全唐诗','yuding','','[]','春水悠悠春草綠，對此思君淚相續。',64,'御定全唐詩/json/800.json','["春水悠悠春草綠，對此思君淚相續。", "羞將離恨向東風，理盡秦箏不成曲。", "與君形影分吳越，玉枕經年對離別。", "登臺北望煙雨深，回身泣向寥天月。"]'),
('yuding-20','楚妃怨','姚月華','唐','御定全唐诗','yuding','','[]','梧桐葉下黃金井，橫架轆轤牽素綆。',32,'御定全唐詩/json/800.json','["梧桐葉下黃金井，橫架轆轤牽素綆。", "美人初起天未明，手拂銀瓶秋水冷。"]'),
('yuding-21','獨游家園','孟氏','唐','御定全唐诗','yuding','','[]','可惜春時節，依前獨自遊。無端兩行淚，長只對花流。',24,'御定全唐詩/json/800.json','["可惜春時節，依前獨自遊。無端兩行淚，長只對花流。"]'),
('yuding-22','答少年','孟氏','唐','御定全唐诗','yuding','','[]','誰家少年兒，心中暗自欺。不道終不可，可即恐郎知。',24,'御定全唐詩/json/800.json','["誰家少年兒，心中暗自欺。不道終不可，可即恐郎知。"]'),
('yuding-23','寄情','趙氏3','唐','御定全唐诗','yuding','','[]','春風白馬紫絲韁，正值蠶娘未采桑。五夜有心隨暮雨，',40,'御定全唐詩/json/800.json','["春風白馬紫絲韁，正值蠶娘未采桑。五夜有心隨暮雨，", "為報西遊減離恨，阮郎才去嫁劉郎。"]'),
('yuding-24','書紅綃帕','李節度姬','唐','御定全唐诗','yuding','','[]','囊裹真香誰見竊，鮫綃滴淚染成紅。',64,'御定全唐詩/json/800.json','["囊裹真香誰見竊，鮫綃滴淚染成紅。", "殷勤遺下輕綃意，好與情郎懷袖中。", "金珠富貴吾家事，常渴佳期乃寂寥。", "偶用志誠求雅合，良媒未必勝紅綃。"]'),
('yuding-25','會張生述懷','李節度姬','唐','御定全唐诗','yuding','','[]','門前畫戟尋常設，堂上犀簪取次看。',32,'御定全唐詩/json/800.json','["門前畫戟尋常設，堂上犀簪取次看。", "最是惱人情緒處，鳳凰樓上月華寒。"]'),
('yuding-26','別韋洵美詩','崔素娥','唐','御定全唐诗','yuding','','[]','妾閉閒房君路岐，妾心君恨兩依依。',32,'御定全唐詩/json/800.json','["妾閉閒房君路岐，妾心君恨兩依依。", "神魂倘遇巫娥伴，猶逐朝雲暮雨歸。"]'),
('yuding-27','送韋生酒','鮑家四弦','唐','御定全唐诗','yuding','','[]','白露濕庭砌，皓月臨前軒。此時去留恨，含思獨無言。',24,'御定全唐詩/json/800.json','["白露濕庭砌，皓月臨前軒。此時去留恨，含思獨無言。"]'),
('yuding-28','送鮑生酒','鮑家四弦','唐','御定全唐诗','yuding','','[]','風颭荷珠難暫圓，多情信有短姻緣。',32,'御定全唐詩/json/800.json','["風颭荷珠難暫圓，多情信有短姻緣。", "西樓今夜三更月，還照離人泣斷弦。"]'),
('yuding-29','贈別','嚴續姬','唐','御定全唐诗','yuding','','[]','風柳搖搖無定枝，陽臺雲雨夢中歸。',32,'御定全唐詩/json/800.json','["風柳搖搖無定枝，陽臺雲雨夢中歸。", "他年蓬島音塵絕，留取尊前舊舞衣。"]'),
('yuding-0','采桑','郎大家宋氏','唐','御定全唐诗','yuding','','[]','春來南雁歸，日去西蠶遠。妾思紛何極，客遊殊未返。',24,'御定全唐詩/json/801.json','["春來南雁歸，日去西蠶遠。妾思紛何極，客遊殊未返。"]'),
('yuding-1','宛轉歌二首','郎大家宋氏','唐','御定全唐诗','yuding','','[]','風已清，月朗琴複鳴。掩抑非千態，殷勤是一聲。',94,'御定全唐詩/json/801.json','["風已清，月朗琴複鳴。掩抑非千態，殷勤是一聲。", "歌宛轉，宛轉和且長。願為雙鴻鵠，比翼共翱翔。", "日已暮，長簷鳥聲度。此時望君君不來，此時思君君不顧。", "歌宛轉，宛轉那能異棲宿。願為形與影，出入恒相逐。"]'),
('yuding-2','長相思','郎大家宋氏','唐','御定全唐诗','yuding','','[]','長相思，久離別。關山阻，風煙絕。臺上鏡文銷，',22,'御定全唐詩/json/801.json','["長相思，久離別。關山阻，風煙絕。臺上鏡文銷，"]'),
('yuding-3','朝雲引','郎大家宋氏','唐','御定全唐诗','yuding','','[]','巴西巫峽指巴東，朝雲觸石上朝空。巫山巫峽高何已，',24,'御定全唐詩/json/801.json','["巴西巫峽指巴東，朝雲觸石上朝空。巫山巫峽高何已，"]'),
('yuding-4','宿巫山寄遠人','梁瓊','唐','御定全唐诗','yuding','','[]','巫山雲，巫山雨，朝雲暮雨無定所。南峰忽暗北峰晴，',64,'御定全唐詩/json/801.json','["巫山雲，巫山雨，朝雲暮雨無定所。南峰忽暗北峰晴，", "春風澹澹白雲閑，驚湍流水響千山。一夜此中對明月，", "曉看襟上淚流處，點點血痕猶在衣。"]'),
('yuding-5','昭君怨','梁瓊','唐','御定全唐诗','yuding','','[]','自古無和親，貽災到妾身。朔風嘶去馬，漢月出行輪。',48,'御定全唐詩/json/801.json','["自古無和親，貽災到妾身。朔風嘶去馬，漢月出行輪。", "衣薄狼山雪，妝成虜塞春。回看父母國，生死畢胡塵。"]'),
('yuding-6','銅雀台','梁瓊','唐','御定全唐诗','yuding','','[]','歌扇向陵開，齊行奠玉杯。舞時飛燕列，夢裏片雲來。',48,'御定全唐詩/json/801.json','["歌扇向陵開，齊行奠玉杯。舞時飛燕列，夢裏片雲來。", "月色空餘恨，松聲莫更哀。誰憐未死妾，掩袂下銅台。"]'),
('yuding-7','遠意','梁瓊','唐','御定全唐诗','yuding','','[]','脈脈長攄氣，微微不離心。叩頭從此去，煩惱阿誰禁。',24,'御定全唐詩/json/801.json','["脈脈長攄氣，微微不離心。叩頭從此去，煩惱阿誰禁。"]'),
('yuding-8','句','梁瓊','唐','御定全唐诗','yuding','','[]','玉枕空流別後淚，羅衣已盡去時香。',16,'御定全唐詩/json/801.json','["玉枕空流別後淚，羅衣已盡去時香。"]'),
('yuding-9','有所思','劉雲','唐','御定全唐诗','yuding','','[]','朝亦有所思，暮亦有所思。登樓望君處，藹藹蕭關道。',44,'御定全唐詩/json/801.json','["朝亦有所思，暮亦有所思。登樓望君處，藹藹蕭關道。", "掩淚向浮雲，誰知妾懷抱。玉井蒼苔春院深，"]'),
('yuding-10','婕妤怨','劉雲','唐','御定全唐诗','yuding','','[]','君恩不可見，妾豈如秋扇。秋扇尚有時，妾身永微賤。',40,'御定全唐詩/json/801.json','["君恩不可見，妾豈如秋扇。秋扇尚有時，妾身永微賤。", "莫言朝花不復落，嬌容幾奪昭陽殿。"]'),
('yuding-11','望月','劉雲','唐','御定全唐诗','yuding','','[]','天漢涼秋夜，澄澄一鏡明。山空猿屢嘯，林靜鵲頻驚。',24,'御定全唐詩/json/801.json','["天漢涼秋夜，澄澄一鏡明。山空猿屢嘯，林靜鵲頻驚。"]'),
('yuding-12','古意','崔萱','唐','御定全唐诗','yuding','','[]','灼灼葉中花，夏萎春又芳。明明天上月，蟾缺圓複光。',72,'御定全唐詩/json/801.json','["灼灼葉中花，夏萎春又芳。明明天上月，蟾缺圓複光。", "未如君子情，朝違夕已忘。玉帳枕猶暖，紈扇思何長。", "願因西南風，吹上玳瑁床。嬌眠錦衾裏，輾轉雙鴛鴦。"]'),
('yuding-13','敘別','崔萱','唐','御定全唐诗','yuding','','[]','碧池漾漾春水綠，中有佳禽暮棲宿。',32,'御定全唐詩/json/801.json','["碧池漾漾春水綠，中有佳禽暮棲宿。", "願持此意永相貽，只慮君情中反復。"]'),
('yuding-14','豪家子','崔萱','唐','御定全唐诗','yuding','','[]','年少家藏累代金，紅樓盡日醉沉沉。',32,'御定全唐詩/json/801.json','["年少家藏累代金，紅樓盡日醉沉沉。", "馬非躞蹀寧酬價，人不嬋娟肯動心。"]'),
('yuding-15','句','崔萱','唐','御定全唐诗','yuding','','[]','豈知一隻鳳釵價，沽得數村蝸舍人。',16,'御定全唐詩/json/801.json','["豈知一隻鳳釵價，沽得數村蝸舍人。"]'),
('yuding-16','贈所思','崔仲容','唐','御定全唐诗','yuding','','[]','所居幸接鄰，相見不相親。一似雲間月，何殊鏡裏人。',48,'御定全唐詩/json/801.json','["所居幸接鄰，相見不相親。一似雲間月，何殊鏡裏人。", "丹誠空有夢，腸斷不禁春。願作梁間燕，無由變此身。"]'),
('yuding-17','戲贈','崔仲容','唐','御定全唐诗','yuding','','[]','暫到昆侖未得歸，阮郎何事教人非。',32,'御定全唐詩/json/801.json','["暫到昆侖未得歸，阮郎何事教人非。", "如今身佩上清籙，莫遣落花沾羽衣。"]'),
('yuding-18','贈歌姬','崔仲容','唐','御定全唐诗','yuding','','[]','水剪雙眸霧剪衣，當筵一曲媚春輝。瀟湘夜瑟怨猶在，',40,'御定全唐詩/json/801.json','["水剪雙眸霧剪衣，當筵一曲媚春輝。瀟湘夜瑟怨猶在，", "渭城朝雨休重唱，滿眼陽關客未歸。"]'),
('yuding-19','句','崔仲容','唐','御定全唐诗','yuding','','[]','妾心合君心，一似影隨形。',52,'御定全唐詩/json/801.json','["妾心合君心，一似影隨形。", "梁燕無情困，雙棲語此時。", "不覺紅顏去，空嗟白髮生。", "桐花落盡春又盡，紫塞征人猶未歸。"]'),
('yuding-20','獨夜詞','崔公遠','唐','御定全唐诗','yuding','','[]','晴天霜落寒風急，錦帳羅幃羞更入。',32,'御定全唐詩/json/801.json','["晴天霜落寒風急，錦帳羅幃羞更入。", "秦箏不復續斷弦，回身掩淚挑燈立。"]'),
('yuding-21','句','崔公遠','唐','御定全唐诗','yuding','','[]','看花獨不語，裴回雙淚潸。',28,'御定全唐詩/json/801.json','["看花獨不語，裴回雙淚潸。", "君今遠戍在何處，遣妾秋來長望天。"]'),
('yuding-22','春詞二首','張琰','唐','御定全唐诗','yuding','','[]','垂柳鳴黃鸝，關關若求友。春情不可耐，愁殺閨中婦。',72,'御定全唐詩/json/801.json','["垂柳鳴黃鸝，關關若求友。春情不可耐，愁殺閨中婦。", "日暮登高樓，誰憐小垂手。", "昨日桃花飛，今朝梨花吐。春色能幾時，那堪此愁緒。", "蕩子遊不歸，春來淚如雨。"]'),
('yuding-23','銅雀台','張琰','唐','御定全唐诗','yuding','','[]','君王冥漠不可見，銅雀歌舞空裴回。西陵嘖嘖悲宿鳥，',24,'御定全唐詩/json/801.json','["君王冥漠不可見，銅雀歌舞空裴回。西陵嘖嘖悲宿鳥，"]'),
('yuding-24','句','張琰','唐','御定全唐诗','yuding','','[]','年年人自老，日日水東流。',24,'御定全唐詩/json/801.json','["年年人自老，日日水東流。", "庭芳自搖落，永念結中腸。"]'),
('yuding-25','哭夫二首','裴羽仙','唐','御定全唐诗','yuding','','[]','風卷平沙日欲曛，狼煙遙認犬羊群。',64,'御定全唐詩/json/801.json','["風卷平沙日欲曛，狼煙遙認犬羊群。", "李陵一戰無歸日，望斷胡天哭塞雲。", "良人平昔逐蕃渾，力戰輕行出塞門。", "從此不歸成萬古，空留賤妾怨黃昏。"]'),
('yuding-26','長門怨','劉媛','唐','御定全唐诗','yuding','','[]','雨滴梧桐秋夜長，愁心和雨到昭陽。',64,'御定全唐詩/json/801.json','["雨滴梧桐秋夜長，愁心和雨到昭陽。", "淚痕不學君恩斷，拭卻千行更萬行。", "學畫蛾眉獨出群，當時人道便承恩。", "經年不見君王面，花落黃昏空掩門。"]'),
('yuding-27','送遠','劉媛','唐','御定全唐诗','yuding','','[]','聞道瞿塘灩澦堆，青山流水近陽臺。',32,'御定全唐詩/json/801.json','["聞道瞿塘灩澦堆，青山流水近陽臺。", "知君此去無還日，妾亦隨波不復回。"]'),
('yuding-28','句','劉媛','唐','御定全唐诗','yuding','','[]','春風報梅柳，一夜發南枝。',28,'御定全唐詩/json/801.json','["春風報梅柳，一夜發南枝。", "傍人那得知心事，一面殘妝空淚痕。"]'),
('yuding-29','懷良人','葛鴉兒','唐','御定全唐诗','yuding','','[]','蓬鬢荊釵世所稀，布裙猶是嫁時衣。',32,'御定全唐詩/json/801.json','["蓬鬢荊釵世所稀，布裙猶是嫁時衣。", "胡麻好種無人種，正是歸時不見歸。"]'),
('yuding-30','會仙詩','葛鴉兒','唐','御定全唐诗','yuding','','[]','彩鳳搖搖下翠微，煙光漠漠遍芳枝。',64,'御定全唐詩/json/801.json','["彩鳳搖搖下翠微，煙光漠漠遍芳枝。", "玉窗仙會何人見，唯有春風仔細知。", "煙霞迤邐接蓬萊，宮殿參差曉日開。", "群玉山前人別處，紫鸞飛起望仙台。"]'),
('yuding-31','暗別離','劉瑤','唐','御定全唐诗','yuding','','[]','槐花結子桐葉焦，單飛越鳥啼青霄。翠軒輾雲輕遙遙，',48,'御定全唐詩/json/801.json','["槐花結子桐葉焦，單飛越鳥啼青霄。翠軒輾雲輕遙遙，", "朱弦暗斷不見人，風動花枝月中影。青鸞脈脈西飛去，"]'),
('yuding-32','古意曲','劉瑤','唐','御定全唐诗','yuding','','[]','梧桐階下月團團，洞房如水秋夜闌。吳刀剪破機頭錦，',24,'御定全唐詩/json/801.json','["梧桐階下月團團，洞房如水秋夜闌。吳刀剪破機頭錦，"]'),
('yuding-33','闔閭城懷古','劉瑤','唐','御定全唐诗','yuding','','[]','五湖春水接遙天，國破君亡不記年。',32,'御定全唐詩/json/801.json','["五湖春水接遙天，國破君亡不記年。", "唯有妖娥曾舞處，古台寂寞起愁煙。"]'),
('yuding-34','峽中即事','廉氏','唐','御定全唐诗','yuding','','[]','清秋三峽此中去，鳴鳥孤猿不可聞。一道水聲多亂石，',24,'御定全唐詩/json/801.json','["清秋三峽此中去，鳴鳥孤猿不可聞。一道水聲多亂石，"]'),
('yuding-35','懷遠','廉氏','唐','御定全唐诗','yuding','','[]','隙塵何微微，朝夕通其輝。人生各有托，君去獨不歸。',48,'御定全唐詩/json/801.json','["隙塵何微微，朝夕通其輝。人生各有托，君去獨不歸。", "青林有蟬響，赤日無鳥飛。裴回東南望，雙淚空沾衣。"]'),
('yuding-36','寄征人','廉氏','唐','御定全唐诗','yuding','','[]','淒淒北風吹鴛被，娟娟西月生蛾眉。',32,'御定全唐詩/json/801.json','["淒淒北風吹鴛被，娟娟西月生蛾眉。", "誰知獨夜相思處，淚滴寒塘蕙草時。"]'),
('yuding-37','寄遠','田娥','唐','御定全唐诗','yuding','','[]','憶昨會詩酒，終日相逢迎。今來成故事，歲月令人驚。',48,'御定全唐詩/json/801.json','["憶昨會詩酒，終日相逢迎。今來成故事，歲月令人驚。", "淚流紅粉薄，風度羅衣輕。難為子猷志，虛負文君名。"]'),
('yuding-38','攜手曲','田娥','唐','御定全唐诗','yuding','','[]','攜手共惜芳菲節，鶯啼錦花滿城闕。行樂逶迤念容色，',24,'御定全唐詩/json/801.json','["攜手共惜芳菲節，鶯啼錦花滿城闕。行樂逶迤念容色，"]'),
('yuding-39','長信宮','田娥','唐','御定全唐诗','yuding','','[]','團圓手中扇，昔為君所持。今日君棄捐，複值秋風時。',36,'御定全唐詩/json/801.json','["團圓手中扇，昔為君所持。今日君棄捐，複值秋風時。", "悲將入篋笥，自歎知何為。"]'),
('yuding-40','句','田娥','唐','御定全唐诗','yuding','','[]','春至偏無興，秋來只是眠。',12,'御定全唐詩/json/801.json','["春至偏無興，秋來只是眠。"]'),
('yuding-41','中秋夜泊武昌','劉淑柔','唐','御定全唐诗','yuding','','[]','兩城相對峙，一水向東流。今夜素娥月，何年黃鶴樓。',48,'御定全唐詩/json/801.json','["兩城相對峙，一水向東流。今夜素娥月，何年黃鶴樓。", "悠悠蘭棹晚，渺渺荻花秋。無奈柔腸斷，關山總是愁。"]'),
('yuding-42','賦荊門','薛瓊','唐','御定全唐诗','yuding','','[]','黃鳥翻紅樹，青牛臥綠苔。渚宮歌舞地，輕霧鎖樓臺。',24,'御定全唐詩/json/801.json','["黃鳥翻紅樹，青牛臥綠苔。渚宮歌舞地，輕霧鎖樓臺。"]'),
('yuding-43','戲贈','趙虛舟','唐','御定全唐诗','yuding','','[]','砌下梧桐葉正齊，花繁雨後壓枝低。',32,'御定全唐詩/json/801.json','["砌下梧桐葉正齊，花繁雨後壓枝低。", "報導不須鴉鳥亂，他家自有鳳凰棲。"]'),
('yuding-44','銅雀台','張瑛','唐','御定全唐诗','yuding','','[]','君王冥漠不可見，銅雀歌舞空裴回。西陵嘖嘖悲宿鳥，',24,'御定全唐詩/json/801.json','["君王冥漠不可見，銅雀歌舞空裴回。西陵嘖嘖悲宿鳥，"]'),
('yuding-45','望月','張瑛','唐','御定全唐诗','yuding','','[]','天漢涼秋夜，澄澄一鏡明。山空猿屢嘯，林靜鶴頻驚。',24,'御定全唐詩/json/801.json','["天漢涼秋夜，澄澄一鏡明。山空猿屢嘯，林靜鶴頻驚。"]'),
('yuding-46','答外','長孫佐轉妻','唐','御定全唐诗','yuding','','[]','征人去年戍邊水，夜得邊書字盈紙。揮刀就燭裁紅綺，',48,'御定全唐詩/json/801.json','["征人去年戍邊水，夜得邊書字盈紙。揮刀就燭裁紅綺，", "同心再解不心離，離字頻看字愁滅。結成一衣和淚封，"]'),
('yuding-47','早梅','劉元載妻','唐','御定全唐诗','yuding','','[]','南枝向暖北枝寒，一種春風有兩般。',32,'御定全唐詩/json/801.json','["南枝向暖北枝寒，一種春風有兩般。", "憑仗高樓莫吹笛，大家留取倚闌幹。"]'),
('yuding-48','明月堂','劉氏婦','唐','御定全唐诗','yuding','','[]','蟬鬢驚秋華髮新，可憐紅隙盡埃塵。',64,'御定全唐詩/json/801.json','["蟬鬢驚秋華髮新，可憐紅隙盡埃塵。", "西山一夢何年覺，明月堂前不見人。", "玉鉤風急響丁東，回首西山似夢中。", "明月堂前人不到，庭梧一夜老秋風。"]'),
('yuding-49','和潘雍','葛氏女','唐','御定全唐诗','yuding','','[]','九天天遠瑞煙濃，駕鶴驂鸞意已同。',32,'御定全唐詩/json/801.json','["九天天遠瑞煙濃，駕鶴驂鸞意已同。", "從此三山山上月，瓊花開處照春風。"]'),
('yuding-50','寄詩','李主簿姬','唐','御定全唐诗','yuding','','[]','去時盟約與心違，秋日離家春不歸。',32,'御定全唐詩/json/801.json','["去時盟約與心違，秋日離家春不歸。", "應是維揚風景好，恣情歡笑到芳菲。"]'),
('yuding-51','題興元明珠亭','京兆女子','唐','御定全唐诗','yuding','','[]','寂寥滿地落花紅，獨有離人萬恨中。',32,'御定全唐詩/json/801.json','["寂寥滿地落花紅，獨有離人萬恨中。", "回首池塘更無語，手彈珠淚與春風。"]'),
('yuding-52','題玉泉溪','湘驛女子','唐','御定全唐诗','yuding','','[]','紅葉醉秋色，碧溪彈夜弦。佳期不可再，風雨杳如年。',24,'御定全唐詩/json/801.json','["紅葉醉秋色，碧溪彈夜弦。佳期不可再，風雨杳如年。"]'),
('yuding-53','題三鄉詩','若耶溪女子','唐','御定全唐诗','yuding','','[]','昔逐良人西入關，良人身歿妾空還。',32,'御定全唐詩/json/801.json','["昔逐良人西入關，良人身歿妾空還。", "謝娘衛女不相待，為雨為雲歸此山。"]'),
('yuding-54','題沙鹿門','誰氏女','唐','御定全唐诗','yuding','','[]','昔逐良人去上京，良人身歿妾東征。',32,'御定全唐詩/json/801.json','["昔逐良人去上京，良人身歿妾東征。", "同來不得同歸去，永負朝雲暮雨情。"]'),
('yuding-55','聯句','不詳','唐','御定全唐诗','yuding','','[]','朱樓影直日當午，玉樹陰低月已三。——光',228,'御定全唐詩/json/801.json','["朱樓影直日當午，玉樹陰低月已三。——光", "膩粉暗銷銀鏤合，錯刀閑剪泥金衫。——威", "繡床怕引烏龍吠，錦字愁教青鳥銜。——裒", "百味煉來憐益母，千花開處鬥宜男。——光", "鴛鴦有伴誰能羨，鸚鵡無言我自慚。——威", "浪喜遊蜂飛撲撲，佯驚孤燕語喃喃。——裒", "偏憐愛數螆蛦掌，每憶光抽玳瑁簪。——光", "煙洞幾年悲尚在，星橋一夕帳空含。——威", "窗前時節羞虛擲，世上風流笑苦諳。——裒", "獨結香綃偷餉送，暗垂檀袖學通參。——光", "須知化石心難定，卻是為雲分易甘。——威", "看見風光零落盡，弦聲猶逐望江南。——裒"]'),
('yuding-56','聯句','越溪楊女','唐','御定全唐诗','yuding','','[]','珠簾半床月，青竹滿林風。——楊女',32,'御定全唐詩/json/801.json','["珠簾半床月，青竹滿林風。——楊女", "何事今宵景，無人解語同。——謝生"]'),
('yuding-57','春日','越溪楊女','唐','御定全唐诗','yuding','','[]','春盡花隨盡，其如自是花。——楊女',64,'御定全唐詩/json/801.json','["春盡花隨盡，其如自是花。——楊女", "從來說花意，不過此容華。——謝生", "明月易虧輪，好花難戀春。——楊女", "常將花月恨，並作可憐人。——謝生"]'),
('yuding-58','句','曹文姬','唐','御定全唐诗','yuding','','[]','鑿開天外長生地，煉出人間不死丹。',16,'御定全唐詩/json/801.json','["鑿開天外長生地，煉出人間不死丹。"]'),
('yuding-0','燕子樓三首','關盼盼','唐','御定全唐诗','yuding','','[]','樓上殘燈伴曉霜，獨眠人起合歡床。',96,'御定全唐詩/json/802.json','["樓上殘燈伴曉霜，獨眠人起合歡床。", "相思一夜情多少，地角天涯不是長。", "北邙松柏鎖愁煙，燕子樓中思悄然。", "自埋劍履歌塵散，紅袖香銷一十年。", "適看鴻雁岳陽回，又睹玄禽逼社來。", "瑤瑟玉簫無意緒，任從蛛網任從灰。"]'),
('yuding-1','和白公詩','關盼盼','唐','御定全唐诗','yuding','','[]','自守空樓斂恨眉，形同春後牡丹枝。',32,'御定全唐詩/json/802.json','["自守空樓斂恨眉，形同春後牡丹枝。", "舍人不會人深意，訝道泉台不去隨。"]'),
('yuding-2','句','關盼盼','唐','御定全唐诗','yuding','','[]','兒童不識沖天物，漫把青泥汙雪毫。',16,'御定全唐詩/json/802.json','["兒童不識沖天物，漫把青泥汙雪毫。"]'),
('yuding-3','囉嗊曲六首','劉采春','唐','御定全唐诗','yuding','','[]','不喜秦淮水，生憎江上船。載兒夫婿去，經歲又經年。',144,'御定全唐詩/json/802.json','["不喜秦淮水，生憎江上船。載兒夫婿去，經歲又經年。", "借問東園柳，枯來得幾年。自無枝葉分，莫恐太陽偏。", "莫作商人婦，金釵當卜錢。朝朝江口望，錯認幾人船。", "那年離別日，只道住桐廬。桐廬人不見，今得廣州書。", "昨日勝今日，今年老去年。黃河清有日，白發黑無緣。", "昨日北風寒，牽船浦里安。潮來打纜斷，搖櫓始知難。"]'),
('yuding-4','寄歐陽詹','太原妓','唐','御定全唐诗','yuding','','[]','自從別後減容光，半是思郎半恨郎。',32,'御定全唐詩/json/802.json','["自從別後減容光，半是思郎半恨郎。", "欲識舊來雲髻樣，為奴開取縷金箱。"]'),
('yuding-5','續韋蟾句','武昌妓','唐','御定全唐诗','yuding','','[]','悲莫悲兮生別離，登山臨水送將歸。',32,'御定全唐詩/json/802.json','["悲莫悲兮生別離，登山臨水送將歸。", "武昌無限新栽柳，不見楊花撲面飛。"]'),
('yuding-6','獻李觀察','舞柘枝女','唐','御定全唐诗','yuding','','[]','湘江舞罷忽成悲，便脫蠻靴出絳帷。',32,'御定全唐詩/json/802.json','["湘江舞罷忽成悲，便脫蠻靴出絳帷。", "誰是蔡邕琴酒客，魏公懷舊嫁文姬。"]'),
('yuding-7','贈盧夫人','常浩','唐','御定全唐诗','yuding','','[]','佳人惜顏色，恐逐芳菲歇。日暮出畫堂，下階拜新月。',48,'御定全唐詩/json/802.json','["佳人惜顏色，恐逐芳菲歇。日暮出畫堂，下階拜新月。", "拜月如有詞，傍人那得知。歸來投玉枕，始覺淚痕垂。"]'),
('yuding-8','寄遠','常浩','唐','御定全唐诗','yuding','','[]','年年二月時，十年期別期。春風不知信，軒蓋獨遲遲。',64,'御定全唐詩/json/802.json','["年年二月時，十年期別期。春風不知信，軒蓋獨遲遲。", "今日無端卷珠箔，始見庭花複零落。人心一往不復歸，", "卻念容華非昔好，畫眉猶自待君來。"]'),
('yuding-9','送武補闕','襄陽妓','唐','御定全唐诗','yuding','','[]','弄珠灘上欲銷魂，獨把離懷寄酒尊。',32,'御定全唐詩/json/802.json','["弄珠灘上欲銷魂，獨把離懷寄酒尊。", "無限煙花不留意，忍教芳草怨王孫。"]'),
('yuding-10','題孫棨詩後','王福娘','唐','御定全唐诗','yuding','','[]','苦把文章邀勸人，吟看好個語言新。',32,'御定全唐詩/json/802.json','["苦把文章邀勸人，吟看好個語言新。", "雖然不及相如賦，也直黃金一二斤。"]'),
('yuding-11','問棨詩','王福娘','唐','御定全唐诗','yuding','','[]','日日悲傷未有圖，懶將心事話凡夫。',32,'御定全唐詩/json/802.json','["日日悲傷未有圖，懶將心事話凡夫。", "非同覆水應收得，只問仙郎有意無。"]'),
('yuding-12','謝棨','王福娘','唐','御定全唐诗','yuding','','[]','久賦恩情欲托身，已將心事再三陳。',32,'御定全唐詩/json/802.json','["久賦恩情欲托身，已將心事再三陳。", "泥蓮既沒移栽分，今日分離莫恨人。"]'),
('yuding-13','答小子弟詩','楊萊兒','唐','御定全唐诗','yuding','','[]','黃口小兒口莫憑，逡巡看取第三名。',32,'御定全唐詩/json/802.json','["黃口小兒口莫憑，逡巡看取第三名。", "孝廉持水添瓶子，莫向街頭亂碗鳴。"]'),
('yuding-14','和趙光遠題壁','楊萊兒','唐','御定全唐诗','yuding','','[]','長者車塵每到門，長卿非慕卓王孫。定知羽翼難隨鳳，',40,'御定全唐詩/json/802.json','["長者車塵每到門，長卿非慕卓王孫。定知羽翼難隨鳳，", "多情多病年應促，早辦名香為返魂。"]'),
('yuding-15','貽鄭昌圖','楚兒','唐','御定全唐诗','yuding','','[]','應是前生有宿冤，不期今世惡因緣。蛾眉欲碎巨靈掌，',40,'御定全唐詩/json/802.json','["應是前生有宿冤，不期今世惡因緣。蛾眉欲碎巨靈掌，", "曲江昨日君相遇，當下遭他數十鞭。"]'),
('yuding-16','和李標','王蘇蘇','唐','御定全唐诗','yuding','','[]','怪得犬驚雞亂飛，羸童瘦馬老麻衣。',32,'御定全唐詩/json/802.json','["怪得犬驚雞亂飛，羸童瘦馬老麻衣。", "阿誰亂引閒人到，留住青蚨熱趕歸。"]'),
('yuding-17','臨終召客','顏令賓','唐','御定全唐诗','yuding','','[]','氣餘三五喘，花剩兩三枝。話別一尊酒，相邀無後期。',24,'御定全唐詩/json/802.json','["氣餘三五喘，花剩兩三枝。話別一尊酒，相邀無後期。"]'),
('yuding-18','寄故人','張窈窕','唐','御定全唐诗','yuding','','[]','淡淡春風花落時，不堪愁望更相思。',32,'御定全唐詩/json/802.json','["淡淡春風花落時，不堪愁望更相思。", "無金可買長門賦，有恨空吟團扇詩。"]'),
('yuding-19','上成都在事','張窈窕','唐','御定全唐诗','yuding','','[]','昨日賣衣裳，今日賣衣裳。衣裳渾賣盡，羞見嫁時箱。',48,'御定全唐詩/json/802.json','["昨日賣衣裳，今日賣衣裳。衣裳渾賣盡，羞見嫁時箱。", "有賣愁仍緩，無時心轉傷。故園有虜隔，何處事蠶桑。"]'),
('yuding-20','春思二首','張窈窕','唐','御定全唐诗','yuding','','[]','門前梅柳爛春輝，閉妾深閨繡舞衣。',64,'御定全唐詩/json/802.json','["門前梅柳爛春輝，閉妾深閨繡舞衣。", "雙燕不知腸欲斷，銜泥故故傍人飛。", "井上梧桐是妾移，夜來花發最高枝。", "若教不向深閨種，春過門前爭得知。"]'),
('yuding-21','西江行','張窈窕','唐','御定全唐诗','yuding','','[]','日下西塞山，南來洞庭客。晴空白鳥度，萬里秋光碧。',24,'御定全唐詩/json/802.json','["日下西塞山，南來洞庭客。晴空白鳥度，萬里秋光碧。"]'),
('yuding-22','贈所思','張窈窕','唐','御定全唐诗','yuding','','[]','與君咫尺長離別，遣妾容華為誰說。',32,'御定全唐詩/json/802.json','["與君咫尺長離別，遣妾容華為誰說。", "夕望層城眼欲穿，曉臨明鏡腸堪絕。"]'),
('yuding-23','句','張窈窕','唐','御定全唐诗','yuding','','[]','滿院花飛人不到，含情欲語燕雙雙。（《春情》，',22,'御定全唐詩/json/802.json','["滿院花飛人不到，含情欲語燕雙雙。（《春情》，"]'),
('yuding-24','贈裴思謙','平康妓','唐','御定全唐诗','yuding','','[]','銀釭斜背解明璫，小語偷聲賀玉郎。',32,'御定全唐詩/json/802.json','["銀釭斜背解明璫，小語偷聲賀玉郎。", "從此不知蘭麝貴，夜來新惹桂枝香。"]'),
('yuding-25','迷香洞','史鳳','唐','御定全唐诗','yuding','','[]','洞口飛瓊佩羽霓，香風飄拂使人迷。',32,'御定全唐詩/json/802.json','["洞口飛瓊佩羽霓，香風飄拂使人迷。", "自從邂逅芙蓉帳，不數桃花流水溪。"]'),
('yuding-26','神雞枕','史鳳','唐','御定全唐诗','yuding','','[]','枕繪鴛鴦久與棲，新裁霧縠鬥神雞。',32,'御定全唐詩/json/802.json','["枕繪鴛鴦久與棲，新裁霧縠鬥神雞。", "與郎酣夢渾忘曉，雞亦留連不肯啼。"]'),
('yuding-27','鎖蓮燈','史鳳','唐','御定全唐诗','yuding','','[]','燈鎖蓮花花照罍，翠鈿同醉楚台巍。',32,'御定全唐詩/json/802.json','["燈鎖蓮花花照罍，翠鈿同醉楚台巍。", "殘灰剔罷攜纖手，也勝金蓮送轍回。"]'),
('yuding-28','鮫紅被','史鳳','唐','御定全唐诗','yuding','','[]','肱被當年僅禦寒，青樓慣染血猩紈。',32,'御定全唐詩/json/802.json','["肱被當年僅禦寒，青樓慣染血猩紈。", "牙床舒卷鵷鸞共，正值窗櫺月一團。"]'),
('yuding-29','傳香枕','史鳳','唐','御定全唐诗','yuding','','[]','韓壽香從何處傳，枕邊芳馥戀嬋娟。',32,'御定全唐詩/json/802.json','["韓壽香從何處傳，枕邊芳馥戀嬋娟。", "休疑粉黛加鋌刃，玉女旃檀侍佛前。"]'),
('yuding-30','八分羊','史鳳','唐','御定全唐诗','yuding','','[]','黨家風味足肥羊，綺閣留人漫較量。',32,'御定全唐詩/json/802.json','["黨家風味足肥羊，綺閣留人漫較量。", "萬羊亦是男兒事，莫學狂夫取次嘗。"]'),
('yuding-31','閉門羹','史鳳','唐','御定全唐诗','yuding','','[]','一豆聊供游冶郎，去時忙喚鎖倉琅。',32,'御定全唐詩/json/802.json','["一豆聊供游冶郎，去時忙喚鎖倉琅。", "入門獨慕相如侶，欲撥瑤琴彈鳳凰。"]'),
('yuding-32','突厥三台','盛小叢','唐','御定全唐诗','yuding','','[]','雁門山上雁初飛，馬邑闌中馬正肥。',32,'御定全唐詩/json/802.json','["雁門山上雁初飛，馬邑闌中馬正肥。", "日旰山西逢驛使，殷勤南北送征衣。"]'),
('yuding-33','雲鬟','趙鸞鸞','唐','御定全唐诗','yuding','','[]','擾擾香雲濕未幹，鴉領蟬翼膩光寒。',32,'御定全唐詩/json/802.json','["擾擾香雲濕未幹，鴉領蟬翼膩光寒。", "側邊斜插黃金鳳，妝罷夫君帶笑看。"]'),
('yuding-34','柳眉','趙鸞鸞','唐','御定全唐诗','yuding','','[]','彎彎柳葉愁邊戲，湛湛菱花照處頻。',32,'御定全唐詩/json/802.json','["彎彎柳葉愁邊戲，湛湛菱花照處頻。", "嫵媚不煩螺子黛，春山畫出自精神。"]'),
('yuding-35','檀口','趙鸞鸞','唐','御定全唐诗','yuding','','[]','銜杯微動櫻桃顆，咳唾輕飄茉莉香。',32,'御定全唐詩/json/802.json','["銜杯微動櫻桃顆，咳唾輕飄茉莉香。", "曾見白家樊素口，瓠犀顆顆綴榴芳。"]'),
('yuding-36','纖指','趙鸞鸞','唐','御定全唐诗','yuding','','[]','纖纖軟玉削春蔥，長在香羅翠袖中。',32,'御定全唐詩/json/802.json','["纖纖軟玉削春蔥，長在香羅翠袖中。", "昨日琵琶弦索上，分明滿甲染猩紅。"]'),
('yuding-37','酥乳','趙鸞鸞','唐','御定全唐诗','yuding','','[]','粉香汗濕瑤琴軫，春逗酥融綿雨膏。',32,'御定全唐詩/json/802.json','["粉香汗濕瑤琴軫，春逗酥融綿雨膏。", "浴罷檀郎捫弄處，靈華涼沁紫葡萄。"]'),
('yuding-38','獻陳陶處士','蓮花妓','唐','御定全唐诗','yuding','','[]','蓮花為號玉為腮，珍重尚書遣妾來。',32,'御定全唐詩/json/802.json','["蓮花為號玉為腮，珍重尚書遣妾來。", "處士不生巫峽夢，虛勞神女下陽臺。"]'),
('yuding-39','敘懷','徐月英','唐','御定全唐诗','yuding','','[]','為失三從泣淚頻，此身何用處人倫。',32,'御定全唐詩/json/802.json','["為失三從泣淚頻，此身何用處人倫。", "雖然日逐笙歌樂，長羨荊釵與布裙。"]'),
('yuding-40','送人','徐月英','唐','御定全唐诗','yuding','','[]','惆悵人間萬事違，兩人同去一人歸。',32,'御定全唐詩/json/802.json','["惆悵人間萬事違，兩人同去一人歸。", "生憎平望亭前水，忍照鴛鴦相背飛。"]'),
('yuding-41','句','徐月英','唐','御定全唐诗','yuding','','[]','枕前淚與階前雨，隔個窗兒滴到明。',16,'御定全唐詩/json/802.json','["枕前淚與階前雨，隔個窗兒滴到明。"]'),
('yuding-42','句','韓襄客','唐','御定全唐诗','yuding','','[]','連理枝前同設誓，丁香樹下共論心。',16,'御定全唐詩/json/802.json','["連理枝前同設誓，丁香樹下共論心。"]'),
('yuding-0','酬人雨後玩竹','薛濤','唐','御定全唐诗','yuding','','[]','南天春雨時，那鑒雪霜姿。眾類亦雲茂，虛心能自持。',48,'御定全唐詩/json/803.json','["南天春雨時，那鑒雪霜姿。眾類亦雲茂，虛心能自持。", "多留晉賢醉，早伴舜妃悲。晚歲君能賞，蒼蒼勁節奇。"]'),
('yuding-1','春望詞四首','薛濤','唐','御定全唐诗','yuding','','[]','花開不同賞，花落不同悲。欲問相思處，花開花落時。',96,'御定全唐詩/json/803.json','["花開不同賞，花落不同悲。欲問相思處，花開花落時。", "攬草結同心，將以遺知音。春愁正斷絕，春鳥複哀吟。", "風花日將老，佳期猶渺渺。不結同心人，空結同心草。", "那堪花滿枝，翻作兩相思。玉箸垂朝鏡，春風知不知。"]'),
('yuding-2','宣上人見示與諸公唱和','薛濤','唐','御定全唐诗','yuding','','[]','許廁高齋唱，涓泉定不如。可憐譙記室，流水滿禪居。',24,'御定全唐詩/json/803.json','["許廁高齋唱，涓泉定不如。可憐譙記室，流水滿禪居。"]'),
('yuding-3','風','薛濤','唐','御定全唐诗','yuding','','[]','獵蕙微風遠，飄弦唳一聲。林梢鳴淅瀝，松徑夜淒清。',24,'御定全唐詩/json/803.json','["獵蕙微風遠，飄弦唳一聲。林梢鳴淅瀝，松徑夜淒清。"]'),
('yuding-4','月','薛濤','唐','御定全唐诗','yuding','','[]','魄依鉤樣小，扇逐漢機團。細影將圓質，人間幾處看。',24,'御定全唐詩/json/803.json','["魄依鉤樣小，扇逐漢機團。細影將圓質，人間幾處看。"]'),
('yuding-5','蟬','薛濤','唐','御定全唐诗','yuding','','[]','露滌清音遠，風吹數葉齊。聲聲似相接，各在一枝棲。',24,'御定全唐詩/json/803.json','["露滌清音遠，風吹數葉齊。聲聲似相接，各在一枝棲。"]'),
('yuding-6','池上雙鳥','薛濤','唐','御定全唐诗','yuding','','[]','雙棲綠池上，朝暮共飛還。更憶將雛日，同心蓮葉間。',24,'御定全唐詩/json/803.json','["雙棲綠池上，朝暮共飛還。更憶將雛日，同心蓮葉間。"]'),
('yuding-7','鴛鴦草','薛濤','唐','御定全唐诗','yuding','','[]','綠英滿香砌，兩兩鴛鴦小。但娛春日長，不管秋風早。',24,'御定全唐詩/json/803.json','["綠英滿香砌，兩兩鴛鴦小。但娛春日長，不管秋風早。"]'),
('yuding-8','罰赴邊有懷上韋令公二首','薛濤','唐','御定全唐诗','yuding','','[]','聞道邊城苦，今來到始知。羞將門下曲，唱與隴頭兒。',48,'御定全唐詩/json/803.json','["聞道邊城苦，今來到始知。羞將門下曲，唱與隴頭兒。", "黠虜猶違命，烽煙直北愁。卻教嚴譴妾，不敢向松州。"]'),
('yuding-9','詠八十一顆','薛濤','唐','御定全唐诗','yuding','','[]','色比丹霞朝日，形如合浦筼簹。',28,'御定全唐詩/json/803.json','["色比丹霞朝日，形如合浦筼簹。", "開時九九如數，見處雙雙頡頏。"]'),
('yuding-10','謁巫山廟','薛濤','唐','御定全唐诗','yuding','','[]','亂猿啼處訪高唐，路入煙霞草木香。山色未能忘宋玉，',40,'御定全唐詩/json/803.json','["亂猿啼處訪高唐，路入煙霞草木香。山色未能忘宋玉，", "惆悵廟前多少柳，春來空鬥畫眉長。"]'),
('yuding-11','牡丹','薛濤','唐','御定全唐诗','yuding','','[]','去春零落暮春時，淚濕紅箋怨別離。常恐便同巫峽散，',40,'御定全唐詩/json/803.json','["去春零落暮春時，淚濕紅箋怨別離。常恐便同巫峽散，", "只欲欄邊安枕席，夜深閑共說相思。"]'),
('yuding-12','賊平後上高相公','薛濤','唐','御定全唐诗','yuding','','[]','驚看天地白荒荒，瞥見青山舊夕陽。',32,'御定全唐詩/json/803.json','["驚看天地白荒荒，瞥見青山舊夕陽。", "始信大威能照映，由來日月借生光。"]'),
('yuding-13','送友人','薛濤','唐','御定全唐诗','yuding','','[]','水國蒹葭夜有霜，月寒山色共蒼蒼。',32,'御定全唐詩/json/803.json','["水國蒹葭夜有霜，月寒山色共蒼蒼。", "誰言千里自今夕，離夢杳如關塞長。"]'),
('yuding-14','聽僧吹蘆管','薛濤','唐','御定全唐诗','yuding','','[]','曉蟬嗚咽暮鶯愁，言語殷勤十指頭。',32,'御定全唐詩/json/803.json','["曉蟬嗚咽暮鶯愁，言語殷勤十指頭。", "罷閱梵書聊一弄，散隨金磬泥清秋。"]'),
('yuding-15','酬郭簡州寄柑子','薛濤','唐','御定全唐诗','yuding','','[]','霜規不讓黃金色，圓質仍含禦史香。',32,'御定全唐詩/json/803.json','["霜規不讓黃金色，圓質仍含禦史香。", "何處同聲情最異，臨川太守謝家郎。"]'),
('yuding-16','上川主武元衡相國二首','薛濤','唐','御定全唐诗','yuding','','[]','落日重城夕霧收，玳筵雕俎薦諸侯。',64,'御定全唐詩/json/803.json','["落日重城夕霧收，玳筵雕俎薦諸侯。", "因令朗月當庭燎，不使珠簾下玉鉤。", "東閣移尊綺席陳，貂簪龍節更宜春。", "軍城畫角三聲歇，雲幕初垂紅燭新。"]'),
('yuding-17','憶荔枝','薛濤','唐','御定全唐诗','yuding','','[]','傳聞象郡隔南荒，絳實豐肌不可忘。',32,'御定全唐詩/json/803.json','["傳聞象郡隔南荒，絳實豐肌不可忘。", "近有青衣連楚水，素漿還得類瓊漿。"]'),
('yuding-18','斛石山曉望寄呂侍禦','薛濤','唐','御定全唐诗','yuding','','[]','曦輪初轉照仙扃，旋擘煙嵐上窅冥。',32,'御定全唐詩/json/803.json','["曦輪初轉照仙扃，旋擘煙嵐上窅冥。", "不得玄暉同指點，天涯蒼翠漫青青。"]'),
('yuding-19','寄詞','薛濤','唐','御定全唐诗','yuding','','[]','菌閣芝樓杳靄中，霞開深見玉皇宮。',32,'御定全唐詩/json/803.json','["菌閣芝樓杳靄中，霞開深見玉皇宮。", "紫陽天上神仙客，稱在人間立世功。"]'),
('yuding-20','斛石山書事','薛濤','唐','御定全唐诗','yuding','','[]','王家山水畫圖中，意思都盧粉墨容。',32,'御定全唐詩/json/803.json','["王家山水畫圖中，意思都盧粉墨容。", "今日忽登虛境望，步搖冠翠一千峰。"]'),
('yuding-21','送姚員外','薛濤','唐','御定全唐诗','yuding','','[]','萬條江柳早秋枝，嫋地翻風色未衰。',32,'御定全唐詩/json/803.json','["萬條江柳早秋枝，嫋地翻風色未衰。", "欲折爾來將贈別，莫教煙月兩鄉悲。"]'),
('yuding-22','酬祝十三秀才','薛濤','唐','御定全唐诗','yuding','','[]','浩思藍山玉彩寒，冰囊敲碎楚金盤。',32,'御定全唐詩/json/803.json','["浩思藍山玉彩寒，冰囊敲碎楚金盤。", "詩家利器馳聲久，何用春闈榜下看。"]'),
('yuding-23','別李郎中','薛濤','唐','御定全唐诗','yuding','','[]','花落梧桐鳳別凰，想登秦嶺更淒涼。',32,'御定全唐詩/json/803.json','["花落梧桐鳳別凰，想登秦嶺更淒涼。", "安仁縱有詩將賦，一半音詞雜悼亡。"]'),
('yuding-24','送扶煉師','薛濤','唐','御定全唐诗','yuding','','[]','錦浦歸舟巫峽雲，綠波迢遞雨紛紛。',32,'御定全唐詩/json/803.json','["錦浦歸舟巫峽雲，綠波迢遞雨紛紛。", "山陰妙術人傳久，也說將鵝與右軍。"]'),
('yuding-25','摩訶池贈蕭中丞','薛濤','唐','御定全唐诗','yuding','','[]','昔以多能佐碧油，今朝同泛舊仙舟。',32,'御定全唐詩/json/803.json','["昔以多能佐碧油，今朝同泛舊仙舟。", "淒涼逝水頹波遠，惟有碑泉咽不流。"]'),
('yuding-26','鄉思','薛濤','唐','御定全唐诗','yuding','','[]','峨嵋山下水如油，憐我心同不系舟。',32,'御定全唐詩/json/803.json','["峨嵋山下水如油，憐我心同不系舟。", "何日片帆離錦浦，棹聲齊唱發中流。"]'),
('yuding-27','和李書記席上見贈','薛濤','唐','御定全唐诗','yuding','','[]','翩翩射策東堂秀，豈複相逢豁寸心。',32,'御定全唐詩/json/803.json','["翩翩射策東堂秀，豈複相逢豁寸心。", "借問風光為誰麗，萬條絲柳翠煙深。"]'),
('yuding-28','棠梨花和李太尉','薛濤','唐','御定全唐诗','yuding','','[]','吳均蕙圃移嘉木，正及東溪春雨時。',32,'御定全唐詩/json/803.json','["吳均蕙圃移嘉木，正及東溪春雨時。", "日晚鶯啼何所為，淺深紅膩壓繁枝。"]'),
('yuding-29','酬文使君','薛濤','唐','御定全唐诗','yuding','','[]','延英曉拜漢恩新，五馬騰驤九陌塵。',32,'御定全唐詩/json/803.json','["延英曉拜漢恩新，五馬騰驤九陌塵。", "今日謝庭飛白雪，巴歌不復舊陽春。"]'),
('yuding-30','酬吳隨君','薛濤','唐','御定全唐诗','yuding','','[]','支公別墅接花扃，買得前山總未經。',32,'御定全唐詩/json/803.json','["支公別墅接花扃，買得前山總未經。", "入戶剡溪雲水滿，高齋咫尺躡青冥。"]'),
('yuding-31','酬李校書','薛濤','唐','御定全唐诗','yuding','','[]','才遊象外身雖遠，學茂區中事易聞。',32,'御定全唐詩/json/803.json','["才遊象外身雖遠，學茂區中事易聞。", "自顧漳濱多病後，空瞻逸翮舞青雲。"]'),
('yuding-32','賦淩雲寺二首','薛濤','唐','御定全唐诗','yuding','','[]','聞說淩雲寺裏苔，風高日近絕纖埃。',64,'御定全唐詩/json/803.json','["聞說淩雲寺裏苔，風高日近絕纖埃。", "橫雲點染芙蓉壁，似待詩人寶月來。", "聞說淩雲寺裏花，飛空繞磴逐江斜。", "有時鎖得嫦娥鏡，鏤出瑤台五色霞。"]'),
('yuding-33','九日遇雨二首','薛濤','唐','御定全唐诗','yuding','','[]','萬里驚飆朔氣深，江城蕭索晝陰陰。',64,'御定全唐詩/json/803.json','["萬里驚飆朔氣深，江城蕭索晝陰陰。", "誰憐不得登山去，可惜寒芳色似金。", "茱萸秋節佳期阻，金菊寒花滿院香。", "神女欲來知有意，先令雲雨暗池塘。"]'),
('yuding-34','酬雍秀才貽巴峽圖','薛濤','唐','御定全唐诗','yuding','','[]','千疊雲峰萬頃湖，白波分去繞荊吳。',32,'御定全唐詩/json/803.json','["千疊雲峰萬頃湖，白波分去繞荊吳。", "感君識我枕流意，重示瞿塘峽口圖。"]'),
('yuding-35','上王尚書','薛濤','唐','御定全唐诗','yuding','','[]','碧玉雙幢白玉郎，初辭天帝下扶桑。',32,'御定全唐詩/json/803.json','["碧玉雙幢白玉郎，初辭天帝下扶桑。", "手持雲篆題新榜，十萬人家春日長。"]'),
('yuding-36','和劉賓客玉蕣','薛濤','唐','御定全唐诗','yuding','','[]','瓊枝的皪露珊珊，欲折如披玉彩寒。',32,'御定全唐詩/json/803.json','["瓊枝的皪露珊珊，欲折如披玉彩寒。", "閑拂朱房何所似，緣山偏映月輪殘。"]'),
('yuding-37','江邊','薛濤','唐','御定全唐诗','yuding','','[]','西風忽報雁雙雙，人世心形兩自降。',32,'御定全唐詩/json/803.json','["西風忽報雁雙雙，人世心形兩自降。", "不為魚腸有真訣，誰能夢夢立清江。"]'),
('yuding-38','送盧員外','薛濤','唐','御定全唐诗','yuding','','[]','玉壘山前風雪夜，錦官城外別離魂。',32,'御定全唐詩/json/803.json','["玉壘山前風雪夜，錦官城外別離魂。", "信陵公子如相問，長向夷門感舊恩。"]'),
('yuding-39','題竹郎廟','薛濤','唐','御定全唐诗','yuding','','[]','竹郎廟前多古木，夕陽沉沉山更綠。',32,'御定全唐詩/json/803.json','["竹郎廟前多古木，夕陽沉沉山更綠。", "何處江村有笛聲，聲聲儘是迎郎曲。"]'),
('yuding-40','贈蘇十三中丞','薛濤','唐','御定全唐诗','yuding','','[]','洛陽陌上埋輪氣，欲逐秋空擊隼飛。',32,'御定全唐詩/json/803.json','["洛陽陌上埋輪氣，欲逐秋空擊隼飛。", "今日芝泥檢征詔，別須台外振霜威。"]'),
('yuding-41','和郭員外題萬里橋','薛濤','唐','御定全唐诗','yuding','','[]','萬里橋頭獨越吟，知憑文字寫愁心。',32,'御定全唐詩/json/803.json','["萬里橋頭獨越吟，知憑文字寫愁心。", "細侯風韻兼前事，不止為舟也作霖。"]'),
('yuding-42','送鄭眉州','薛濤','唐','御定全唐诗','yuding','','[]','雨暗眉山江水流，離人掩袂立高樓。',32,'御定全唐詩/json/803.json','["雨暗眉山江水流，離人掩袂立高樓。", "雙旌千騎駢東陌，獨有羅敷望上頭。"]'),
('yuding-43','江亭餞別','薛濤','唐','御定全唐诗','yuding','','[]','綠沼紅泥物象幽，范汪兼倅李並州。',32,'御定全唐詩/json/803.json','["綠沼紅泥物象幽，范汪兼倅李並州。", "離亭急管四更後，不見公車心獨愁。"]'),
('yuding-44','海棠溪','薛濤','唐','御定全唐诗','yuding','','[]','春教風景駐仙霞，水面魚身總帶花。',32,'御定全唐詩/json/803.json','["春教風景駐仙霞，水面魚身總帶花。", "人世不思靈卉異，競將紅纈染輕沙。"]'),
('yuding-45','採蓮舟','薛濤','唐','御定全唐诗','yuding','','[]','風前一葉壓荷蕖，解報新秋又得魚。',32,'御定全唐詩/json/803.json','["風前一葉壓荷蕖，解報新秋又得魚。", "兔走烏馳人語靜，滿溪紅袂棹歌初。"]'),
('yuding-46','菱荇沼','薛濤','唐','御定全唐诗','yuding','','[]','水荇斜牽綠藻浮，柳絲和葉臥清流。',32,'御定全唐詩/json/803.json','["水荇斜牽綠藻浮，柳絲和葉臥清流。", "何時得向溪頭賞，旋摘菱花旋泛舟。"]'),
('yuding-47','金燈花','薛濤','唐','御定全唐诗','yuding','','[]','闌邊不見蘘蘘葉，砌下惟翻豔豔叢。',32,'御定全唐詩/json/803.json','["闌邊不見蘘蘘葉，砌下惟翻豔豔叢。", "細視欲將何物比，曉霞初疊赤城宮。"]'),
('yuding-48','春郊遊眺寄孫處士二首','薛濤','唐','御定全唐诗','yuding','','[]','低頭久立向薔薇，愛似零陵香惹衣。',64,'御定全唐詩/json/803.json','["低頭久立向薔薇，愛似零陵香惹衣。", "何事碧溪孫處士，百勞東去燕西飛。", "今朝縱目玩芳菲，夾纈籠裙繡地衣。", "滿袖滿頭兼手把，教人識是看花歸。"]'),
('yuding-49','酬楊供奉法師見招','薛濤','唐','御定全唐诗','yuding','','[]','遠水長流潔複清，雪窗高臥與雲平。',32,'御定全唐詩/json/803.json','["遠水長流潔複清，雪窗高臥與雲平。", "不嫌袁室無煙火，惟笑商山有姓名。"]'),
('yuding-50','試新服裁制初成三首','薛濤','唐','御定全唐诗','yuding','','[]','紫陽宮裏賜紅綃，仙霧朦朧隔海遙。',96,'御定全唐詩/json/803.json','["紫陽宮裏賜紅綃，仙霧朦朧隔海遙。", "霜兔毳寒冰繭淨，嫦娥笑指織星橋。", "九氣分為九色霞，五靈仙馭五雲車。", "春風因過東君舍，偷樣人間染百花。", "長裾本是上清儀，曾逐群仙把玉芝。", "每到宮中歌舞會，折腰齊唱步虛詞。"]'),
('yuding-51','寄張元夫','薛濤','唐','御定全唐诗','yuding','','[]','前溪獨立後溪行，鷺識朱衣自不驚。',32,'御定全唐詩/json/803.json','["前溪獨立後溪行，鷺識朱衣自不驚。", "借問人間愁寂意，伯牙弦絕已無聲。"]'),
('yuding-52','酬辛員外折花見遺','薛濤','唐','御定全唐诗','yuding','','[]','青鳥東飛正落梅，銜花滿口下瑤台。',32,'御定全唐詩/json/803.json','["青鳥東飛正落梅，銜花滿口下瑤台。", "一枝為授殷勤意，把向風前旋旋開。"]'),
('yuding-53','贈遠二首','薛濤','唐','御定全唐诗','yuding','','[]','芙蓉新落蜀山秋，錦字開緘到是愁。',64,'御定全唐詩/json/803.json','["芙蓉新落蜀山秋，錦字開緘到是愁。", "閨閣不知戎馬事，月高還上望夫樓。", "擾弱新蒲葉又齊，春深花落塞前溪。", "知君未轉秦關騎，月照千門掩袖啼。"]'),
('yuding-54','秋泉','薛濤','唐','御定全唐诗','yuding','','[]','冷色初澄一帶煙，幽聲遙瀉十絲弦。',32,'御定全唐詩/json/803.json','["冷色初澄一帶煙，幽聲遙瀉十絲弦。", "長來枕上牽情思，不使愁人半夜眠。"]'),
('yuding-55','柳絮','薛濤','唐','御定全唐诗','yuding','','[]','二月楊花輕複微，春風搖盪惹人衣。',32,'御定全唐詩/json/803.json','["二月楊花輕複微，春風搖盪惹人衣。", "他家本是無情物，一任南飛又北飛。"]'),
('yuding-56','續嘉陵驛詩獻武相國','薛濤','唐','御定全唐诗','yuding','','[]','蜀門西更上青天，強為公歌蜀國弦。',32,'御定全唐詩/json/803.json','["蜀門西更上青天，強為公歌蜀國弦。", "卓氏長卿稱士女，錦江玉壘獻山川。"]'),
('yuding-57','段相國游武擔寺，病不能從題寄','薛濤','唐','御定全唐诗','yuding','','[]','消瘦翻堪見令公，落花無那恨東風。',32,'御定全唐詩/json/803.json','["消瘦翻堪見令公，落花無那恨東風。", "儂心猶道青春在，羞看飛蓬石鏡中。"]'),
('yuding-58','贈段校書','薛濤','唐','御定全唐诗','yuding','','[]','公子翩翩說校書，玉弓金勒紫綃裾。',32,'御定全唐詩/json/803.json','["公子翩翩說校書，玉弓金勒紫綃裾。", "玄成莫便驕名譽，文采風流定不如。"]'),
('yuding-59','十離詩：犬離主','薛濤','唐','御定全唐诗','yuding','','[]','馴擾朱門四五年，毛香足淨主人憐。',32,'御定全唐詩/json/803.json','["馴擾朱門四五年，毛香足淨主人憐。", "無端咬著親情客，不得紅絲毯上眠。"]'),
('yuding-60','十離詩：筆離手','薛濤','唐','御定全唐诗','yuding','','[]','越管宣毫始稱情，紅箋紙上撒花瓊。',32,'御定全唐詩/json/803.json','["越管宣毫始稱情，紅箋紙上撒花瓊。", "都緣用久鋒頭盡，不得羲之手裏擎。"]'),
('yuding-61','十離詩：馬離廄','薛濤','唐','御定全唐诗','yuding','','[]','雪耳紅毛淺碧蹄，追風曾到日東西。',32,'御定全唐詩/json/803.json','["雪耳紅毛淺碧蹄，追風曾到日東西。", "為驚玉貌郎君墜，不得華軒更一嘶。"]'),
('yuding-62','十離詩：鸚鵡離籠','薛濤','唐','御定全唐诗','yuding','','[]','隴西獨自一孤身，飛去飛來上錦茵。',32,'御定全唐詩/json/803.json','["隴西獨自一孤身，飛去飛來上錦茵。", "都緣出語無方便，不得籠中再喚人。"]'),
('yuding-63','十離詩：燕離巢','薛濤','唐','御定全唐诗','yuding','','[]','出入朱門未忍拋，主人常愛語交交。',32,'御定全唐詩/json/803.json','["出入朱門未忍拋，主人常愛語交交。", "銜泥穢汙珊瑚枕，不得梁間更壘巢。"]'),
('yuding-64','十離詩：珠離掌','薛濤','唐','御定全唐诗','yuding','','[]','皎潔圓明內外通，清光似照水晶宮。',32,'御定全唐詩/json/803.json','["皎潔圓明內外通，清光似照水晶宮。", "只緣一點玷相穢，不得終宵在掌中。"]'),
('yuding-65','十離詩：魚離池','薛濤','唐','御定全唐诗','yuding','','[]','跳躍深池四五秋，常搖朱尾弄綸鉤。',32,'御定全唐詩/json/803.json','["跳躍深池四五秋，常搖朱尾弄綸鉤。", "無端擺斷芙蓉朵，不得清波更一遊。"]'),
('yuding-66','十離詩：鷹離鞲','薛濤','唐','御定全唐诗','yuding','','[]','爪利如鋒眼似鈴，平原捉兔稱高情。',32,'御定全唐詩/json/803.json','["爪利如鋒眼似鈴，平原捉兔稱高情。", "無端竄向青雲外，不得君王臂上擎。"]'),
('yuding-67','十離詩：竹離亭','薛濤','唐','御定全唐诗','yuding','','[]','蓊鬱新栽四五行，常將勁節負秋霜。',32,'御定全唐詩/json/803.json','["蓊鬱新栽四五行，常將勁節負秋霜。", "為緣春筍鑽牆破，不得垂陰覆玉堂。"]'),
('yuding-68','十離詩：鏡離台','薛濤','唐','御定全唐诗','yuding','','[]','鑄瀉黃金鏡始開，初生三五月裴回。',32,'御定全唐詩/json/803.json','["鑄瀉黃金鏡始開，初生三五月裴回。", "為遭無限塵蒙蔽，不得華堂上玉台。"]'),
('yuding-69','酬杜舍人','薛濤','唐','御定全唐诗','yuding','','[]','雙魚底事到儂家，撲手新詩片片霞。',32,'御定全唐詩/json/803.json','["雙魚底事到儂家，撲手新詩片片霞。", "唱到白蘋洲畔曲，芙蓉空老蜀江花。"]'),
('yuding-70','籌邊樓','薛濤','唐','御定全唐诗','yuding','','[]','平臨雲鳥八窗秋，壯壓西川四十州。',32,'御定全唐詩/json/803.json','["平臨雲鳥八窗秋，壯壓西川四十州。", "諸將莫貪羌族馬，最高層處見邊頭。"]'),
('yuding-71','贈韋校書','薛濤','唐','御定全唐诗','yuding','','[]','芸香誤比荊山玉，那似登科甲乙年。',32,'御定全唐詩/json/803.json','["芸香誤比荊山玉，那似登科甲乙年。", "澹地鮮風將綺思，飄花散蕊媚青天。"]'),
('yuding-72','江月樓','薛濤','唐','御定全唐诗','yuding','','[]','秋風仿佛吳江冷，鷗路參差夕陽影。垂虹納納臥譙門，',24,'御定全唐詩/json/803.json','["秋風仿佛吳江冷，鷗路參差夕陽影。垂虹納納臥譙門，"]'),
('yuding-73','西岩','薛濤','唐','御定全唐诗','yuding','','[]','憑闌卻憶騎鯨客，把酒臨風手自招。',32,'御定全唐詩/json/803.json','["憑闌卻憶騎鯨客，把酒臨風手自招。", "細雨聲中停去馬，夕陽影裏亂鳴蜩。"]'),
('yuding-74','罰赴邊上武相公二首','薛濤','唐','御定全唐诗','yuding','','[]','螢在荒蕪月在天，螢飛豈到月輪邊。',64,'御定全唐詩/json/803.json','["螢在荒蕪月在天，螢飛豈到月輪邊。", "重光萬里應相照，目斷雲霄信不傳。", "按轡嶺頭寒複寒，微風細雨徹心肝。", "但得放兒歸舍去，山水屏風永不看。"]'),
('yuding-75','寄舊詩與元微之','薛濤','唐','御定全唐诗','yuding','','[]','詩篇調態人皆有，細膩風光我獨知。月下詠花憐暗澹，',40,'御定全唐詩/json/803.json','["詩篇調態人皆有，細膩風光我獨知。月下詠花憐暗澹，", "老大不能收拾得，與君開似教男兒。"]'),
('yuding-76','句','薛濤','唐','御定全唐诗','yuding','','[]','枝迎南北鳥，葉送往來風。（濤八九歲知聲律。一日，',49,'御定全唐詩/json/803.json','["枝迎南北鳥，葉送往來風。（濤八九歲知聲律。一日，", "聲云云，父愀然久之。後果入樂籍。別本載田洙遇薛濤，"]'),
('yuding-0','賦得江邊柳','魚玄機','唐','御定全唐诗','yuding','','[]','翠色連荒岸，煙姿入遠樓。影鋪秋水面，花落釣人頭。',48,'御定全唐詩/json/804.json','["翠色連荒岸，煙姿入遠樓。影鋪秋水面，花落釣人頭。", "根老藏魚窟，枝低系客舟。蕭蕭風雨夜，驚夢複添愁。"]'),
('yuding-1','贈鄰女','魚玄機','唐','御定全唐诗','yuding','','[]','羞日遮羅袖，愁春懶起妝。易求無價寶，難得有心郎。',48,'御定全唐詩/json/804.json','["羞日遮羅袖，愁春懶起妝。易求無價寶，難得有心郎。", "枕上潛垂淚，花間暗斷腸。自能窺宋玉，何必恨王昌。"]'),
('yuding-2','寄國香','魚玄機','唐','御定全唐诗','yuding','','[]','旦夕醉吟身，相思又此春。雨中寄書使，窗下斷腸人。',48,'御定全唐詩/json/804.json','["旦夕醉吟身，相思又此春。雨中寄書使，窗下斷腸人。", "山卷珠簾看，愁隨芳草新。別來清宴上，幾度落梁塵。"]'),
('yuding-3','寄題煉師','魚玄機','唐','御定全唐诗','yuding','','[]','霞彩剪為衣，添香出繡幃。芙蓉花葉□，山水帔□稀。',48,'御定全唐詩/json/804.json','["霞彩剪為衣，添香出繡幃。芙蓉花葉□，山水帔□稀。", "駐履聞鶯語，開籠放鶴飛。高堂春睡覺，暮雨正霏霏。"]'),
('yuding-4','寄劉尚書','魚玄機','唐','御定全唐诗','yuding','','[]','八座鎮雄軍，歌謠滿路新。汾川三月雨，晉水百花春。',72,'御定全唐詩/json/804.json','["八座鎮雄軍，歌謠滿路新。汾川三月雨，晉水百花春。", "囹圄長空鎖，干戈久覆塵。儒僧觀子夜，羈客醉紅茵。", "筆硯行隨手，詩書坐繞身。小材多顧盼，得作食魚人。"]'),
('yuding-5','浣紗廟','魚玄機','唐','御定全唐诗','yuding','','[]','吳越相謀計策多，浣紗神女已相和。一雙笑靨才回面，',40,'御定全唐詩/json/804.json','["吳越相謀計策多，浣紗神女已相和。一雙笑靨才回面，", "只今諸暨長江畔，空有青山號苧蘿。"]'),
('yuding-6','賣殘牡丹','魚玄機','唐','御定全唐诗','yuding','','[]','臨風興歎落花頻，芳意潛消又一春。應為價高人不問，',40,'御定全唐詩/json/804.json','["臨風興歎落花頻，芳意潛消又一春。應為價高人不問，", "及至移根上林苑，王孫方恨買無因。"]'),
('yuding-7','酬李學士寄簟','魚玄機','唐','御定全唐诗','yuding','','[]','珍簟新鋪翡翠樓，泓澄玉水記方流。',32,'御定全唐詩/json/804.json','["珍簟新鋪翡翠樓，泓澄玉水記方流。", "唯應雲扇情相似，同向銀床恨早秋。"]'),
('yuding-8','情書','魚玄機','唐','御定全唐诗','yuding','','[]','飲冰食檗志無功，晉水壺關在夢中。秦鏡欲分愁墮鵲，',40,'御定全唐詩/json/804.json','["飲冰食檗志無功，晉水壺關在夢中。秦鏡欲分愁墮鵲，", "書信茫茫何處問，持竿盡日碧江空。"]'),
('yuding-9','閨怨','魚玄機','唐','御定全唐诗','yuding','','[]','蘼蕪盈手泣斜暉，聞道鄰家夫婿歸。別日南鴻才北去，',40,'御定全唐詩/json/804.json','["蘼蕪盈手泣斜暉，聞道鄰家夫婿歸。別日南鴻才北去，", "扃閉朱門人不到，砧聲何事透羅幃。"]'),
('yuding-10','春情寄子安','魚玄機','唐','御定全唐诗','yuding','','[]','山路欹斜石磴危，不愁行苦苦相思。冰銷遠澗憐清韻，',48,'御定全唐詩/json/804.json','["山路欹斜石磴危，不愁行苦苦相思。冰銷遠澗憐清韻，", "如松匪石盟長在，比翼連襟會肯遲。雖恨獨行冬盡日，"]'),
('yuding-11','打球作','魚玄機','唐','御定全唐诗','yuding','','[]','堅圓淨滑一星流，月杖爭敲未擬休。無滯礙時從撥弄，',40,'御定全唐詩/json/804.json','["堅圓淨滑一星流，月杖爭敲未擬休。無滯礙時從撥弄，", "畢竟入門應始了，願君爭取最前籌。"]'),
('yuding-12','暮春有感寄友人','魚玄機','唐','御定全唐诗','yuding','','[]','鶯語驚殘夢，輕妝改淚容。竹陰初月薄，江靜晚煙濃。',48,'御定全唐詩/json/804.json','["鶯語驚殘夢，輕妝改淚容。竹陰初月薄，江靜晚煙濃。", "濕觜銜泥燕，香須采蕊蜂。獨憐無限思，吟罷亞枝松。"]'),
('yuding-13','冬夜寄溫飛卿','魚玄機','唐','御定全唐诗','yuding','','[]','苦思搜詩燈下吟，不眠長夜怕寒衾。滿庭木葉愁風起，',40,'御定全唐詩/json/804.json','["苦思搜詩燈下吟，不眠長夜怕寒衾。滿庭木葉愁風起，", "幽棲莫定梧桐處，暮雀啾啾空繞林。"]'),
('yuding-14','酬李郢夏日釣魚回見示','魚玄機','唐','御定全唐诗','yuding','','[]','住處雖同巷，經年不一過。清詞勸舊女，香桂折新柯。',48,'御定全唐詩/json/804.json','["住處雖同巷，經年不一過。清詞勸舊女，香桂折新柯。", "道性欺冰雪，禪心笑綺羅。跡登霄漢上，無路接煙波。"]'),
('yuding-15','次韻西鄰新居兼乞酒','魚玄機','唐','御定全唐诗','yuding','','[]','一首詩來百度吟，新情字字又聲金。西看已有登垣意，',40,'御定全唐詩/json/804.json','["一首詩來百度吟，新情字字又聲金。西看已有登垣意，", "況逢寒節添鄉思，叔夜佳醪莫獨斟。"]'),
('yuding-16','和友人次韻','魚玄機','唐','御定全唐诗','yuding','','[]','何事能銷旅館愁，紅箋開處見銀鉤。蓬山雨灑千峰小，',40,'御定全唐詩/json/804.json','["何事能銷旅館愁，紅箋開處見銀鉤。蓬山雨灑千峰小，", "欲將香匣收藏卻，且惜時吟在手頭。"]'),
('yuding-17','和新及第悼亡詩二首','魚玄機','唐','御定全唐诗','yuding','','[]','仙籍人間不久留，片時已過十經秋。鴛鴦帳下香猶暖，',72,'御定全唐詩/json/804.json','["仙籍人間不久留，片時已過十經秋。鴛鴦帳下香猶暖，", "彩雲一去無消息，潘嶽多情欲白頭。", "一枝月桂和煙秀，萬樹江桃帶雨紅。", "且醉尊前休悵望，古來悲樂與今同。"]'),
('yuding-18','遊崇真觀南樓，睹新及第題名處','魚玄機','唐','御定全唐诗','yuding','','[]','雲峰滿目放春晴，歷歷銀鉤指下生。',32,'御定全唐詩/json/804.json','["雲峰滿目放春晴，歷歷銀鉤指下生。", "自恨羅衣掩詩句，舉頭空羨榜中名。"]'),
('yuding-19','愁思','魚玄機','唐','御定全唐诗','yuding','','[]','落葉紛紛暮雨和，朱絲獨撫自清歌。放情休恨無心友，',40,'御定全唐詩/json/804.json','["落葉紛紛暮雨和，朱絲獨撫自清歌。放情休恨無心友，", "布衣終作雲霄客，綠水青山時一過。"]'),
('yuding-20','秋怨','魚玄機','唐','御定全唐诗','yuding','','[]','自歎多情是足愁，況當風月滿庭秋。',32,'御定全唐詩/json/804.json','["自歎多情是足愁，況當風月滿庭秋。", "洞房偏與更聲近，夜夜燈前欲白頭。"]'),
('yuding-21','江行','魚玄機','唐','御定全唐诗','yuding','','[]','大江橫抱武昌斜，鸚鵡洲前戶萬家。',64,'御定全唐詩/json/804.json','["大江橫抱武昌斜，鸚鵡洲前戶萬家。", "畫舸春眠朝未足，夢為蝴蝶也尋花。", "煙花已入鸕鷀港，畫舸猶沿鸚鵡洲。", "醉臥醒吟都不覺，今朝驚在漢江頭。"]'),
('yuding-22','聞李端公垂釣回寄贈','魚玄機','唐','御定全唐诗','yuding','','[]','無限荷香染暑衣，阮郎何處弄船歸。',32,'御定全唐詩/json/804.json','["無限荷香染暑衣，阮郎何處弄船歸。", "自慚不及鴛鴦侶，猶得雙雙近釣磯。"]'),
('yuding-23','題任處士創資福寺','魚玄機','唐','御定全唐诗','yuding','','[]','幽人創奇境，遊客駐行程。粉壁空留字，蓮宮未有名。',48,'御定全唐詩/json/804.json','["幽人創奇境，遊客駐行程。粉壁空留字，蓮宮未有名。", "鑿池泉自出，開徑草重生。百尺金輪閣，當川豁眼明。"]'),
('yuding-24','題隱霧亭','魚玄機','唐','御定全唐诗','yuding','','[]','春花秋月入詩篇，白日清宵是散仙。',32,'御定全唐詩/json/804.json','["春花秋月入詩篇，白日清宵是散仙。", "空卷珠簾不曾下，長移一榻對山眠。"]'),
('yuding-25','重陽阻雨','魚玄機','唐','御定全唐诗','yuding','','[]','滿庭黃菊籬邊拆，兩朵芙蓉鏡裏開。',32,'御定全唐詩/json/804.json','["滿庭黃菊籬邊拆，兩朵芙蓉鏡裏開。", "落帽台前風雨阻，不知何處醉金杯。"]'),
('yuding-26','早秋','魚玄機','唐','御定全唐诗','yuding','','[]','嫩菊含新彩，遠山閑夕煙。涼風驚綠樹，清韻入朱弦。',48,'御定全唐詩/json/804.json','["嫩菊含新彩，遠山閑夕煙。涼風驚綠樹，清韻入朱弦。", "思婦機中錦，征人塞外天。雁飛魚在水，書信若為傳。"]'),
('yuding-27','感懷寄人','魚玄機','唐','御定全唐诗','yuding','','[]','恨寄朱弦上，含情意不任。早知雲雨會，未起蕙蘭心。',72,'御定全唐詩/json/804.json','["恨寄朱弦上，含情意不任。早知雲雨會，未起蕙蘭心。", "灼灼桃兼李，無妨國士尋。蒼蒼松與桂，仍羨世人欽。", "月色苔階淨，歌聲竹院深。門前紅葉地，不掃待知音。"]'),
('yuding-28','期友人阻雨不至','魚玄機','唐','御定全唐诗','yuding','','[]','雁魚空有信，雞黍恨無期。閉戶方籠月，褰簾已散絲。',48,'御定全唐詩/json/804.json','["雁魚空有信，雞黍恨無期。閉戶方籠月，褰簾已散絲。", "近泉鳴砌畔，遠浪漲江湄。鄉思悲秋客，愁吟五字詩。"]'),
('yuding-29','訪趙煉師不遇','魚玄機','唐','御定全唐诗','yuding','','[]','何處同仙侶，青衣獨在家。暖爐留煮藥，鄰院為煎茶。',48,'御定全唐詩/json/804.json','["何處同仙侶，青衣獨在家。暖爐留煮藥，鄰院為煎茶。", "畫壁燈光暗，幡竿日影斜。殷勤重回首，牆外數枝花。"]'),
('yuding-30','遣懷','魚玄機','唐','御定全唐诗','yuding','','[]','閒散身無事，風光獨自遊。斷雲江上月，解纜海中舟。',96,'御定全唐詩/json/804.json','["閒散身無事，風光獨自遊。斷雲江上月，解纜海中舟。", "琴弄蕭梁寺，詩吟庾亮樓。叢篁堪作伴，片石好為儔。", "燕雀徒為貴，金銀志不求。滿杯春酒綠，對月夜窗幽。", "繞砌澄清沼，抽簪映細流。臥床書冊遍，半醉起梳頭。"]'),
('yuding-31','寄飛卿','魚玄機','唐','御定全唐诗','yuding','','[]','階砌亂蛩鳴，庭柯煙露清。月中鄰樂響，樓上遠山明。',48,'御定全唐詩/json/804.json','["階砌亂蛩鳴，庭柯煙露清。月中鄰樂響，樓上遠山明。", "珍簟涼風著，瑤琴寄恨生。嵇君懶書劄，底物慰秋情。"]'),
('yuding-32','過鄂州','魚玄機','唐','御定全唐诗','yuding','','[]','柳拂蘭橈花滿枝，石城城下暮帆遲。折牌峰上三閭墓，',40,'御定全唐詩/json/804.json','["柳拂蘭橈花滿枝，石城城下暮帆遲。折牌峰上三閭墓，", "莫愁魂逐清江去，空使行人萬首詩。"]'),
('yuding-33','夏日山居','魚玄機','唐','御定全唐诗','yuding','','[]','移得仙居此地來，花叢自遍不曾栽。庭前亞樹張衣桁，',40,'御定全唐詩/json/804.json','["移得仙居此地來，花叢自遍不曾栽。庭前亞樹張衣桁，", "閑乘畫舫吟明月，信任輕風吹卻回。"]'),
('yuding-34','暮春即事','魚玄機','唐','御定全唐诗','yuding','','[]','深巷窮門少侶儔，阮郎唯有夢中留。香飄羅綺誰家席，',40,'御定全唐詩/json/804.json','["深巷窮門少侶儔，阮郎唯有夢中留。香飄羅綺誰家席，", "安能追逐人間事，萬里身同不系舟。"]'),
('yuding-35','代人悼亡','魚玄機','唐','御定全唐诗','yuding','','[]','曾睹夭桃想玉姿，帶風楊柳認蛾眉。珠歸龍窟知誰見，',40,'御定全唐詩/json/804.json','["曾睹夭桃想玉姿，帶風楊柳認蛾眉。珠歸龍窟知誰見，", "西山日落東山月，恨想無因有了期。"]'),
('yuding-36','和人','魚玄機','唐','御定全唐诗','yuding','','[]','茫茫九陌無知己，暮去朝來典繡衣。寶匣鏡昏蟬鬢亂，',40,'御定全唐詩/json/804.json','["茫茫九陌無知己，暮去朝來典繡衣。寶匣鏡昏蟬鬢亂，", "莫惜羊車頻列載，柳絲梅綻正芳菲。"]'),
('yuding-37','隔漢江寄子安','魚玄機','唐','御定全唐诗','yuding','','[]','江南江北愁望，相思相憶空吟。鴛鴦暖臥沙浦，',35,'御定全唐詩/json/804.json','["江南江北愁望，相思相憶空吟。鴛鴦暖臥沙浦，", "含情咫尺千里，況聽家家遠砧。"]'),
('yuding-38','寓言','魚玄機','唐','御定全唐诗','yuding','','[]','紅桃處處春色，碧柳家家月明。樓上新妝待夜，',35,'御定全唐詩/json/804.json','["紅桃處處春色，碧柳家家月明。樓上新妝待夜，", "人世悲歡一夢，如何得作雙成。"]'),
('yuding-39','江陵愁望寄子安','魚玄機','唐','御定全唐诗','yuding','','[]','楓葉千枝複萬枝，江橋掩映暮帆遲。',32,'御定全唐詩/json/804.json','["楓葉千枝複萬枝，江橋掩映暮帆遲。", "憶君心似西江水，日夜東流無歇時。"]'),
('yuding-40','寄子安','魚玄機','唐','御定全唐诗','yuding','','[]','醉別千卮不浣愁，離腸百結解無由。蕙蘭銷歇歸春圃，',40,'御定全唐詩/json/804.json','["醉別千卮不浣愁，離腸百結解無由。蕙蘭銷歇歸春圃，", "有花時節知難遇，未肯厭厭醉玉樓。"]'),
('yuding-41','送別','魚玄機','唐','御定全唐诗','yuding','','[]','秦樓幾夜愜心期，不料仙郎有別離。',32,'御定全唐詩/json/804.json','["秦樓幾夜愜心期，不料仙郎有別離。", "睡覺莫言雲去處，殘燈一盞野蛾飛。"]'),
('yuding-42','迎李近仁員外','魚玄機','唐','御定全唐诗','yuding','','[]','今日喜時聞喜鵲，昨宵燈下拜燈花。',32,'御定全唐詩/json/804.json','["今日喜時聞喜鵲，昨宵燈下拜燈花。", "焚香出戶迎潘嶽，不羨牽牛織女家。"]'),
('yuding-43','送別','魚玄機','唐','御定全唐诗','yuding','','[]','水柔逐器知難定，雲出無心肯再歸。',32,'御定全唐詩/json/804.json','["水柔逐器知難定，雲出無心肯再歸。", "惆悵春風楚江暮，鴛鴦一隻失群飛。"]'),
('yuding-44','左名場自澤州至京，使人傳語','魚玄機','唐','御定全唐诗','yuding','','[]','閒居作賦幾年愁，王屋山前是舊遊。詩詠東西千嶂亂，',48,'御定全唐詩/json/804.json','["閒居作賦幾年愁，王屋山前是舊遊。詩詠東西千嶂亂，", "忽喜扣門傳語至，為憐鄰巷小房幽。相如琴罷朱弦斷，"]'),
('yuding-45','和人次韻','魚玄機','唐','御定全唐诗','yuding','','[]','喧喧朱紫雜人寰，獨自清吟日色間。何事玉郎搜藻思，',40,'御定全唐詩/json/804.json','["喧喧朱紫雜人寰，獨自清吟日色間。何事玉郎搜藻思，", "不用多情欲相見，松蘿高處是前山。"]'),
('yuding-46','光、威、裒姊妹三人少孤而始妍乃有是作…因次其韻','魚玄機','唐','御定全唐诗','yuding','','[]','昔聞南國容華少，今日東鄰姊妹三。妝閣相看鸚鵡賦，',96,'御定全唐詩/json/804.json','["昔聞南國容華少，今日東鄰姊妹三。妝閣相看鸚鵡賦，", "恐向瑤池曾作女，謫來塵世未為男。文姬有貌終堪比，", "當台競鬥青絲發，對月爭誇白玉簪。小有洞中松露滴，", "阿母幾嗔花下語，潘郎曾向夢中參。暫持清句魂猶斷，"]'),
('yuding-47','折楊柳','魚玄機','唐','御定全唐诗','yuding','','[]','朝朝送別泣花鈿，折盡春風楊柳煙。',32,'御定全唐詩/json/804.json','["朝朝送別泣花鈿，折盡春風楊柳煙。", "願得西山無樹木，免教人作淚懸懸。"]'),
('yuding-48','句','魚玄機','唐','御定全唐诗','yuding','','[]','焚香登玉壇，端簡禮金闕。',64,'御定全唐詩/json/804.json','["焚香登玉壇，端簡禮金闕。", "明月照幽隙，清風開短襟。", "綺陌春望遠，瑤徽春興多。", "殷勤不得語，紅淚一雙流。", "雲情自鬱爭同夢，仙貌長芳又勝花。"]'),
('yuding-0','湖上臥病喜陸鴻漸至','李冶','唐','御定全唐诗','yuding','','[]','昔去繁霜月，今來苦霧時。相逢仍臥病，欲語淚先垂。',48,'御定全唐詩/json/805.json','["昔去繁霜月，今來苦霧時。相逢仍臥病，欲語淚先垂。", "強勸陶家酒，還吟謝客詩。偶然成一醉，此外更何之。"]'),
('yuding-1','寄校書七兄','李冶','唐','御定全唐诗','yuding','','[]','無事烏程縣，蹉跎歲月餘。不知芸閣吏，寂寞竟何如。',48,'御定全唐詩/json/805.json','["無事烏程縣，蹉跎歲月餘。不知芸閣吏，寂寞竟何如。", "遠水浮仙棹，寒星伴使車。因過大雷岸，莫忘八行書。"]'),
('yuding-2','寄朱放','李冶','唐','御定全唐诗','yuding','','[]','望水試登山，山高湖又闊。相思無曉夕，相望經年月。',48,'御定全唐詩/json/805.json','["望水試登山，山高湖又闊。相思無曉夕，相望經年月。", "鬱鬱山木榮，綿綿野花發。別後無限情，相逢一時說。"]'),
('yuding-3','送韓揆之江西','李冶','唐','御定全唐诗','yuding','','[]','相看指楊柳，別恨轉依依。萬里江西水，孤舟何處歸。',48,'御定全唐詩/json/805.json','["相看指楊柳，別恨轉依依。萬里江西水，孤舟何處歸。", "湓城潮不到，夏口信應稀。唯有衡陽雁，年年來去飛。"]'),
('yuding-4','道意寄崔侍郎','李冶','唐','御定全唐诗','yuding','','[]','莫漫戀浮名，應須薄宦情。百年齊旦暮，前事盡虛盈。',48,'御定全唐詩/json/805.json','["莫漫戀浮名，應須薄宦情。百年齊旦暮，前事盡虛盈。", "愁鬢行看白，童顏學未成。無過天竺國，依止古先生。"]'),
('yuding-5','從蕭叔子聽彈琴，賦得三峽流泉歌','李冶','唐','御定全唐诗','yuding','','[]','妾家本住巫山雲，巫山流泉常自聞。玉琴彈出轉寥夐，',72,'御定全唐詩/json/805.json','["妾家本住巫山雲，巫山流泉常自聞。玉琴彈出轉寥夐，", "巨石崩崖指下生，飛泉走浪弦中起。初疑憤怒含雷風，", "憶昔阮公為此曲，能令仲容聽不足。一彈既罷複一彈，"]'),
('yuding-6','相思怨','李冶','唐','御定全唐诗','yuding','','[]','人道海水深，不抵相思半。海水尚有涯，相思渺無畔。',48,'御定全唐詩/json/805.json','["人道海水深，不抵相思半。海水尚有涯，相思渺無畔。", "攜琴上高樓，樓虛月華滿。彈著相思曲，弦腸一時斷。"]'),
('yuding-7','感興','李冶','唐','御定全唐诗','yuding','','[]','朝雲暮雨鎮相隨，去雁來人有返期。玉枕只知長下淚，',40,'御定全唐詩/json/805.json','["朝雲暮雨鎮相隨，去雁來人有返期。玉枕只知長下淚，", "卻憶初聞鳳樓曲，教人寂寞複相思。"]'),
('yuding-8','恩命追入，留別廣陵故人','李冶','唐','御定全唐诗','yuding','','[]','無才多病分龍鍾，不料虛名達九重。仰愧彈冠上華髮，',40,'御定全唐詩/json/805.json','["無才多病分龍鍾，不料虛名達九重。仰愧彈冠上華髮，", "桂樹不能留野客，沙鷗出浦謾相逢。"]'),
('yuding-9','八至','李冶','唐','御定全唐诗','yuding','','[]','至近至遠東西，至深至淺清溪。',28,'御定全唐詩/json/805.json','["至近至遠東西，至深至淺清溪。", "至高至明日月，至親至疏夫妻。"]'),
('yuding-10','送閻二十六赴剡縣','李冶','唐','御定全唐诗','yuding','','[]','流水閶門外，孤舟日複西。離情遍芳草，無處不萋萋。',48,'御定全唐詩/json/805.json','["流水閶門外，孤舟日複西。離情遍芳草，無處不萋萋。", "妾夢經吳苑，君行到剡溪。歸來重相訪，莫學阮郎迷。"]'),
('yuding-11','得閻伯鈞書','李冶','唐','御定全唐诗','yuding','','[]','情來對鏡懶梳頭，暮雨蕭蕭庭樹秋。',32,'御定全唐詩/json/805.json','["情來對鏡懶梳頭，暮雨蕭蕭庭樹秋。", "莫怪闌幹垂玉箸，只緣惆悵對銀鉤。"]'),
('yuding-12','結素魚貽友人','李冶','唐','御定全唐诗','yuding','','[]','尺素如殘雪，結為雙鯉魚。欲知心裏事，看取腹中書。',24,'御定全唐詩/json/805.json','["尺素如殘雪，結為雙鯉魚。欲知心裏事，看取腹中書。"]'),
('yuding-13','偶居','李冶','唐','御定全唐诗','yuding','','[]','心遠浮雲知不還，心雲並在有無間。',32,'御定全唐詩/json/805.json','["心遠浮雲知不還，心雲並在有無間。", "狂風何事相搖盪，吹向南山複北山。"]'),
('yuding-14','明月夜留別','李冶','唐','御定全唐诗','yuding','','[]','離人無語月無聲，明月有光人有情。',32,'御定全唐詩/json/805.json','["離人無語月無聲，明月有光人有情。", "別後相思人似月，雲間水上到層城。"]'),
('yuding-15','春閨怨','李冶','唐','御定全唐诗','yuding','','[]','百尺井欄上，數株桃已紅。念君遼海北，拋妾宋家東。',24,'御定全唐詩/json/805.json','["百尺井欄上，數株桃已紅。念君遼海北，拋妾宋家東。"]'),
('yuding-16','句','李冶','唐','御定全唐诗','yuding','','[]','經時未架卻，心緒亂縱橫。（季蘭五六歲時，其父抱于庭，',74,'御定全唐詩/json/805.json','["經時未架卻，心緒亂縱橫。（季蘭五六歲時，其父抱于庭，", "已看雲鬟散，更念木枯榮。", "鞞鼓喧行選，旌旗拂座隅。", "不睹河陽一縣花，空見青山三兩點。（《寄房明府》，"]'),
('yuding-17','寄洛中諸姊','元淳','唐','御定全唐诗','yuding','','[]','舊國經年別，關河萬里思。題詩憑雁翼，望月想蛾眉。',48,'御定全唐詩/json/805.json','["舊國經年別，關河萬里思。題詩憑雁翼，望月想蛾眉。", "白發愁偏覺，歸心夢獨知。誰堪離亂處，掩淚向南枝。"]'),
('yuding-18','秦中春望','元淳','唐','御定全唐诗','yuding','','[]','鳳樓春望好，宮闕一重重。上苑雨中樹，終南霽後峰。',48,'御定全唐詩/json/805.json','["鳳樓春望好，宮闕一重重。上苑雨中樹，終南霽後峰。", "落花行處遍，佳氣晚來濃。喜見休明代，霓裳躡道蹤。"]'),
('yuding-19','句','元淳','唐','御定全唐诗','yuding','','[]','弟兄俱已盡，松柏問何人。',66,'御定全唐詩/json/805.json','["弟兄俱已盡，松柏問何人。", "聞道茂陵山水好，碧溪流水有桃源。", "赤城峭壁無人到，丹灶芝田有鶴來。", "三千宮女露蛾眉，笑煮黃金日月遲。（《寓言》，"]'),
('yuding-20','舟夜一章','海印','唐','御定全唐诗','yuding','','[]','水色連天色，風聲益浪聲。旅人歸思苦，漁叟夢魂驚。',48,'御定全唐詩/json/805.json','["水色連天色，風聲益浪聲。旅人歸思苦，漁叟夢魂驚。", "舉棹雲先到，移舟月逐行。旋吟詩句罷，猶見遠山橫。"]'),
('yuding-0','詩三百三首','寒山','唐','御定全唐诗','yuding','','[]','凡讀我詩者，心中須護淨。慳貪繼日廉，諂曲登時正。',576,'御定全唐詩/json/806.json','["凡讀我詩者，心中須護淨。慳貪繼日廉，諂曲登時正。", "驅遣除惡業，歸依受真性。今日得佛身，急急如律令。", "重岩我卜居，鳥道絕人跡。庭際何所有，白雲抱幽石。", "住茲凡幾年，屢見春冬易。寄語鐘鼎家，虛名定無益。", "可笑寒山道，而無車馬蹤。聯溪難記曲，疊嶂不知重。", "泣露千般草，吟風一樣松。此時迷徑處，形問影何從。", "吾家好隱淪，居處絕囂塵。踐草成三徑，瞻雲作四鄰。", "助歌聲有鳥，問法語無人。今日娑婆樹，幾年為一春。", "琴書須自隨，祿位用何為。投輦從賢婦，巾車有孝兒。", "風吹曝麥地，水溢沃魚池。常念鷦鷯鳥，安身在一枝。", "弟兄同五郡，父子本三州。欲驗飛鳧集，須征白兔遊。", "靈瓜夢裏受，神橘座中收。鄉國何迢遞，同魚寄水流。", "一為書劍客，二遇聖明君。東守文不賞，西征武不勳。", "學文兼學武，學武兼學文。今日既老矣，餘生不足雲。", "莊子說送終，天地為棺槨。吾歸此有時，唯須一番箔。", "死將喂青蠅，吊不勞白鶴。餓著首陽山，生廉死亦樂。", "人問寒山道，寒山路不通。夏天冰未釋，日出霧朦朧。", "似我何由屆，與君心不同。君心若似我，還得到其中。", "天生百尺樹，剪作長條木。可惜棟樑材，拋之在幽谷。", "年多心尚勁，日久皮漸禿。識者取將來，猶堪柱馬屋。", "驅馬度荒城，荒城動客情。高低舊雉堞，大小古墳塋。", "自振孤蓬影，長凝拱木聲。所嗟皆俗骨，仙史更無名。", "鸚鵡宅西國，虞羅捕得歸。美人朝夕弄，出入在庭幃。", "賜以金籠貯，扃哉損羽衣。不如鴻與鶴，颻颺入雲飛。"]'),
('yuding-1','三字詩六首','寒山','唐','御定全唐诗','yuding','','[]','寒山道，無人到。若能行，稱十號。有蟬鳴，',164,'御定全唐詩/json/806.json','["寒山道，無人到。若能行，稱十號。有蟬鳴，", "我獨居，名善導。子細看，何相好。", "寒山寒，冰鎖石。藏山青，現雪白。", "日出照，一時釋。從茲暖，養老客。", "我居山，勿人識。白雲中，常寂寂。", "寒山深，稱我心。純白石，勿黃金。", "泉聲響，撫伯琴。有子期，辨此音。", "重岩中，足清風。扇不搖，涼冷通。", "明月照，白雲籠。獨自坐，一老翁。", "寒山子，長如是。獨自居，不生死。"]'),
('yuding-2','拾遺二首新添','寒山','唐','御定全唐诗','yuding','','[]','我見世間人，個個爭意氣。一朝忽然死，只得一片地。',72,'御定全唐詩/json/806.json','["我見世間人，個個爭意氣。一朝忽然死，只得一片地。", "闊四尺，長丈二。汝若會出來爭意氣，我與汝立碑記。", "家有寒山詩，勝汝看經卷。書放屏風上，時時看一遍。"]'),
('yuding-0','詩','拾得','唐','御定全唐诗','yuding','','[]','諸佛留藏經，只為人難化。不唯賢與愚，個個心構架。',576,'御定全唐詩/json/807.json','["諸佛留藏經，只為人難化。不唯賢與愚，個個心構架。", "造業大如山，豈解懷憂怕。那肯細尋思，日夜懷奸詐。", "嗟見世間人，個個愛吃肉。碗碟不曾幹，長時道不足。", "昨日設個齋，今朝宰六畜。都緣業使牽，非幹情所欲。", "一度造天堂，百度造地獄。閻羅使來追，闔家盡啼哭。", "爐子邊向火，鑊子裏澡浴。更得出頭時，換卻汝衣服。", "出家要清閒，清閒即為貴。如何塵外人，卻入塵埃裏。", "一向迷本心，終朝役名利。名利得到身，形容已憔悴。", "況複不遂者，虛用平生志。可憐無事人，未能笑得爾。", "養兒與娶妻，養女求媒娉。重重皆是業，更殺眾生命。", "聚集會親情，總來看盤飣。目下雖稱心，罪簿先註定。", "得此分段身，可笑好形質。面貌似銀盤，心中黑如漆。", "烹豬又宰羊，誇道甜如蜜。死後受波吒，更莫稱冤屈。", "佛哀三界子，總是親男女。恐沈黑暗坑，示儀垂化度。", "盡登無上道，俱證菩提路。教汝癡眾生，慧心勤覺悟。", "佛舍尊榮樂，為湣諸癡子。早願悟無生，辦集無上事。", "後來出家者，多緣無業次。不能得衣食，頭鑽入於寺。", "嗟見世間人，永劫在迷津。不省這個意，修行徒苦辛。", "我詩也是詩，有人喚作偈。詩偈總一般，讀時鬚子細。", "緩緩細披尋，不得生容易。依此學修行，大有可笑事。", "有偈有千萬，卒急述應難。若要相知者，但入天臺山。", "岩中深處坐，說理及談玄。共我不相見，對面似千山。", "世間億萬人，面孔不相似。借問何因緣，致令遣如此。", "各執一般見，互說非兼是。但自修己身，不要言他已。"]'),
('yuding-1','壁上詩二首','豐幹','唐','御定全唐诗','yuding','','[]','餘自來天臺，凡經幾萬回。一身如雲水，悠悠任去來。',144,'御定全唐詩/json/807.json','["餘自來天臺，凡經幾萬回。一身如雲水，悠悠任去來。", "逍遙絕無鬧，忘機隆佛道。世途岐路心，眾生多煩惱。", "兀兀沈浪海，漂漂輪三界。可惜一靈物，無始被境埋。", "電光瞥然起，生死紛塵埃。寒山特相訪，拾得常往來。", "論心話明月，太虛廓無礙。法界即無邊，一法普遍該。", "本來無一物，亦無塵可拂。若能了達此，不用坐兀兀。"]'),
('yuding-0','奉和竇使君同恭法師詠高僧二首：竺佛圖澄','慧宣','唐','御定全唐诗','yuding','','[]','大誓憫塗炭，乘機入生死。中州法既弘，葛陂暴亦止。',60,'御定全唐詩/json/808.json','["大誓憫塗炭，乘機入生死。中州法既弘，葛陂暴亦止。", "乳孔光一室，掌鏡徹千里。道盛咒蓮華，災生吟棘子。", "埋石緣雖謝，流沙化方始。"]'),
('yuding-1','奉和竇使君同恭法師詠高僧二首：釋僧肇','慧宣','唐','御定全唐诗','yuding','','[]','般若唯絕鑿，涅盤固無名。先賢未始覺，之子唱希聲。',60,'御定全唐詩/json/808.json','["般若唯絕鑿，涅盤固無名。先賢未始覺，之子唱希聲。", "秦王嗟理詣，童壽揖詞清。徽音聞廬嶽，精難動中京。", "適驗方袍裏，奇才複挺生。"]'),
('yuding-2','秋日遊東山寺尋殊曇二法師','慧宣','唐','御定全唐诗','yuding','','[]','木落樹蕭槮，水清流寂。屬此悲哉氣，複茲羈旅戚。',145,'御定全唐詩/json/808.json','["木落樹蕭槮，水清流寂。屬此悲哉氣，複茲羈旅戚。", "奚用寫煩憂，山泉恣遊歷。萬丈窺深澗，千尋仰絕壁。", "傍嶺竹參差，緣崖藤冪zx。行行極幽邃，去去逾空寂。", "果值息心侶，喬枝方掛錫。圍繞悉栴檀，純良豈沙礫。", "妙法誠無比，深經解怨敵。心歡即頂禮，道存仍目擊。", "慧刀幸已逢，疑網於焉析。豈直卻煩惱，方期拯沈溺。"]'),
('yuding-3','句','慧宣','唐','御定全唐诗','yuding','','[]','如蒙一被服，方堪稱福田。（詠賜玄奘衲、袈裟，',22,'御定全唐詩/json/808.json','["如蒙一被服，方堪稱福田。（詠賜玄奘衲、袈裟，"]'),
('yuding-4','愛妾換馬','法宣','唐','御定全唐诗','yuding','','[]','朱鬣飾金鑣，紅妝束素腰。似雲來躞蹀，如雪去飄颻。',48,'御定全唐詩/json/808.json','["朱鬣飾金鑣，紅妝束素腰。似雲來躞蹀，如雪去飄颻。", "桃花含淺汗，柳葉帶餘嬌。騁光將獨立，雙絕不俱標。"]'),
('yuding-5','和趙王觀妓','法宣','唐','御定全唐诗','yuding','','[]','桂山留上客，蘭室命妖饒。城中畫廣黛，宮裏束纖腰。',48,'御定全唐詩/json/808.json','["桂山留上客，蘭室命妖饒。城中畫廣黛，宮裏束纖腰。", "舞袖風前舉，歌聲扇後嬌。周郎不須顧，今日管弦調。"]'),
('yuding-6','聽獨杵擣衣','慧偘','唐','御定全唐诗','yuding','','[]','非是無人助，意欲自鳴砧。向月憐孤影，承風送迥音。',48,'御定全唐詩/json/808.json','["非是無人助，意欲自鳴砧。向月憐孤影，承風送迥音。", "疑搗雙絲練，似奏一弦琴。令君聞獨杵，知妾有專心。"]'),
('yuding-7','聞侯方兒來寇','慧偘','唐','御定全唐诗','yuding','','[]','羊皮贖去士，馬革斂還屍。天下方無事，孝廉非哭時。',24,'御定全唐詩/json/808.json','["羊皮贖去士，馬革斂還屍。天下方無事，孝廉非哭時。"]'),
('yuding-8','和琳法師初春法集之作','慧淨','唐','御定全唐诗','yuding','','[]','鷲嶺光前選，祇園表昔恭。哲人崇踵武，弘道會群龍。',108,'御定全唐詩/json/808.json','["鷲嶺光前選，祇園表昔恭。哲人崇踵武，弘道會群龍。", "高座登蓮葉，麈尾振霜松。塵飛揚雅梵，風度引疏鐘。", "靜言澄義海，發論上詞鋒。心虛道易合，跡廣席難重。", "和風動淑氣，麗日啟時雍。高才掞雅什，顧己濫朋從。", "因茲仰積善，靈華庶可逢。"]'),
('yuding-9','與英才言聚賦得升天行','慧淨','唐','御定全唐诗','yuding','','[]','馭風過閬苑，控鶴下瀛洲。欲采三芝秀，先從千仞遊。',48,'御定全唐詩/json/808.json','["馭風過閬苑，控鶴下瀛洲。欲采三芝秀，先從千仞遊。", "駕鳳吟虛管，乘槎泛淺流。頹齡一已駐，方驗大椿秋。"]'),
('yuding-10','和盧贊府游紀國道場','慧淨','唐','御定全唐诗','yuding','','[]','日光通漢室，星彩晦周朝。法城從此構，香閣本岧嶢。',72,'御定全唐詩/json/808.json','["日光通漢室，星彩晦周朝。法城從此構，香閣本岧嶢。", "株盤仰承露，刹鳳俯摩霄。落照侵虛牖，長虹拖跨橋。", "高才暫騁目，雲藻隨飄颻。欲追千里驥，終是謝連鑣。"]'),
('yuding-11','冬日普光寺臥疾，值雪簡諸舊遊','慧淨','唐','御定全唐诗','yuding','','[]','臥屙苦留滯，辟戶望遙天。寒雲舒複卷，落雪斷還連。',72,'御定全唐詩/json/808.json','["臥屙苦留滯，辟戶望遙天。寒雲舒複卷，落雪斷還連。", "凝華照書閣，飛素涴琴弦。回飄洛神賦，皎映齊紈篇。", "縈階如鶴舞，拂樹似花鮮。徒賞豐年瑞，沈憂終自憐。"]'),
('yuding-12','雜言','慧淨','唐','御定全唐诗','yuding','','[]','觀化祇山頂，流睇古王城。萬載池猶潔，千年苑尚清。',262,'御定全唐詩/json/808.json','["觀化祇山頂，流睇古王城。萬載池猶潔，千年苑尚清。", "仿佛影堅路，摧殘廣脅楹。七寶仙台亡舊跡，", "既傷火宅眩中門，還嗟寶渚迷長阪。步陟平郊望，", "唯有能仁獨圓悟，廓塵靜浪開玄路。創逢肌命棄身城，", "三祇不倦陵二車，一足忘勞超九數。定瀲江清沐久結，", "度有流光功德收，金河示滅歸常住。鶴林權唱演功周，", "流教在茲辰，傳芳代有人。沙河雪嶺迷朝徑，", "誓舍危軀追勝義，咸希畢契傳燈情。勞歌勿複陳，", "北睨舍城池尚在，南睎尊嶺穴猶存。五峰秀，百池分。", "粲粲鮮花明四曜，輝輝道樹鏡三春。揚錫指山阿，", "佇靈鎮梵嶽，凝思遍生河。金花逸掌儀前奉，", "回斯少福澗生津，共會龍華舍塵翳。"]'),
('yuding-13','三不為篇','海順','唐','御定全唐诗','yuding','','[]','我欲偃文修武，身死名存。斫石通道，祈井流泉。',141,'御定全唐詩/json/808.json','["我欲偃文修武，身死名存。斫石通道，祈井流泉。", "君肝在內，我身處邊。荊軻拔劍，毛遂捧盤。不為則已，", "我欲刺股錐刃，懸頭屋樑。書臨雪彩，牒映螢光。", "一朝鵬舉，萬里鸞翔。縱任才辯，遊說君王。高車反邑，", "我欲衒才鬻德，入市趨朝。四眾瞻仰，三槐附交。", "標形引勢，身達名超。箱盈綺服，廚富甘肴。諷揚弦管，"]'),
('yuding-14','出賜玄奘衲、袈裟衣應制','道恭','唐','御定全唐诗','yuding','','[]','福田資象德，聖種理幽熏。不持金作縷，還用彩成文。',48,'御定全唐詩/json/808.json','["福田資象德，聖種理幽熏。不持金作縷，還用彩成文。", "朱青自掩映，翠綺相氤氳。獨有離離葉，恒向稻畦分。"]'),
('yuding-15','設缸面酒款蕭翼，探得來字','辨才','唐','御定全唐诗','yuding','','[]','初醞一缸開，新知萬里來。披雲同落寞，步月共裴回。',48,'御定全唐詩/json/808.json','["初醞一缸開，新知萬里來。披雲同落寞，步月共裴回。", "夜久孤琴思，風長旅雁哀。非君有秘術，誰照不然灰。"]'),
('yuding-16','書遺文後','僧鳳','唐','御定全唐诗','yuding','','[]','苦哉黑闇女，樂矣功德天。智者俱不受，愚夫納二邊。',48,'御定全唐詩/json/808.json','["苦哉黑闇女，樂矣功德天。智者俱不受，愚夫納二邊。", "我奉能仁教，歸依彌勒前。願闡摩訶衍，成就那羅延。"]'),
('yuding-17','譏韋玎吟以韋字為韻','利涉','唐','御定全唐诗','yuding','','[]','我之佛法是無為，何故今朝得有為。',32,'御定全唐詩/json/808.json','["我之佛法是無為，何故今朝得有為。", "無韋始得三數載，不知此複是何韋。"]'),
('yuding-18','別三輔諸僧','道會','唐','御定全唐诗','yuding','','[]','去住俱為客，分悲損性情。共作無期別，誰能訪死生。',24,'御定全唐詩/json/808.json','["去住俱為客，分悲損性情。共作無期別，誰能訪死生。"]'),
('yuding-19','贈王仙柯','中寤','唐','御定全唐诗','yuding','','[]','瞻思不及望仙兄，早晚升霞入太清。手種一株松未老，',40,'御定全唐詩/json/808.json','["瞻思不及望仙兄，早晚升霞入太清。手種一株松未老，", "異日卻歸華表語，待教凡俗普聞名。"]'),
('yuding-20','在西國懷王舍城','義淨','唐','御定全唐诗','yuding','','[]','遊，愁。赤縣遠，丹思抽。鷲嶺寒風駛，龍河激水流。',60,'御定全唐詩/json/808.json','["遊，愁。赤縣遠，丹思抽。鷲嶺寒風駛，龍河激水流。", "既喜朝聞日複日，不覺頹年秋更秋。", "已畢耆山本願城難遇，終望持經振錫住神州。"]'),
('yuding-21','與無行禪師同游鷲嶺瞻奉…雜言詩','義淨','唐','御定全唐诗','yuding','','[]','觀化祇山頂，流睇古王城。萬載池猶潔，千年苑尚清。',263,'御定全唐詩/json/808.json','["觀化祇山頂，流睇古王城。萬載池猶潔，千年苑尚清。", "仿佛影堅路，摧殘廣脅gJ。七寶仙台亡舊跡，", "既傷火宅眩中門，還嗟寶渚迷長阪。步陟平郊望，", "唯有能仁獨圓悟，廓塵靜浪開玄路。創逢肌命棄身城，", "三祇不倦陵二車，一足忘勞超九數。定瀲江清沐久結，", "度有流光功德收，金河示滅歸常住。鶴林權唱演功周，", "流教在茲辰，傳芳代有人。沙河雪嶺迷朝徑，", "誓舍危軀追勝義，咸希畢契傳燈情。勞歌勿複陳，", "北睨舍城池尚在，南睎尊嶺穴猶存。五峰秀，百池分。", "粲粲鮮花明四曜，輝輝道樹鏡三春。揚錫指山阿，", "佇靈鎮梵嶽，凝思遍生河。金花逸掌儀前奉，", "回斯少福澗生津，共會龍華舍塵翳。"]'),
('yuding-22','玄逵律師言離廣府還望桂林去留愴然自述贈懷','義淨','唐','御定全唐诗','yuding','','[]','標心之梵宇，運想入仙洲。嬰痼乖同好，沈情阻若抽。',48,'御定全唐詩/json/808.json','["標心之梵宇，運想入仙洲。嬰痼乖同好，沈情阻若抽。", "葉落乍難聚，情離不可收。何日乘杯至，詳觀演法流。"]'),
('yuding-23','餘以咸亨元年在西京尋聽于時與並部處一法師…聊題兩絕','義淨','唐','御定全唐诗','yuding','','[]','我行之數萬，愁緒百重思。那教六尺影，獨步五天陲。',48,'御定全唐詩/json/808.json','["我行之數萬，愁緒百重思。那教六尺影，獨步五天陲。", "上將可陵師，匹士志難移。如論惜短命，何得滿長祇。"]'),
('yuding-24','西域寺','義淨','唐','御定全唐诗','yuding','','[]','眾美仍羅列，群英已古今。也知生死分，那得不傷心。',24,'御定全唐詩/json/808.json','["眾美仍羅列，群英已古今。也知生死分，那得不傷心。"]'),
('yuding-25','道希法師求法西域終於庵摩羅跋國後…聊題一絕','義淨','唐','御定全唐诗','yuding','','[]','百苦忘勞獨進影，四恩在念契流通。',32,'御定全唐詩/json/808.json','["百苦忘勞獨進影，四恩在念契流通。", "如何未盡傳燈志，溘然於此遇途窮。"]'),
('yuding-26','行路難','寶月','唐','御定全唐诗','yuding','','[]','君不見，孤雁關外發，酸嘶度楊越。空城客子心腸斷，',48,'御定全唐詩/json/808.json','["君不見，孤雁關外發，酸嘶度楊越。空城客子心腸斷，", "夜夜遙遙徒相思，年年望望情不歇。取我匣中青銅鏡，"]'),
('yuding-27','老僧','景雲','唐','御定全唐诗','yuding','','[]','日照西山雪，老僧門始開。凍瓶粘柱礎，宿火焰爐灰。',48,'御定全唐詩/json/808.json','["日照西山雪，老僧門始開。凍瓶粘柱礎，宿火焰爐灰。", "童子病歸去，鹿麑寒入來。齋鐘知漸近，枝鳥下生台。"]'),
('yuding-28','溪叟','景雲','唐','御定全唐诗','yuding','','[]','溪翁居處靜，溪鳥入門飛。早起釣魚去，夜深乘月歸。',48,'御定全唐詩/json/808.json','["溪翁居處靜，溪鳥入門飛。早起釣魚去，夜深乘月歸。", "露香菰米熟，煙暖荇絲肥。瀟灑塵埃外，扁舟一草衣。"]'),
('yuding-29','畫松','景雲','唐','御定全唐诗','yuding','','[]','畫松一似真松樹，且待尋思記得無。',32,'御定全唐詩/json/808.json','["畫松一似真松樹，且待尋思記得無。", "曾在天臺山上見，石橋南畔第三株。"]'),
('yuding-30','送戴三征君還穀口舊居','理瑩','唐','御定全唐诗','yuding','','[]','岩穴多遺秀，弓車屢遠招。周王尊渭叟，潁客傲唐堯。',120,'御定全唐詩/json/808.json','["岩穴多遺秀，弓車屢遠招。周王尊渭叟，潁客傲唐堯。", "出處天波洽，關河地勢遙。瞻星吳郡夜，作霧華山朝。", "清論虛重席，閒居掛一瓢。漁歌思坐酌，宸渥寵行軺。", "春為荷裳暖，霜因葛履消。層崖懸瀑溜，萬壑振清飆。", "穀鳥猶遷木，場駒正食苗。謝安何日起，台鼎佇君調。"]'),
('yuding-31','送童子下山','金地藏','唐','御定全唐诗','yuding','','[]','空門寂寞汝思家，禮別雲房下九華。愛向竹欄騎竹馬，',40,'御定全唐詩/json/808.json','["空門寂寞汝思家，禮別雲房下九華。愛向竹欄騎竹馬，", "好去不須頻下淚，老僧相伴有煙霞。"]'),
('yuding-32','題張僧繇醉僧圖','懷素','唐','御定全唐诗','yuding','','[]','人人送酒不曾沽，終日松間掛一壺。',32,'御定全唐詩/json/808.json','["人人送酒不曾沽，終日松間掛一壺。", "草聖欲成狂便發，真堪畫入醉僧圖。"]'),
('yuding-33','寄衡嶽僧','懷素','唐','御定全唐诗','yuding','','[]','祝融高座對寒峰，雲水昭丘幾萬重。',32,'御定全唐詩/json/808.json','["祝融高座對寒峰，雲水昭丘幾萬重。", "五月衲衣猶近火，起來白鶴冷青松。"]'),
('yuding-0','酬皇甫冉西陵見寄','靈一','唐','御定全唐诗','yuding','','[]','西陵潮信滿，島嶼沒中流。越客依風水，相思南渡頭。',48,'御定全唐詩/json/809.json','["西陵潮信滿，島嶼沒中流。越客依風水，相思南渡頭。", "寒光生極浦，落日映滄洲。何事揚帆去，空驚海上鷗。"]'),
('yuding-1','溪行即事','靈一','唐','御定全唐诗','yuding','','[]','近夜山更碧，入林溪轉清。不知伏牛事，潭洞何從橫。',48,'御定全唐詩/json/809.json','["近夜山更碧，入林溪轉清。不知伏牛事，潭洞何從橫。", "野岸煙初合，平湖月未生。孤舟屢失道，但聽秋泉聲。"]'),
('yuding-2','棲霞山夜坐','靈一','唐','御定全唐诗','yuding','','[]','山頭戒壇路，幽映雪岩側。四面青石床，一峰苔蘚色。',48,'御定全唐詩/json/809.json','["山頭戒壇路，幽映雪岩側。四面青石床，一峰苔蘚色。", "松風靜複起，月影開還黑。何獨乘夜來，殊非晝所得。"]'),
('yuding-3','宿天柱觀','靈一','唐','御定全唐诗','yuding','','[]','石室初投宿，仙翁喜暫容。花源隔水見，洞府過山逢。',48,'御定全唐詩/json/809.json','["石室初投宿，仙翁喜暫容。花源隔水見，洞府過山逢。", "泉湧階前地，雲生戶外峰。中宵自入定，非是欲降龍。"]'),
('yuding-4','酬皇甫冉將赴無錫，於雲門寺贈別','靈一','唐','御定全唐诗','yuding','','[]','湖南通古寺，來往意無涯。欲識雲門路，千峰到若耶。',48,'御定全唐詩/json/809.json','["湖南通古寺，來往意無涯。欲識雲門路，千峰到若耶。", "春山子敬宅，古木謝敷家。自可長偕隱，那言相去賒。"]'),
('yuding-5','宜豐新泉','靈一','唐','御定全唐诗','yuding','','[]','泉源新湧出，洞澈映纖雲。稍落芙蓉沼，初淹苔蘚文。',48,'御定全唐詩/json/809.json','["泉源新湧出，洞澈映纖雲。稍落芙蓉沼，初淹苔蘚文。", "素將空意合，淨與眾流分。每到清宵月，泠泠夢裏聞。"]'),
('yuding-6','靜林精舍','靈一','唐','御定全唐诗','yuding','','[]','靜林溪路遠，蕭帝有遺蹤。水擊羅浮磬，山鳴于闐鐘。',48,'御定全唐詩/json/809.json','["靜林溪路遠，蕭帝有遺蹤。水擊羅浮磬，山鳴于闐鐘。", "燈傳三世火，樹老萬株松。無數煙霞色，空聞昔臥龍。"]'),
('yuding-7','江行寄張舍人','靈一','唐','御定全唐诗','yuding','','[]','客程終日風塵苦，蓬轉還家未有期。林色曉分殘雪後，',40,'御定全唐詩/json/809.json','["客程終日風塵苦，蓬轉還家未有期。林色曉分殘雪後，", "流蕩此心難共說，千峰澄霽隔瓊枝。"]'),
('yuding-8','送王穎悟歸左綿','靈一','唐','御定全唐诗','yuding','','[]','客意天南興已闌，不堪言別向仙官。夢搖玉佩隨旄節，',40,'御定全唐詩/json/809.json','["客意天南興已闌，不堪言別向仙官。夢搖玉佩隨旄節，", "想得故山青靄裏，泉聲入夜獨潺潺。"]'),
('yuding-9','安公','靈一','唐','御定全唐诗','yuding','','[]','彌天稱聖哲，象法初繄賴。弘道識行藏，匡時知進退。',72,'御定全唐詩/json/809.json','["彌天稱聖哲，象法初繄賴。弘道識行藏，匡時知進退。", "秦王輕與舉，習生重酬對。學文古篆中，義顯心經內。", "法服應華夏，金言流海岱。西方浮雲間，更陪龍華會。"]'),
('yuding-10','林公','靈一','唐','御定全唐诗','yuding','','[]','支公信高逸，久向山林住。時將孫許游，豈以形骸遇。',72,'御定全唐詩/json/809.json','["支公信高逸，久向山林住。時將孫許游，豈以形骸遇。", "幸辭天子詔，複覽名臣疏。西晉尚虛無，南朝久淪誤。", "因談老莊意，乃盡逍遙趣。誰為竹林賢，風流相比附。"]'),
('yuding-11','遠公','靈一','唐','御定全唐诗','yuding','','[]','遠公逢道安，一朝棄儒服。真機久消歇，世教空拘束。',72,'御定全唐詩/json/809.json','["遠公逢道安，一朝棄儒服。真機久消歇，世教空拘束。", "誓入羅浮中，遂棲廬山曲。禪經初纂定，佛語新名目。", "缽帽絕朝宗，簪裾翻拜伏。東林多隱士，為我辭榮祿。"]'),
('yuding-12','雨後欲尋天目山，問元、駱二公溪路','靈一','唐','御定全唐诗','yuding','','[]','昨夜雲生天井東，春山一雨一回風。',32,'御定全唐詩/json/809.json','["昨夜雲生天井東，春山一雨一回風。", "林花並逐溪流下，欲上龍池通不通。"]'),
('yuding-13','題僧院','靈一','唐','御定全唐诗','yuding','','[]','虎溪閑月引相過，帶雪松枝掛薜蘿。',32,'御定全唐詩/json/809.json','["虎溪閑月引相過，帶雪松枝掛薜蘿。", "無限青山行欲盡，白雲深處老僧多。"]'),
('yuding-14','宿靜林寺','靈一','唐','御定全唐诗','yuding','','[]','山寺門前多古松，溪行欲到已聞鐘。',32,'御定全唐詩/json/809.json','["山寺門前多古松，溪行欲到已聞鐘。", "中宵引領尋高頂，月照雲峰凡幾重。"]'),
('yuding-15','再還宜豐寺','靈一','唐','御定全唐诗','yuding','','[]','再尋招隱地，重會息心期。樵客問歸日，山僧記別時。',48,'御定全唐詩/json/809.json','["再尋招隱地，重會息心期。樵客問歸日，山僧記別時。", "野雲陰遠甸，秋雨漲前陂。勿謂探形勝，吾今不好奇。"]'),
('yuding-16','春日山齋','靈一','唐','御定全唐诗','yuding','','[]','野徑東風起，山扉度日開。晴光拆紅萼，流水長青苔。',48,'御定全唐詩/json/809.json','["野徑東風起，山扉度日開。晴光拆紅萼，流水長青苔。", "逋客殊未去，芳時已再來。非關戀春草，自是欲裴回。"]'),
('yuding-17','留別忠州故人','靈一','唐','御定全唐诗','yuding','','[]','一身無定處，萬里獨銷魂。芳草迷歸路，春流滴淚痕。',48,'御定全唐詩/json/809.json','["一身無定處，萬里獨銷魂。芳草迷歸路，春流滴淚痕。", "幾時休旅食，何夜宿江村。欲識相思苦，空山啼暮猿。"]'),
('yuding-18','送別','靈一','唐','御定全唐诗','yuding','','[]','憑高莫送遠，看欲斷歸心。別恨啼猿苦，相思流水深。',48,'御定全唐詩/json/809.json','["憑高莫送遠，看欲斷歸心。別恨啼猿苦，相思流水深。", "翠雲南澗影，丹桂晚山陰。若未來雙鵠，遼城何更尋。"]'),
('yuding-19','送冽寺主之京迎禪和尚','靈一','唐','御定全唐诗','yuding','','[]','禪門居此地，瞻望在虛空。水國月未上，蒼生如夢中。',48,'御定全唐詩/json/809.json','["禪門居此地，瞻望在虛空。水國月未上，蒼生如夢中。", "上人知機士，瓶錫慰樊籠。彼土諸梵眾，嗟君揚道風。"]'),
('yuding-20','送王法師之西川','靈一','唐','御定全唐诗','yuding','','[]','旅遊無近遠，要自別魂銷。官柳鄉愁亂，春山客路遙。',48,'御定全唐詩/json/809.json','["旅遊無近遠，要自別魂銷。官柳鄉愁亂，春山客路遙。", "伴行芳草遠，緣興野花飄。計日功成後，還將輔聖朝。"]'),
('yuding-21','送范律師往果州','靈一','唐','御定全唐诗','yuding','','[]','終南千古後，獨爾繼卿名。離障非今日，修因是幾生。',48,'御定全唐詩/json/809.json','["終南千古後，獨爾繼卿名。離障非今日，修因是幾生。", "亂峰寒影暮，深澗野流清。遠客歸心苦，難為此別情。"]'),
('yuding-22','送明素上人歸楚覲省','靈一','唐','御定全唐诗','yuding','','[]','能將疏懶背時人，不厭孤萍任此身。江上昔年同出處，',40,'御定全唐詩/json/809.json','["能將疏懶背時人，不厭孤萍任此身。江上昔年同出處，", "前路倍憐多勝事，到家知慶彩衣新。"]'),
('yuding-23','項王廟','靈一','唐','御定全唐诗','yuding','','[]','緬想咸陽事可嗟，楚歌哀怨思無涯。八千子弟歸何處，',40,'御定全唐詩/json/809.json','["緬想咸陽事可嗟，楚歌哀怨思無涯。八千子弟歸何處，", "拔山力盡烏江水，今日悠悠空浪花。"]'),
('yuding-24','酬陳明府舟中見贈','靈一','唐','御定全唐诗','yuding','','[]','長溪通夜靜，素舸與人閑。月影沈秋水，風聲落暮山。',48,'御定全唐詩/json/809.json','["長溪通夜靜，素舸與人閑。月影沈秋水，風聲落暮山。", "稻花千頃外，蓮葉兩河間。陶令多真意，相思一解顏。"]'),
('yuding-25','題東蘭若','靈一','唐','御定全唐诗','yuding','','[]','上人禪室路裴回，萬木清陰向日開。寒竹影侵行徑石，',40,'御定全唐詩/json/809.json','["上人禪室路裴回，萬木清陰向日開。寒竹影侵行徑石，", "更惜片陽談妙理，歸時莫待暝鐘催。"]'),
('yuding-26','送朱放','靈一','唐','御定全唐诗','yuding','','[]','苦見人間世，思歸洞裏天。縱令山鳥語，不廢野人眠。',24,'御定全唐詩/json/809.json','["苦見人間世，思歸洞裏天。縱令山鳥語，不廢野人眠。"]'),
('yuding-27','歸岑山過惟審上人別業','靈一','唐','御定全唐诗','yuding','','[]','禪客無心憶薜蘿，自然行徑向山多。',32,'御定全唐詩/json/809.json','["禪客無心憶薜蘿，自然行徑向山多。", "知君欲問人間事，始與浮雲共一過。"]'),
('yuding-28','於潛道中呈元八處士','靈一','唐','御定全唐诗','yuding','','[]','苕水灘行淺，潛州路漸深。參差遠岫色，迢遞野人心。',48,'御定全唐詩/json/809.json','["苕水灘行淺，潛州路漸深。參差遠岫色，迢遞野人心。", "凍澗冰難釋，秋山日易陰。不知天目下，何處是雲林。"]'),
('yuding-29','送殷判官歸上都','靈一','唐','御定全唐诗','yuding','','[]','漾舟雲路客，來過夕陽時。向背堪遺恨，逢迎宿未期。',48,'御定全唐詩/json/809.json','["漾舟雲路客，來過夕陽時。向背堪遺恨，逢迎宿未期。", "水容愁暮急，花影動春遲。別後王孫草，青青入夢思。"]'),
('yuding-30','贈別皇甫曾','靈一','唐','御定全唐诗','yuding','','[]','幽人從遠岳，過客愛春山。高駕能相送，孤遊且未還。',48,'御定全唐詩/json/809.json','["幽人從遠岳，過客愛春山。高駕能相送，孤遊且未還。", "紫苔封井石，綠竹掩柴關。若到雲峰外，齊心去住間。"]'),
('yuding-31','送陳允初卜居麻園','靈一','唐','御定全唐诗','yuding','','[]','欲向麻源隱，能尋謝客蹤。空山幾千里，幽谷第三重。',48,'御定全唐詩/json/809.json','["欲向麻源隱，能尋謝客蹤。空山幾千里，幽谷第三重。", "茅宇寧須葺，荷衣不待縫。因君見往事，為我謝喬松。"]'),
('yuding-32','秋題劉逸人林泉','靈一','唐','御定全唐诗','yuding','','[]','涼飆亂黃葉，遲客橘陰清。蘿徑封行跡，雲門閉野情。',48,'御定全唐詩/json/809.json','["涼飆亂黃葉，遲客橘陰清。蘿徑封行跡，雲門閉野情。", "零林秋露響，穿竹暮煙輕。莫戀幽棲地，懷安卻敗名。"]'),
('yuding-33','自大林與韓明府歸郭中精舍','靈一','唐','御定全唐诗','yuding','','[]','野客同舟楫，相攜複一歸。孤煙生暮景，遠岫帶春暉。',48,'御定全唐詩/json/809.json','["野客同舟楫，相攜複一歸。孤煙生暮景，遠岫帶春暉。", "不道還山是，誰雲向郭非。禪門有通隱，喧寂共忘機。"]'),
('yuding-34','同使君宿大樑驛','靈一','唐','御定全唐诗','yuding','','[]','旌旗江上出，花外捲簾空。夜色臨城月，春寒度水風。',48,'御定全唐詩/json/809.json','["旌旗江上出，花外捲簾空。夜色臨城月，春寒度水風。", "雖然行李別，且喜語音同。若問匡廬事，終身愧遠公。"]'),
('yuding-35','題黃公陶翰別業','靈一','唐','御定全唐诗','yuding','','[]','聞說花源堪避秦，幽尋數月不逢人。煙霞洞裏無雞犬，',40,'御定全唐詩/json/809.json','["聞說花源堪避秦，幽尋數月不逢人。煙霞洞裏無雞犬，", "醉臥白雲閑入夢，不知何物是吾身。"]'),
('yuding-36','哭衛尚書','靈一','唐','御定全唐诗','yuding','','[]','畫戟重門楚水陰，天涯欲暮共傷心。南荊雙戟痕猶在，',40,'御定全唐詩/json/809.json','["畫戟重門楚水陰，天涯欲暮共傷心。南荊雙戟痕猶在，", "有路茫茫向誰問，感君空有淚沾襟。"]'),
('yuding-37','贈靈澈禪師','靈一','唐','御定全唐诗','yuding','','[]','禪師來往翠微間，萬里千峰到剡山。',32,'御定全唐詩/json/809.json','["禪師來往翠微間，萬里千峰到剡山。", "何時共到天臺裏，身與浮雲處處閑。"]'),
('yuding-38','將出宜豐寺留題山房','靈一','唐','御定全唐诗','yuding','','[]','池上蓮荷不自開，山中流水偶然來。',32,'御定全唐詩/json/809.json','["池上蓮荷不自開，山中流水偶然來。", "若言聚散定由我，未是回時那得回。"]'),
('yuding-39','妙樂觀','靈一','唐','御定全唐诗','yuding','','[]','王喬所居空山觀，白雲至今凝不散。壇場月路幾千年，',48,'御定全唐詩/json/809.json','["王喬所居空山觀，白雲至今凝不散。壇場月路幾千年，", "忽見一人檠茶碗，篸花昨夜風吹滿。自言家處在東坡，"]'),
('yuding-40','與元居士青山潭飲茶','靈一','唐','御定全唐诗','yuding','','[]','野泉煙火白雲間，坐飲香茶愛此山。',32,'御定全唐詩/json/809.json','["野泉煙火白雲間，坐飲香茶愛此山。", "岩下維舟不忍去，青溪流水暮潺潺。"]'),
('yuding-41','送人得蕩子歸倡婦','靈一','唐','御定全唐诗','yuding','','[]','垂涕憑回信，為語柳園人。情知獨難守，又是一陽春。',24,'御定全唐詩/json/809.json','["垂涕憑回信，為語柳園人。情知獨難守，又是一陽春。"]'),
('yuding-42','句','靈一','唐','御定全唐诗','yuding','','[]','濾泉侵月起，掃徑避蟲行。',12,'御定全唐詩/json/809.json','["濾泉侵月起，掃徑避蟲行。"]'),
('yuding-0','聽鶯歌','靈澈','唐','御定全唐诗','yuding','','[]','新鶯傍簷曉更悲，孤音清泠囀素枝。口邊血出語未盡，',72,'御定全唐詩/json/810.json','["新鶯傍簷曉更悲，孤音清泠囀素枝。口邊血出語未盡，", "玄猿何事朝夜啼，白鷺長在汀洲宿。黑雕黃鶴豈不高，", "飛去來，莫上高城頭，莫下空園裏。城頭鴟烏拾膻腥，"]'),
('yuding-1','歸湖南作','靈澈','唐','御定全唐诗','yuding','','[]','山邊水邊待月明，暫向人間借路行。',32,'御定全唐詩/json/810.json','["山邊水邊待月明，暫向人間借路行。", "如今還向山邊去，只有湖水無行路。"]'),
('yuding-2','初到汀州','靈澈','唐','御定全唐诗','yuding','','[]','初放到滄洲，前心詎解愁。舊交容不拜，臨老學梳頭。',48,'御定全唐詩/json/810.json','["初放到滄洲，前心詎解愁。舊交容不拜，臨老學梳頭。", "禪室白雲去，故山明月秋。幾年猶在此，北戶水南流。"]'),
('yuding-3','九日和於使君思上京親故','靈澈','唐','御定全唐诗','yuding','','[]','清晨有高會，賓從出東方。楚俗風煙古，汀洲草木涼。',48,'御定全唐詩/json/810.json','["清晨有高會，賓從出東方。楚俗風煙古，汀洲草木涼。", "山情來遠思，菊意在重陽。心憶華池上，從容鴛鷺行。"]'),
('yuding-4','送道虔上人游方','靈澈','唐','御定全唐诗','yuding','','[]','律儀通外學，詩思入玄關。煙景隨緣到，風姿與道閑。',48,'御定全唐詩/json/810.json','["律儀通外學，詩思入玄關。煙景隨緣到，風姿與道閑。", "貫花留淨室，咒水度空山。誰識浮雲意，悠悠天地間。"]'),
('yuding-5','送鑒供奉歸蜀寧親','靈澈','唐','御定全唐诗','yuding','','[]','林間出定戀庭闈，聖主恩深暫許歸。雙樹欲辭金錫冷，',40,'御定全唐詩/json/810.json','["林間出定戀庭闈，聖主恩深暫許歸。雙樹欲辭金錫冷，", "此去不須求彩服，紫衣全勝老萊衣。"]'),
('yuding-6','天姥岑望天臺山','靈澈','唐','御定全唐诗','yuding','','[]','天臺眾峰外，華頂當寒空。有時半不見，崔嵬在雲中。',24,'御定全唐詩/json/810.json','["天臺眾峰外，華頂當寒空。有時半不見，崔嵬在雲中。"]'),
('yuding-7','遠公墓','靈澈','唐','御定全唐诗','yuding','','[]','古墓石棱棱，寒雲晚景凝。空悲虎溪月，不見雁門僧。',24,'御定全唐詩/json/810.json','["古墓石棱棱，寒雲晚景凝。空悲虎溪月，不見雁門僧。"]'),
('yuding-8','宿東林寺','靈澈','唐','御定全唐诗','yuding','','[]','天寒猛虎叫岩雪，林下無人空有月。',32,'御定全唐詩/json/810.json','["天寒猛虎叫岩雪，林下無人空有月。", "千年像教今不聞，焚香獨為鬼神說。"]'),
('yuding-9','簡寂觀','靈澈','唐','御定全唐诗','yuding','','[]','古松古柏岩壁間，猿攀鶴巢古枝折。',32,'御定全唐詩/json/810.json','["古松古柏岩壁間，猿攀鶴巢古枝折。", "五月有霜六月寒，時見山翁來取雪。"]'),
('yuding-10','元日觀郭將軍早朝','靈澈','唐','御定全唐诗','yuding','','[]','欲曙九衢人更多，千條香燭照星河。',32,'御定全唐詩/json/810.json','["欲曙九衢人更多，千條香燭照星河。", "今朝始見金吾貴，車馬縱橫避玉珂。"]'),
('yuding-11','東林寺酬韋丹刺史','靈澈','唐','御定全唐诗','yuding','','[]','年老心閑無外事，麻衣草座亦容身。',32,'御定全唐詩/json/810.json','["年老心閑無外事，麻衣草座亦容身。", "相逢盡道休官好，林下何曾見一人。"]'),
('yuding-12','東林寺寄包侍禦','靈澈','唐','御定全唐诗','yuding','','[]','古殿清陰山木春，池邊跂石一觀身。',32,'御定全唐詩/json/810.json','["古殿清陰山木春，池邊跂石一觀身。", "誰能來此焚香坐，共作壚峰二十人。"]'),
('yuding-13','西林寄楊公','靈澈','唐','御定全唐诗','yuding','','[]','日日愛山歸已遲，閑閒空度少年時。',32,'御定全唐詩/json/810.json','["日日愛山歸已遲，閑閒空度少年時。", "余身定寄林中老，心與長松片石期。"]'),
('yuding-14','答徐廣叔四問','靈澈','唐','御定全唐诗','yuding','','[]','童子出家無第行，隨師乞食遣稱名。',32,'御定全唐詩/json/810.json','["童子出家無第行，隨師乞食遣稱名。", "長沙豈敢論年幾，絳老惟知甲子生。"]'),
('yuding-15','聞李處士亡','靈澈','唐','御定全唐诗','yuding','','[]','時時聞說故人死，日日自悲隨老身。',32,'御定全唐詩/json/810.json','["時時聞說故人死，日日自悲隨老身。", "白髮不生應不得，青山長在屬何人。"]'),
('yuding-16','句','靈澈','唐','御定全唐诗','yuding','','[]','松樹有死枝，塚上唯莓苔。石門無人入，古木花不開。',160,'御定全唐詩/json/810.json','["松樹有死枝，塚上唯莓苔。石門無人入，古木花不開。", "綠竹歲寒在，故人衰老多。", "月色靜中見，泉聲深處聞。", "古觀茅山下，諸峰欲曙時。真人是黃子，玉堂生紫芝。", "禪門至六祖，衣缽無人得。", "古墓碑表折，荒壟松柏稀。", "秋深知氣正，家近覺山寒。", "山僧不記重陽日，因見茱萸憶去年。", "今非古獄下，莫向鬥邊看。", "海月生殘夜，江春入暮年。", "窗風枯硯水，山雨慢琴弦。"]'),
('yuding-17','湘夫人祠','大易','唐','御定全唐诗','yuding','','[]','靈祠古木合，波揚大江濆。未□湘南雨，知為何處雲。',48,'御定全唐詩/json/810.json','["靈祠古木合，波揚大江濆。未□湘南雨，知為何處雲。", "苔痕澀珠履，草色妒羅裙。妙鼓彤雲瑟，羈臣不可聞。"]'),
('yuding-18','贈司空拾遺','大易','唐','御定全唐诗','yuding','','[]','侍臣何事辭雲陛，江上微雲見雪花。望閣未承丹鳳詔，',40,'御定全唐詩/json/810.json','["侍臣何事辭雲陛，江上微雲見雪花。望閣未承丹鳳詔，", "高館更容塵外客，仍令歸路待瑤華。"]'),
('yuding-19','寄錢郎中','法照','唐','御定全唐诗','yuding','','[]','閉門深樹裏，閑足鳥來過。五馬不復貴，一僧誰奈何。',48,'御定全唐詩/json/810.json','["閉門深樹裏，閑足鳥來過。五馬不復貴，一僧誰奈何。", "藥苗家自有，香飯乞時多。寄語嬋娟客，將心向薜蘿。"]'),
('yuding-20','送清江上人','法照','唐','御定全唐诗','yuding','','[]','越人僧體古，清慮洗塵勞。一國詩名遠，多生律行高。',48,'御定全唐詩/json/810.json','["越人僧體古，清慮洗塵勞。一國詩名遠，多生律行高。", "見山援葛藟，避世著方袍。早晚雲門去，儂應逐爾曹。"]'),
('yuding-21','送無著禪師歸新羅','法照','唐','御定全唐诗','yuding','','[]','萬里歸鄉路，隨緣不算程。尋山百衲弊，過海一杯輕。',48,'御定全唐詩/json/810.json','["萬里歸鄉路，隨緣不算程。尋山百衲弊，過海一杯輕。", "夜宿依雲色，晨齋就水聲。何年持貝葉，卻到漢家城。"]'),
('yuding-22','遊元象泊','釋泚','唐','御定全唐诗','yuding','','[]','空水潮色淨，澹然湖上心。舳艫輕且進，汀洲如可尋。',48,'御定全唐詩/json/810.json','["空水潮色淨，澹然湖上心。舳艫輕且進，汀洲如可尋。", "秋風洄溯險，落日波濤深。寂寞武陵去，中流方至今。"]'),
('yuding-23','北原別業','釋泚','唐','御定全唐诗','yuding','','[]','野外車騎絕，古村桑柘陰。流鶯出穀靜，春草閉門深。',48,'御定全唐詩/json/810.json','["野外車騎絕，古村桑柘陰。流鶯出穀靜，春草閉門深。", "學稼農為業，忘情道作心。因知上皇日，鑿井在靈林。"]'),
('yuding-24','雜詩','龐蘊','唐','御定全唐诗','yuding','','[]','未識龍宮莫說珠，識珠言說與君殊。',240,'御定全唐詩/json/810.json','["未識龍宮莫說珠，識珠言說與君殊。", "空拳只是嬰兒信，豈得將來誑老夫。", "萬法從心起，心生萬法生。法生同日了，來去在虛行。", "寄語修道人，空生慎勿生。如能達此理，不動出深坑。", "極目觀前境，寂寞無一人。回頭看後底，影亦不隨身。", "神識苟能無掛礙，廓周法界等虛空。", "不假坐禪持戒律，超然解脫豈勞功。", "日用事無別，惟吾自偶偕。頭頭非取捨，處處勿張乖。", "朱紫誰為號，青山絕點埃。神通並妙用，運水及搬柴。", "十方同聚會，個個學無為。此是選佛場，心空及第歸。", "焰水無魚下底鉤，覓魚無處笑君愁。", "可憐谷隱老禪伯，被唾如何見亦羞。"]'),
('yuding-0','歸山作','護國','唐','御定全唐诗','yuding','','[]','喧靜各有路，偶隨心所安。縱然在朝市，終不忘林巒。',96,'御定全唐詩/json/811.json','["喧靜各有路，偶隨心所安。縱然在朝市，終不忘林巒。", "四皓將拂衣，二疏能掛冠。窗前隱逸傳，每日三時看。", "靳尚那可論，屈原亦可歎。至今黃泉下，名及青雲端。", "松牖見初月，花間禮古壇。何處論心懷，世上空漫漫。"]'),
('yuding-1','題醴陵玉仙觀歌','護國','唐','御定全唐诗','yuding','','[]','王喬一去空仙觀，白雲至今凝不散。星垣松殿幾千秋，',48,'御定全唐詩/json/811.json','["王喬一去空仙觀，白雲至今凝不散。星垣松殿幾千秋，", "路逢一人擎藥碗，松花夜雨風吹滿。自言家住在東坡，"]'),
('yuding-2','訪雲母山僧','護國','唐','御定全唐诗','yuding','','[]','森然古岩裏，淨行一番僧。松下濾寒水，佛前挑夜燈。',48,'御定全唐詩/json/811.json','["森然古岩裏，淨行一番僧。松下濾寒水，佛前挑夜燈。", "蓮花國土異，貝葉梵書能。想到空王境，無心問愛憎。"]'),
('yuding-3','題王班水亭','護國','唐','御定全唐诗','yuding','','[]','湖上見秋色，曠然如爾懷。豈惟歡隴畝，兼亦外形骸。',48,'御定全唐詩/json/811.json','["湖上見秋色，曠然如爾懷。豈惟歡隴畝，兼亦外形骸。", "待月歸山寺，彈琴坐暝齋。布衣閑自貴，何用謁天階。"]'),
('yuding-4','山中寄王員外','護國','唐','御定全唐诗','yuding','','[]','為問幽蘭桂，空山複若何。芬芳終有分，采折更誰過。',48,'御定全唐詩/json/811.json','["為問幽蘭桂，空山複若何。芬芳終有分，采折更誰過。", "望在軒階近，恩沾雨露多。移居儻得地，長願接瓊柯。"]'),
('yuding-5','許州鄭使君孩子','護國','唐','御定全唐诗','yuding','','[]','毛骨貴天生，肌膚片玉明。見人空解笑，弄物不知名。',48,'御定全唐詩/json/811.json','["毛骨貴天生，肌膚片玉明。見人空解笑，弄物不知名。", "國器嗟猶小，門風望益清。抱來芳樹下，時引鳳雛聲。"]'),
('yuding-6','愴故人舊居','護國','唐','御定全唐诗','yuding','','[]','惆悵至日暮，寒鴉啼樹林。破階苔色厚，殘壁雨痕深。',48,'御定全唐詩/json/811.json','["惆悵至日暮，寒鴉啼樹林。破階苔色厚，殘壁雨痕深。", "命與時不遇，福為禍所侵。空餘行徑在，令我歎人吟。"]'),
('yuding-7','逢靈道士','護國','唐','御定全唐诗','yuding','','[]','浮丘山上見黃冠，松柏森森登古壇。一莖青竹以為杖，',40,'御定全唐詩/json/811.json','["浮丘山上見黃冠，松柏森森登古壇。一莖青竹以為杖，", "縮地往來無定所，花源到處路漫漫。"]'),
('yuding-8','別盛安','護國','唐','御定全唐诗','yuding','','[]','情人取次幾淹留，別後南州與北州。月色為憐今夜客，',40,'御定全唐詩/json/811.json','["情人取次幾淹留，別後南州與北州。月色為憐今夜客，", "親故相逢且借問，古來無種是王侯。"]'),
('yuding-9','傷蔡處士','護國','唐','御定全唐诗','yuding','','[]','篋中遺草是琅玕，對此空令灑淚看。三徑尚餘行跡在，',40,'御定全唐詩/json/811.json','["篋中遺草是琅玕，對此空令灑淚看。三徑尚餘行跡在，", "欲問皇天天更遠，有才無命說應難。"]'),
('yuding-10','臨川道中','護國','唐','御定全唐诗','yuding','','[]','出谷入谷路回轉，秋風已至歸期晚。',32,'御定全唐詩/json/811.json','["出谷入谷路回轉，秋風已至歸期晚。", "舉頭何處望來蹤，萬仞千山鳥飛遠。"]'),
('yuding-11','贈張駙馬斑竹柱杖','護國','唐','御定全唐诗','yuding','','[]','此君與我在雲溪，勁節奇文勝杖藜。',32,'御定全唐詩/json/811.json','["此君與我在雲溪，勁節奇文勝杖藜。", "為有歲寒堪贈遠，玉階行處願提攜。"]'),
('yuding-12','病癒寄友','法振','唐','御定全唐诗','yuding','','[]','哀樂暗成疾，臥中芳月移。西山有清士，孤嘯不可追。',48,'御定全唐詩/json/811.json','["哀樂暗成疾，臥中芳月移。西山有清士，孤嘯不可追。", "搗藥晝林靜，汲泉陰澗遲。微蹤與麋鹿，遠謝求羊知。"]'),
('yuding-13','程評事西園之作','法振','唐','御定全唐诗','yuding','','[]','誰向春鶯道，名園已共知。簷前回水影，城上出花枝。',48,'御定全唐詩/json/811.json','["誰向春鶯道，名園已共知。簷前回水影，城上出花枝。", "搖拂煙雲動，登臨翰墨隨。相招能不厭，山舍為君移。"]'),
('yuding-14','陳九溪中草堂','法振','唐','御定全唐诗','yuding','','[]','溪草落濺濺，魚飛入稻田。早寒臨洞月，輕素捲簾煙。',49,'御定全唐詩/json/811.json','["溪草落濺濺，魚飛入稻田。早寒臨洞月，輕素捲簾煙。", "dU幘題新句，蓑衣象古賢。曙花閑秀色，三十六峰前。"]'),
('yuding-15','題天長阮少府湖上客歸','法振','唐','御定全唐诗','yuding','','[]','孤棹移官舍，新農寄楚田。晴林渡海日，春草長湖煙。',48,'御定全唐詩/json/811.json','["孤棹移官舍，新農寄楚田。晴林渡海日，春草長湖煙。", "臥對閑鷗戲，談經稚子賢。佳期更何許，應向嘯台前。"]'),
('yuding-16','題萬山許煉師','法振','唐','御定全唐诗','yuding','','[]','道成人不識，流水響空山。花暗軒窗外，雲隨坐臥間。',48,'御定全唐詩/json/811.json','["道成人不識，流水響空山。花暗軒窗外，雲隨坐臥間。", "驗圖名已久，絕粒事長閑。更欲昆侖去，羞看絳節還。"]'),
('yuding-17','河源破賊後贈袁將軍','法振','唐','御定全唐诗','yuding','','[]','白羽三千駐，蕭蕭萬里行。出關深漢壘，帶月破蕃營。',48,'御定全唐詩/json/811.json','["白羽三千駐，蕭蕭萬里行。出關深漢壘，帶月破蕃營。", "蔓草河原色，悲笳碎葉聲。欲朝王母殿，前路駐高旌。"]'),
('yuding-18','越中贈程先生','法振','唐','御定全唐诗','yuding','','[]','紗帽度殘春，虛舟寄一身。溪邊逢越女，花裏問秦人。',48,'御定全唐詩/json/811.json','["紗帽度殘春，虛舟寄一身。溪邊逢越女，花裏問秦人。", "古塞連山靜，陰霞落海新。有時城郭去，暗與酒家親。"]'),
('yuding-19','送常大夫赴朔方','法振','唐','御定全唐诗','yuding','','[]','關山今不掩，軍候鳥先知。大漢嫖姚入，烏孫部曲隨。',48,'御定全唐詩/json/811.json','["關山今不掩，軍候鳥先知。大漢嫖姚入，烏孫部曲隨。", "高旌天外駐，寒角月中吹。歸到長安第，花應再滿枝。"]'),
('yuding-20','送人遊閩越','法振','唐','御定全唐诗','yuding','','[]','不須行借問，為爾話閩中。海島陰晴日，江帆來去風。',48,'御定全唐詩/json/811.json','["不須行借問，為爾話閩中。海島陰晴日，江帆來去風。", "道游玄度宅，身寄朗陵公。此別何傷遠，如今關塞通。"]'),
('yuding-21','送褚先生海上尋封煉師','法振','唐','御定全唐诗','yuding','','[]','潮落風初定，天吳避客舟。近承三殿旨，欲向五湖遊。',72,'御定全唐詩/json/811.json','["潮落風初定，天吳避客舟。近承三殿旨，欲向五湖遊。", "不厭烏皮幾，新縫鶴氅裘。明珠漂斷岸，陰火映中流。", "華蓋芝童引，神丹桂女收。懸知居縹緲，因為識浮丘。"]'),
('yuding-22','送韓侍禦自使幕巡海北','法振','唐','御定全唐诗','yuding','','[]','微雨空山夜洗兵，繡衣朝拂海雲清。幕中運策心應苦，',40,'御定全唐詩/json/811.json','["微雨空山夜洗兵，繡衣朝拂海雲清。幕中運策心應苦，", "因說元戎能破敵，高歌一曲隴關情。"]'),
('yuding-23','張舍人南溪別業','法振','唐','御定全唐诗','yuding','','[]','新田繞屋半春耕，藜杖閑門引客行。山翠自成微雨色，',40,'御定全唐詩/json/811.json','["新田繞屋半春耕，藜杖閑門引客行。山翠自成微雨色，", "入夜更宜明月滿，雙童喚出解吹笙。"]'),
('yuding-24','別盧使君歸故柵村','法振','唐','御定全唐诗','yuding','','[]','歸風白馬引嘶聲，落日猶看楚客情。塞口竹緣空戍沒，',40,'御定全唐詩/json/811.json','["歸風白馬引嘶聲，落日猶看楚客情。塞口竹緣空戍沒，", "東道宿程投故柵，依依漁父解相迎。"]'),
('yuding-25','丹陽浦送客之海上','法振','唐','御定全唐诗','yuding','','[]','不到終南向幾秋，移居更欲近滄洲。風吹雨色連村暗，',40,'御定全唐詩/json/811.json','["不到終南向幾秋，移居更欲近滄洲。風吹雨色連村暗，", "如君豈得空高枕，只益天書遣遠求。"]'),
('yuding-26','月夜泛舟','法振','唐','御定全唐诗','yuding','','[]','西塞長雲盡，南湖片月斜。漾舟人不見，臥入武陵花。',24,'御定全唐詩/json/811.json','["西塞長雲盡，南湖片月斜。漾舟人不見，臥入武陵花。"]'),
('yuding-27','送友人之上都','法振','唐','御定全唐诗','yuding','','[]','玉帛征賢楚客稀，猿啼相送武陵歸。',32,'御定全唐詩/json/811.json','["玉帛征賢楚客稀，猿啼相送武陵歸。", "湖頭望入桃花去，一片春帆帶雨飛。"]'),
('yuding-28','句','法振','唐','御定全唐诗','yuding','','[]','畫鼓催來錦臂襄，小娥雙起整霓裳。（《柘枝》，',22,'御定全唐詩/json/811.json','["畫鼓催來錦臂襄，小娥雙起整霓裳。（《柘枝》，"]'),
('yuding-0','早發陝州途中贈嚴秘書','清江','唐','御定全唐诗','yuding','','[]','此身雖不系，憂道亦勞生。萬里江湖夢，千山雨雪行。',72,'御定全唐詩/json/812.json','["此身雖不系，憂道亦勞生。萬里江湖夢，千山雨雪行。", "人家依舊壘，關路閉層城。未盡交河虜，猶屯細柳兵。", "艱難嗟遠客，棲托賴深情。貧病吾將有，精修許少卿。"]'),
('yuding-1','早春書情寄河南崔少府','清江','唐','御定全唐诗','yuding','','[]','春日春風至，陽和似不均。病身空益老，愁鬢不知春。',72,'御定全唐詩/json/812.json','["春日春風至，陽和似不均。病身空益老，愁鬢不知春。", "宇宙成遺物，光陰促幻身。客游傷末路，心事向行人。", "道薄猶懷土，時難欲厭貧。微才如可寄，赤縣有鄉親。"]'),
('yuding-2','春遊司直城西鸕鷀溪別業','清江','唐','御定全唐诗','yuding','','[]','別墅軍城下，閑喧未可齊。春深花蝶夢，曉隔柳煙鞞。',120,'御定全唐詩/json/812.json','["別墅軍城下，閑喧未可齊。春深花蝶夢，曉隔柳煙鞞。", "韶景浮寒水，疏楊映綠堤。沿洄看竹色，來往聽鶯啼。", "久慢持生術，多親種藥畦。家貧知素行，心苦見清溪。", "越客初投分，南枝得寄棲。禪機空寂寞，雅趣賴招攜。", "本寺重江外，游方二室西。裴回戀知己，日夕草萋萋。"]'),
('yuding-3','夕次襄邑','清江','唐','御定全唐诗','yuding','','[]','何處戒吾道，經年遠路中。客心猶向北，河水自歸東。',48,'御定全唐詩/json/812.json','["何處戒吾道，經年遠路中。客心猶向北，河水自歸東。", "古戍鳴寒角，疏林振夕風。輕舟惟載月，那與故人同。"]'),
('yuding-4','宿嚴維宅簡章八元','清江','唐','御定全唐诗','yuding','','[]','佳期曾不遠，甲第即南鄰。惠愛偏相及，經過豈厭頻。',48,'御定全唐詩/json/812.json','["佳期曾不遠，甲第即南鄰。惠愛偏相及，經過豈厭頻。", "秋寒林葉動，夕霽月華新。莫話羈棲事，平原是主人。"]'),
('yuding-5','贈淮西賈兵馬使','清江','唐','御定全唐诗','yuding','','[]','破虜功成百戰場，天書新拜漢中郎。映門旌旆春風起，',40,'御定全唐詩/json/812.json','["破虜功成百戰場，天書新拜漢中郎。映門旌旆春風起，", "由來吳楚多同調，感激逢君共異鄉。"]'),
('yuding-6','送堅上人歸杭州天竺寺','清江','唐','御定全唐诗','yuding','','[]','十年勞負笈，經論化中朝。流水知鄉近，和風惜別遙。',48,'御定全唐詩/json/812.json','["十年勞負笈，經論化中朝。流水知鄉近，和風惜別遙。", "雲山零夜雨，花岸上春潮。歸臥南天竺，禪心更寂寥。"]'),
('yuding-7','送贊律師歸嵩山','清江','唐','御定全唐诗','yuding','','[]','禪意歸心急，山深定易安。清貧修道苦，孝友別家難。',48,'御定全唐詩/json/812.json','["禪意歸心急，山深定易安。清貧修道苦，孝友別家難。", "雪路侵溪轉，花宮映嶽看。到時瞻塔暮，松月向人寒。"]'),
('yuding-8','上都酬章十八兄','清江','唐','御定全唐诗','yuding','','[]','每歎經年別，人生有幾年。關河長問道，風雨獨隨緣。',48,'御定全唐詩/json/812.json','["每歎經年別，人生有幾年。關河長問道，風雨獨隨緣。", "寓蝶成莊夢，懷人識禰賢。徽猷不及此，空愧白華篇。"]'),
('yuding-9','登樓望月寄鳳翔李少尹','清江','唐','御定全唐诗','yuding','','[]','陌上涼風槐葉凋，夕陽秋露濕寒條。登樓望月楚山上，',40,'御定全唐詩/json/812.json','["陌上涼風槐葉凋，夕陽秋露濕寒條。登樓望月楚山上，", "軒車不重無名客，此地誰能訪寂寥。"]'),
('yuding-10','湘川懷古','清江','唐','御定全唐诗','yuding','','[]','瀟湘連汨羅，複對九嶷河。浪勢屈原塚，竹聲漁父歌。',48,'御定全唐詩/json/812.json','["瀟湘連汨羅，複對九嶷河。浪勢屈原塚，竹聲漁父歌。", "地荒征騎少，天暖浴禽多。脈脈東流水，古今同奈何。"]'),
('yuding-11','七夕','清江','唐','御定全唐诗','yuding','','[]','七夕景迢迢，相逢只一宵。月為開帳燭，雲作渡河橋。',48,'御定全唐詩/json/812.json','["七夕景迢迢，相逢只一宵。月為開帳燭，雲作渡河橋。", "映水金冠動，當風玉佩搖。惟愁更漏促，離別在明朝。"]'),
('yuding-12','長安臥病','清江','唐','御定全唐诗','yuding','','[]','身世足堪悲，空房臥病時。捲簾花雨滴，掃石竹陰移。',48,'御定全唐詩/json/812.json','["身世足堪悲，空房臥病時。捲簾花雨滴，掃石竹陰移。", "已覺生如夢，堪嗟壽不知。未能通法性，詎可免支離。"]'),
('yuding-13','送婆羅門','清江','唐','御定全唐诗','yuding','','[]','雪嶺金河獨向東，吳山楚澤意無窮。',32,'御定全唐詩/json/812.json','["雪嶺金河獨向東，吳山楚澤意無窮。", "如今白首鄉心盡，萬里歸程在夢中。"]'),
('yuding-14','喜皇甫大夫同宿大樑驛','清江','唐','御定全唐诗','yuding','','[]','江頭旌旆去，花外捲簾空。夜色臨城月，春聲渡水風。',48,'御定全唐詩/json/812.json','["江頭旌旆去，花外捲簾空。夜色臨城月，春聲渡水風。", "也知行李別，暫喜話言同。若問廬山事，終身愧遠公。"]'),
('yuding-15','酬姚補闕南仲雲溪館中戲題隨書見寄','清江','唐','御定全唐诗','yuding','','[]','寺溪臨使府，風景借仁祠。補袞周官貴，能名漢主慈。',48,'御定全唐詩/json/812.json','["寺溪臨使府，風景借仁祠。補袞周官貴，能名漢主慈。", "臥雲知獨處，望月憶同時。忽枉緘中贈，瓊瑤滿手持。"]'),
('yuding-16','喜嚴侍禦蜀還贈嚴秘書','清江','唐','御定全唐诗','yuding','','[]','往年分首出咸秦，木落花開秋又春。江客不曾知蜀路，',40,'御定全唐詩/json/812.json','["往年分首出咸秦，木落花開秋又春。江客不曾知蜀路，", "多羨二龍同漢代，繡衣芸閣共榮親。"]'),
('yuding-17','送韋參軍江陵','清江','唐','御定全唐诗','yuding','','[]','槐花落盡柳陰清，蕭索涼天楚客情。海上舊山無的信，',40,'御定全唐詩/json/812.json','["槐花落盡柳陰清，蕭索涼天楚客情。海上舊山無的信，", "公子道存知不棄，欲依劉表住南荊。"]'),
('yuding-18','月夜有懷黃端公兼簡朱孫二判官','清江','唐','御定全唐诗','yuding','','[]','月照疏林驚鵲飛，羈人此夜共無依。青門旅寓身空老，',48,'御定全唐詩/json/812.json','["月照疏林驚鵲飛，羈人此夜共無依。青門旅寓身空老，", "四科弟子稱文學，五馬諸侯是繡衣。江雁往來曾不定，"]'),
('yuding-19','精舍遇雨','清江','唐','御定全唐诗','yuding','','[]','空門寂寂淡吾身，溪雨微微洗客塵。',32,'御定全唐詩/json/812.json','["空門寂寂淡吾身，溪雨微微洗客塵。", "臥向白雲情未盡，任他黃鳥醉芳春。"]'),
('yuding-20','小雪','清江','唐','御定全唐诗','yuding','','[]','落雪臨風不厭看，更多還恐蔽林巒。',32,'御定全唐詩/json/812.json','["落雪臨風不厭看，更多還恐蔽林巒。", "愁人正在書窗下，一片飛來一片寒。"]'),
('yuding-21','句','清江','唐','御定全唐诗','yuding','','[]','萬木無一葉，客心悲此時。',12,'御定全唐詩/json/812.json','["萬木無一葉，客心悲此時。"]'),
('yuding-0','送呂郎中赴滄州','無可','唐','御定全唐诗','yuding','','[]','出守滄州去，西風送旆旌。路遙經幾郡，地盡到孤城。',48,'御定全唐詩/json/813.json','["出守滄州去，西風送旆旌。路遙經幾郡，地盡到孤城。", "拜廟千山綠，登樓遍海清。何人共東望，日向積濤生。"]'),
('yuding-1','書馬如文石門居','無可','唐','御定全唐诗','yuding','','[]','別業逸高情，暮泉喧客亭。林回天闕近，雨過石門青。',48,'御定全唐詩/json/813.json','["別業逸高情，暮泉喧客亭。林回天闕近，雨過石門青。", "野果誰來拾，山禽獨臥聽。要迎文會友，時複掃柴扃。"]'),
('yuding-2','送章正字秩滿東歸','無可','唐','御定全唐诗','yuding','','[]','朝衣登別席，春色滿秦關。芸閣吏誰替，海門身又還。',48,'御定全唐詩/json/813.json','["朝衣登別席，春色滿秦關。芸閣吏誰替，海門身又還。", "尋僧流水僻，見月遠林閑。雖是忘機者，難齊去住間。"]'),
('yuding-3','賦得望遠山送客歸','無可','唐','御定全唐诗','yuding','','[]','遙山寒雨過，正向暮天橫。隱隱淩雲出，蒼蒼與水準。',48,'御定全唐詩/json/813.json','["遙山寒雨過，正向暮天橫。隱隱淩雲出，蒼蒼與水準。", "何時凝厚地，幾處映孤城。歸客秋風裏，回看傷別情。"]'),
('yuding-4','送宜春裴宰是將軍旻之孫','無可','唐','御定全唐诗','yuding','','[]','垂白方為縣，徒知大父雄。山春南去棹，楚夜北飛鴻。',48,'御定全唐詩/json/813.json','["垂白方為縣，徒知大父雄。山春南去棹，楚夜北飛鴻。", "疊嶂和雲滅，孤城與嶺通。誰知持惠化，一境動清風。"]'),
('yuding-5','送樸山人歸日本','無可','唐','御定全唐诗','yuding','','[]','海霽晚帆開，應無鄉信催。水從荒外積，人指日邊回。',48,'御定全唐詩/json/813.json','["海霽晚帆開，應無鄉信催。水從荒外積，人指日邊回。", "望國乘風久，浮天絕島來。儻因華夏使，書劄轉悠哉。"]'),
('yuding-6','送姚宰任吉州安福縣','無可','唐','御定全唐诗','yuding','','[]','落絮滿衣裳，攜琴問酒鄉。掛帆南入楚，到縣半浮湘。',48,'御定全唐詩/json/813.json','["落絮滿衣裳，攜琴問酒鄉。掛帆南入楚，到縣半浮湘。", "吏散翠禽下，庭閑斑竹長。人安宜遠泛，沙上蕙蘭香。"]'),
('yuding-7','送李少府之任臨邛','無可','唐','御定全唐诗','yuding','','[]','邛南方作尉，調補一何卑。發論唯公幹，承家乃帝枝。',48,'御定全唐詩/json/813.json','["邛南方作尉，調補一何卑。發論唯公幹，承家乃帝枝。", "山長風嫋棧，江蔭石和澌。舊井王孫宅，還尋獨有期。"]'),
('yuding-8','遊山寺','無可','唐','御定全唐诗','yuding','','[]','千峰路盤盡，林寺昔何名。步步入山影，房房聞水聲。',48,'御定全唐詩/json/813.json','["千峰路盤盡，林寺昔何名。步步入山影，房房聞水聲。", "多年人跡斷，殘照石陰清。自可求居止，安閒過此生。"]'),
('yuding-9','酬姚員外見過林下','無可','唐','御定全唐诗','yuding','','[]','掃苔迎五馬，蒔藥過申鐘。鶴共林僧見，雲隨野客逢。',48,'御定全唐詩/json/813.json','["掃苔迎五馬，蒔藥過申鐘。鶴共林僧見，雲隨野客逢。", "入樓山隔水，滴旆露垂松。日暮題詩去，空知雅調重。"]'),
('yuding-10','寄華州馬戴','無可','唐','御定全唐诗','yuding','','[]','三峰待秋上，鳥外掛衣巾。猶見無窮景，應非暫往身。',48,'御定全唐詩/json/813.json','["三峰待秋上，鳥外掛衣巾。猶見無窮景，應非暫往身。", "水寒仙掌路，山遠華陽人。欲問壇邊月，尋思闕複新。"]'),
('yuding-11','秋夜寄青龍寺空貞二上人','無可','唐','御定全唐诗','yuding','','[]','夜來思道侶，木葉向人飄。精舍池邊古，秋山樹下遙。',48,'御定全唐詩/json/813.json','["夜來思道侶，木葉向人飄。精舍池邊古，秋山樹下遙。", "磬寒徹幾裏，雲白已經宵。未得同居止，蕭然自寂寥。"]'),
('yuding-12','過杏溪寺寄姚員外','無可','唐','御定全唐诗','yuding','','[]','門徑眾峰頭，盤岩複轉溝。雲僧隨樹老，杏水落江流。',48,'御定全唐詩/json/813.json','["門徑眾峰頭，盤岩複轉溝。雲僧隨樹老，杏水落江流。", "峽狖有時到，秦人今日遊。謝公多晚眺，此景在南樓。"]'),
('yuding-13','送僧歸中條','無可','唐','御定全唐诗','yuding','','[]','夜葉動飄飄，寒來話數宵。卷經歸鳥外，轉雪過山椒。',48,'御定全唐詩/json/813.json','["夜葉動飄飄，寒來話數宵。卷經歸鳥外，轉雪過山椒。", "舊長松杉大，難行水石遙。元戎宗內學，應就白雲招。"]'),
('yuding-14','送人罷舉東遊','無可','唐','御定全唐诗','yuding','','[]','東堂今已負，況此遠行難。兼雨風聲過，連天草色幹。',48,'御定全唐詩/json/813.json','["東堂今已負，況此遠行難。兼雨風聲過，連天草色幹。", "鴻嘶荒壘閉，兵燒廣川寒。若向龍門宿，懸知拭淚看。"]'),
('yuding-15','金州冬月陪太守游池','無可','唐','御定全唐诗','yuding','','[]','殘臘雪紛紛，林間起送君。苦吟行迥野，投跡向寒雲。',48,'御定全唐詩/json/813.json','["殘臘雪紛紛，林間起送君。苦吟行迥野，投跡向寒雲。", "絕頂晴多去，幽泉凍不聞。唯應草堂寺，高枕脫人群。"]'),
('yuding-16','寄青龍寺原上人','無可','唐','御定全唐诗','yuding','','[]','斂屨入寒竹，安禪過漏聲。高杉殘子落，深井凍痕生。',48,'御定全唐詩/json/813.json','["斂屨入寒竹，安禪過漏聲。高杉殘子落，深井凍痕生。", "罷磬風枝動，懸燈雪屋明。何當招我宿，乘月上方行。"]'),
('yuding-17','秋寄從兄賈島','無可','唐','御定全唐诗','yuding','','[]','暝蟲喧暮色，默思坐西林。聽雨寒更徹，開門落葉深。',48,'御定全唐詩/json/813.json','["暝蟲喧暮色，默思坐西林。聽雨寒更徹，開門落葉深。", "昔因京邑病，並起洞庭心。亦是吾兄事，遲回共至今。"]'),
('yuding-18','新年','無可','唐','御定全唐诗','yuding','','[]','燃燈朝複夕，漸作長年身。紫閣未歸日，青門又見春。',48,'御定全唐詩/json/813.json','["燃燈朝複夕，漸作長年身。紫閣未歸日，青門又見春。", "掩關寒過盡，開定草生新。自有林中趣，誰驚歲去頻。"]'),
('yuding-19','夏日送崔秀才游南','無可','唐','御定全唐诗','yuding','','[]','南方山水地，念子為貧遊。縱是逢佳景，那能緩旅愁。',48,'御定全唐詩/json/813.json','["南方山水地，念子為貧遊。縱是逢佳景，那能緩旅愁。", "夕陽行遠道，煩暑在孤舟。莫向巴江過，猿啼促淚流。"]'),
('yuding-20','晚秋酬姚合見寄','無可','唐','御定全唐诗','yuding','','[]','新命起高眠，江湖空浩然。木衰猶有菊，燕去即無蟬。',48,'御定全唐詩/json/813.json','["新命起高眠，江湖空浩然。木衰猶有菊，燕去即無蟬。", "分察千官內，孤懷遠岳邊。蕭條人外寺，暌阻又經年。"]'),
('yuding-21','暮秋宿友人居','無可','唐','御定全唐诗','yuding','','[]','招我郊居宿，開門但苦吟。秋眠山燒盡，暮歇竹園深。',48,'御定全唐詩/json/813.json','["招我郊居宿，開門但苦吟。秋眠山燒盡，暮歇竹園深。", "寒浦鴻相叫，風窗月欲沈。翻嫌坐禪石，不在此松陰。"]'),
('yuding-22','送李騎曹之武寧','無可','唐','御定全唐诗','yuding','','[]','一歲一歸寧，涼天數騎行。河來當塞曲，山遠與沙平。',48,'御定全唐詩/json/813.json','["一歲一歸寧，涼天數騎行。河來當塞曲，山遠與沙平。", "縱獵旗風卷，聽笳帳月生。新鴻引寒色，回日滿京城。"]'),
('yuding-23','秋日寄厲玄先輩','無可','唐','御定全唐诗','yuding','','[]','楊柳起秋色，故人猶未還。別離俱自苦，少壯豈能閑。',48,'御定全唐詩/json/813.json','["楊柳起秋色，故人猶未還。別離俱自苦，少壯豈能閑。", "夜雨吟殘燭，秋城憶遠山。何當一相見，語默此林間。"]'),
('yuding-24','冬晚與諸文士會太僕田卿宅','無可','唐','御定全唐诗','yuding','','[]','從容啟華館，饌玉複燒蘭。是歲茲旬盡，良宵幾刻殘。',48,'御定全唐詩/json/813.json','["從容啟華館，饌玉複燒蘭。是歲茲旬盡，良宵幾刻殘。", "風回松竹動，人息鬥牛寒。此後思良集，須期月再圓。"]'),
('yuding-25','贈詩僧','無可','唐','御定全唐诗','yuding','','[]','寒山對水塘，竹葉影侵堂。洗藥冰生岸，開門月滿床。',48,'御定全唐詩/json/813.json','["寒山對水塘，竹葉影侵堂。洗藥冰生岸，開門月滿床。", "病多身又老，枕倦夜兼長。來謁吾曹者，呈詩問否臧。"]'),
('yuding-26','寒夜過睿川師院','無可','唐','御定全唐诗','yuding','','[]','長生推獻壽，法坐四朝登。問難無強敵，聲名掩古僧。',48,'御定全唐詩/json/813.json','["長生推獻壽，法坐四朝登。問難無強敵，聲名掩古僧。", "絕塵苔積地，棲竹鳥驚燈。語默俱忘寐，殘窗半月棱。"]'),
('yuding-27','送顥法師往太原講兼呈李司徒','無可','唐','御定全唐诗','yuding','','[]','近臘辭精舍，並州謁尚公。路長山忽盡，塞廣雪無窮。',48,'御定全唐詩/json/813.json','["近臘辭精舍，並州謁尚公。路長山忽盡，塞廣雪無窮。", "講席開晴壘，禪衣涉遠風。聞經諸弟子，應滿此門中。"]'),
('yuding-28','冬日諸禪自商山禮正師真塔回見訪','無可','唐','御定全唐诗','yuding','','[]','久思今忽來，雙屨汙青苔。拂雪從山起，過房禮塔回。',48,'御定全唐詩/json/813.json','["久思今忽來，雙屨汙青苔。拂雪從山起，過房禮塔回。", "偈留閑夜作，禪請暫時開。欲作孤雲去，賦詩餘不才。"]'),
('yuding-29','題青龍寺縱公房','無可','唐','御定全唐诗','yuding','','[]','從誰得法印，不離上方傳。夕磬城霜下，寒房竹月圓。',48,'御定全唐詩/json/813.json','["從誰得法印，不離上方傳。夕磬城霜下，寒房竹月圓。", "煙殘衰木畔，客住積雲邊。未隱滄洲去，時來於此禪。"]'),
('yuding-30','贈圭峰禪師','無可','唐','御定全唐诗','yuding','','[]','絕壑禪床底，泉分落石層。霧交高頂草，雲隱下方燈。',48,'御定全唐詩/json/813.json','["絕壑禪床底，泉分落石層。霧交高頂草，雲隱下方燈。", "朝滿傾心客，溪連學道僧。半旬持一食，此事有誰能。"]'),
('yuding-31','陪姚合游金州南池','無可','唐','御定全唐诗','yuding','','[]','柳暗清波漲，沖萍複漱苔。張筵白鳥起，掃岸使君來。',48,'御定全唐詩/json/813.json','["柳暗清波漲，沖萍複漱苔。張筵白鳥起，掃岸使君來。", "洲島秋應沒，荷花晚盡開。高城吹角絕，騶馭尚裴回。"]'),
('yuding-32','金州別姚合','無可','唐','御定全唐诗','yuding','','[]','日日西亭上，春留到夏殘。言之離別易，勉以道途難。',48,'御定全唐詩/json/813.json','["日日西亭上，春留到夏殘。言之離別易，勉以道途難。", "山出一千里，溪行三百灘。松間樓裏月，秋入五陵看。"]'),
('yuding-33','夏日送田中丞赴蔡州','無可','唐','御定全唐诗','yuding','','[]','出守汝南城，應多戀闕情。地遙人久望，風起旆初行。',48,'御定全唐詩/json/813.json','["出守汝南城，應多戀闕情。地遙人久望，風起旆初行。", "楚廟繁蟬斷，淮田細雨生。賞心知有處，蔣宅古津平。"]'),
('yuding-34','菊','無可','唐','御定全唐诗','yuding','','[]','東籬搖落後，密豔被寒催。夾雨驚新拆，經霜忽盡開。',48,'御定全唐詩/json/813.json','["東籬搖落後，密豔被寒催。夾雨驚新拆，經霜忽盡開。", "野香盈客袖，禁蕊泛天杯。不共春蘭並，悠揚遠蝶來。"]'),
('yuding-35','松','無可','唐','御定全唐诗','yuding','','[]','枝幹怪鱗皴，煙梢出澗新。屈盤高極目，蒼翠遠驚人。',48,'御定全唐詩/json/813.json','["枝幹怪鱗皴，煙梢出澗新。屈盤高極目，蒼翠遠驚人。", "待鶴移陰過，聽風落子頻。青青寒木外，自與九霄鄰。"]'),
('yuding-36','蘭','無可','唐','御定全唐诗','yuding','','[]','蘭色結春光，氛氳掩眾芳。過門階露葉，尋澤徑連香。',48,'御定全唐詩/json/813.json','["蘭色結春光，氛氳掩眾芳。過門階露葉，尋澤徑連香。", "畹靜風吹亂，亭秋雨引長。靈均曾採擷，紉佩掛荷裳。"]'),
('yuding-37','隕葉','無可','唐','御定全唐诗','yuding','','[]','繞巷夾溪紅，蕭條逐北風。別林遺宿鳥，浮水載鳴蟲。',48,'御定全唐詩/json/813.json','["繞巷夾溪紅，蕭條逐北風。別林遺宿鳥，浮水載鳴蟲。", "石小埋初盡，枝長落未終。帶霜書麗什，閑讀白雲中。"]'),
('yuding-38','李常侍書堂','無可','唐','御定全唐诗','yuding','','[]','結構因墳籍，簷前竹未生。塗油窗日早，閱槧幌風輕。',48,'御定全唐詩/json/813.json','["結構因墳籍，簷前竹未生。塗油窗日早，閱槧幌風輕。", "息架蛩驚客，垂燈雨過城。已應窮古史，師律孰齊名。"]'),
('yuding-39','寄和蔡州田郎中','無可','唐','御定全唐诗','yuding','','[]','遺跡仍留蔡，幽人出漢朝。門深荒徑在，台迥數峰遙。',48,'御定全唐詩/json/813.json','["遺跡仍留蔡，幽人出漢朝。門深荒徑在，台迥數峰遙。", "岸石欹相倚，窗松偃未凋。尋思方一去，豈待使君招。"]'),
('yuding-40','經貞女祠','無可','唐','御定全唐诗','yuding','','[]','朝賽暮還祈，開唐複曆隋。精誠山雨至，歲月廟松衰。',48,'御定全唐詩/json/813.json','["朝賽暮還祈，開唐複曆隋。精誠山雨至，歲月廟松衰。", "窺穴龍潭黑，過門鳥道危。不同巫峽女，來往楚王祠。"]'),
('yuding-41','行漢水晚次神灘阻風','無可','唐','御定全唐诗','yuding','','[]','驚風山半起，舟子忽停橈。岸荻吹先亂，灘聲落更跳。',48,'御定全唐詩/json/813.json','["驚風山半起，舟子忽停橈。岸荻吹先亂，灘聲落更跳。", "聽松今欲暮，過島或明朝。若盡平生趣，東浮看石橋。"]'),
('yuding-42','送田中丞使西戎','無可','唐','御定全唐诗','yuding','','[]','朝元下赤墀，玉節使西夷。關隴風回首，河湟雪灑旗。',48,'御定全唐詩/json/813.json','["朝元下赤墀，玉節使西夷。關隴風回首，河湟雪灑旗。", "磧砂行幾月，戎帳到何時。應盡平生志，高全大國儀。"]'),
('yuding-43','送董正字歸覲毗陵','無可','唐','御定全唐诗','yuding','','[]','暫辭讎校去，未發見新鴻。路入江波上，人歸楚邑東。',48,'御定全唐詩/json/813.json','["暫辭讎校去，未發見新鴻。路入江波上，人歸楚邑東。", "山遙晴出樹，野極暮連空。何以念兄弟，應思潔膳同。"]'),
('yuding-44','送邵錫及第歸湖州','無可','唐','御定全唐诗','yuding','','[]','春關鳥罷啼，歸慶浙煙西。郡守招延重，鄉人慕仰齊。',48,'御定全唐詩/json/813.json','["春關鳥罷啼，歸慶浙煙西。郡守招延重，鄉人慕仰齊。", "橘青逃暑寺，茶長隔湖溪。乘暇知高眺，微應辨會稽。"]'),
('yuding-45','送薛重中丞充太原副使','無可','唐','御定全唐诗','yuding','','[]','中司出華省，副相晉陽行。書答偏州啟，籌參上將營。',48,'御定全唐詩/json/813.json','["中司出華省，副相晉陽行。書答偏州啟，籌參上將營。", "踏沙夜馬細，吹雨曉笳清。正報胡塵滅，桃花汾水生。"]'),
('yuding-46','送靈武李侍禦','無可','唐','御定全唐诗','yuding','','[]','靈州天一涯，幕客似還家。地得江南壤，程分磧裏砂。',48,'御定全唐詩/json/813.json','["靈州天一涯，幕客似還家。地得江南壤，程分磧裏砂。", "禁鹽調上味，麥穗結秋花。前席因籌畫，清吟塞日斜。"]'),
('yuding-47','冬夜姚侍禦宅送李廓少府','無可','唐','御定全唐诗','yuding','','[]','王事圭峰下，將還禁漏餘。偶歡新歲近，惜別後期疏。',48,'御定全唐詩/json/813.json','["王事圭峰下，將還禁漏餘。偶歡新歲近，惜別後期疏。", "雪罷見來吏，川昏聊整車。獨吟多暇日，應寄柏台書。"]'),
('yuding-48','送喻鳧及第歸陽羨','無可','唐','御定全唐诗','yuding','','[]','姓字載科名，無過子最榮。宗中初及第，江上覲難兄。',48,'御定全唐詩/json/813.json','["姓字載科名，無過子最榮。宗中初及第，江上覲難兄。", "月向波濤沒，茶連洞壑生。石橋高思在，且為看東坑。"]'),
('yuding-49','送沅江宋明府即開府璟之孫','無可','唐','御定全唐诗','yuding','','[]','初聞從事日，鄂渚動芳菲。一遂鈞衡薦，今為長吏歸。',48,'御定全唐詩/json/813.json','["初聞從事日，鄂渚動芳菲。一遂鈞衡薦，今為長吏歸。", "人臨沅水望，雁映楚山飛。唯有傳聲政，家風重發揮。"]'),
('yuding-50','送薛秀才游河中兼投任郎中留後','無可','唐','御定全唐诗','yuding','','[]','詩古賦縱橫，令人畏後生。駕言游禹跡，知己在蒲城。',48,'御定全唐詩/json/813.json','["詩古賦縱橫，令人畏後生。駕言游禹跡，知己在蒲城。", "日射雲煙散，風吹草木榮。孤吟臨寇境，莫問請長纓。"]'),
('yuding-51','寄姚諫議','無可','唐','御定全唐诗','yuding','','[]','鳴鞭靜路塵，籍籍諫垣臣。函疏辭專密，爐香立獨親。',48,'御定全唐詩/json/813.json','["鳴鞭靜路塵，籍籍諫垣臣。函疏辭專密，爐香立獨親。", "篋多臨水作，窗宿臥雲人。危坐開寒紙，燈前起草頻。"]'),
('yuding-52','大理正任二十和江淹擬古詩二十章寄示','無可','唐','御定全唐诗','yuding','','[]','不啻回青眼，應疑似碧雲。古風真往哲，雅道濫朝聞。',48,'御定全唐詩/json/813.json','["不啻回青眼，應疑似碧雲。古風真往哲，雅道濫朝聞。", "活獄威豪右，銷時賴典墳。如何經濟意，未克致吾君。"]'),
('yuding-53','寄殿院薛侍禦','無可','唐','御定全唐诗','yuding','','[]','名高意本閑，浮俗自難攀。佐蜀連錢出，朝天獬豸還。',48,'御定全唐詩/json/813.json','["名高意本閑，浮俗自難攀。佐蜀連錢出，朝天獬豸還。", "回翔曆清院，彈奏迥離班。休浣通玄旨，留僧晝掩關。"]'),
('yuding-54','禪林寺','無可','唐','御定全唐诗','yuding','','[]','臺山朝佛隴，勝地絕埃氛。冷色石橋月，素光華頂雲。',48,'御定全唐詩/json/813.json','["臺山朝佛隴，勝地絕埃氛。冷色石橋月，素光華頂雲。", "遠泉和雪溜，幽磬帶松聞。終斷游方念，爐香繼此焚。"]'),
('yuding-0','奉和裴舍人春日杜城舊事','無可','唐','御定全唐诗','yuding','','[]','早晚辭綸綍，觀農下杜西。草新池似鏡，麥暖土如泥。',48,'御定全唐詩/json/814.json','["早晚辭綸綍，觀農下杜西。草新池似鏡，麥暖土如泥。", "鵷鷺依川宿，驊騮向野嘶。春來詩更苦，松韻亦含淒。"]'),
('yuding-1','酬厲侍禦秋中思歸樹石所居見寄','無可','唐','御定全唐诗','yuding','','[]','三峰居接近，數裏躡雲行。深去通仙境，思歸厭宦名。',48,'御定全唐詩/json/814.json','["三峰居接近，數裏躡雲行。深去通仙境，思歸厭宦名。", "月從高掌出，泉向亂松鳴。坐石眠霞侶，秋來短褐成。"]'),
('yuding-2','奉和段著作山居呈諸同志三首次本韻','無可','唐','御定全唐诗','yuding','','[]','香花懷道侶，巾舄立雙童。解印鴛鴻內，抽毫水石中。',144,'御定全唐詩/json/814.json','["香花懷道侶，巾舄立雙童。解印鴛鴻內，抽毫水石中。", "履溫行燒地，衣赤動霞風。又似朝天去，諸僧不可同。", "官辭中秘府，疏放野麋齊。偃仰青霄近，登臨白日低。", "折腰窺乳竇，定足涉冰溪。染翰揮嵐翠，僧名幾處題。", "暫收丹陛跡，獨往亂山居。入雪知人遠，眠雲覺俗虛。", "足垂岩頂石，纓濯洞中渠。只見僧酬答，新歸絕壑書。"]'),
('yuding-3','春日送麗處士歸龍山','無可','唐','御定全唐诗','yuding','','[]','愛弟直霜台，家山羨獨回。出門時返顧，何日更西來。',48,'御定全唐詩/json/814.json','["愛弟直霜台，家山羨獨回。出門時返顧，何日更西來。", "柳亦臨關發，花應到越開。漁舟誰伴上，依舊恣沿洄。"]'),
('yuding-4','寄興善寺崔律師','無可','唐','御定全唐诗','yuding','','[]','沐浴前朝像，深秋白髮師。從來居此寺，未省有東池。',48,'御定全唐詩/json/814.json','["沐浴前朝像，深秋白髮師。從來居此寺，未省有東池。", "幽石叢圭片，孤鬆動雪枝。頃曾聽道話，別起遠山思。"]'),
('yuding-5','送清散遊太白山','無可','唐','御定全唐诗','yuding','','[]','卷經歸太白，躡蘚別蘿龕。若履浮雲上，須看積翠南。',48,'御定全唐詩/json/814.json','["卷經歸太白，躡蘚別蘿龕。若履浮雲上，須看積翠南。", "倚身松入漢，瞑目月離潭。此境堪長往，塵中事可諳。"]'),
('yuding-6','冬晚姚諫議宅會送元緒上人歸南山','無可','唐','御定全唐诗','yuding','','[]','禪客詩家見，凝寒忽告還。分題回諫筆，留偈在商關。',48,'御定全唐詩/json/814.json','["禪客詩家見，凝寒忽告還。分題回諫筆，留偈在商關。", "盤徑緣高雪，閒房在半山。自知麋鹿性，亦欲離人間。"]'),
('yuding-7','送契公自桂陽赴南海','無可','唐','御定全唐诗','yuding','','[]','南行登嶺首，與俗洗煩埃。磬罷孤舟發，禪移積瘴開。',48,'御定全唐詩/json/814.json','["南行登嶺首，與俗洗煩埃。磬罷孤舟發，禪移積瘴開。", "中餐湘鳥下，朝講海人來。莫便將經卷，炎方去不回。"]'),
('yuding-8','冬中與諸公會宿姚端公宅，懷永樂殷侍禦','無可','唐','御定全唐诗','yuding','','[]','柱史靜開筵，所思何地偏。故人為縣吏，五老遠峰前。',48,'御定全唐詩/json/814.json','["柱史靜開筵，所思何地偏。故人為縣吏，五老遠峰前。", "賓榻寒侵樹，公庭夜落泉。會當隨假務，一就白雲禪。"]'),
('yuding-9','同劉秀才宿見贈','無可','唐','御定全唐诗','yuding','','[]','浮雲流水心，只是愛山林。共恨多年別，相逢一夜吟。',48,'御定全唐詩/json/814.json','["浮雲流水心，只是愛山林。共恨多年別，相逢一夜吟。", "既能持苦節，勿謂少知音。憶就西池宿，月圓松竹深。"]'),
('yuding-10','官池上','無可','唐','御定全唐诗','yuding','','[]','迥疏城闕內，寒瀉出雲波。岸廣山魚到，汀閑海鷺過。',48,'御定全唐詩/json/814.json','["迥疏城闕內，寒瀉出雲波。岸廣山魚到，汀閑海鷺過。", "泛溝侵道急，流葉入宮多。移舸浮中沚，清宵徹曉河。"]'),
('yuding-11','中秋月','無可','唐','御定全唐诗','yuding','','[]','蟾宜天地靜，三五對階蓂。照耀超諸夜，光芒掩眾星。',48,'御定全唐詩/json/814.json','["蟾宜天地靜，三五對階蓂。照耀超諸夜，光芒掩眾星。", "影寒池更澈，露冷樹銷青。枉值中秋半，長乖宿洞庭。"]'),
('yuding-12','雪','無可','唐','御定全唐诗','yuding','','[]','松亞竹珊珊，心知萬井歡。山明迷舊徑，溪滿漲新瀾。',48,'御定全唐詩/json/814.json','["松亞竹珊珊，心知萬井歡。山明迷舊徑，溪滿漲新瀾。", "客醉瑤台曙，兵防玉塞寒。紅樓知有酒，誰肯學袁安。"]'),
('yuding-13','宿西嶽白石院','無可','唐','御定全唐诗','yuding','','[]','白石上嵌空，寒雲西複東。瀑流懸住處，雛鶴失禪中。',48,'御定全唐詩/json/814.json','["白石上嵌空，寒雲西複東。瀑流懸住處，雛鶴失禪中。", "岳壁松多古，壇基雪不通。未能親近去，擁褐愧相同。"]'),
('yuding-14','送僧','無可','唐','御定全唐诗','yuding','','[]','四海無拘系，行心興自濃。百年三事衲，萬里一枝筇。',48,'御定全唐詩/json/814.json','["四海無拘系，行心興自濃。百年三事衲，萬里一枝筇。", "夜減當晴影，春消過雪蹤。白雲深處去，知宿在何峰。"]'),
('yuding-15','送贊律師歸嵩山','無可','唐','御定全唐诗','yuding','','[]','禪意歸心急，山深定易安。清貧修道苦，孝友別家難。',48,'御定全唐詩/json/814.json','["禪意歸心急，山深定易安。清貧修道苦，孝友別家難。", "雪路尋溪轉，花宮映嶽看。到時孤塔暮，松月向人寒。"]'),
('yuding-16','春晚喜悟禪師自琉璃上方見過','無可','唐','御定全唐诗','yuding','','[]','琉璃師到城，談性外諸經。下嶺雪霜在，近人林木清。',48,'御定全唐詩/json/814.json','["琉璃師到城，談性外諸經。下嶺雪霜在，近人林木清。", "苔痕深草履，瀑布滴銅瓶。樂問山中事，宵言徹曉星。"]'),
('yuding-17','秋暮與諸文士集宿姚端公所居','無可','唐','御定全唐诗','yuding','','[]','宵清月複圓，共集侍臣筵。獨寡區中學，空論樹下禪。',48,'御定全唐詩/json/814.json','["宵清月複圓，共集侍臣筵。獨寡區中學，空論樹下禪。", "風多秋晚竹，雲盡夜深天。此會東西去，堪愁又來年。"]'),
('yuding-18','客中聞從兄島游蒲絳因寄','無可','唐','御定全唐诗','yuding','','[]','遙遙行李心，蒼野入寒深。吟待黃河雪，眠聽絳郡砧。',48,'御定全唐詩/json/814.json','["遙遙行李心，蒼野入寒深。吟待黃河雪，眠聽絳郡砧。", "差期逢缺月，訪信出空林。何處孤燈下，只聞嘹唳禽。"]'),
('yuding-19','送李長吉之任東井','無可','唐','御定全唐诗','yuding','','[]','江盤棧轉虛，候吏拜行車。家世維城後，官資宰邑初。',48,'御定全唐詩/json/814.json','["江盤棧轉虛，候吏拜行車。家世維城後，官資宰邑初。", "市饒黃犢賣，田躡白雲鉏。萬里千山路，何因欲寄書。"]'),
('yuding-20','宿安國簡公院','無可','唐','御定全唐诗','yuding','','[]','雨後清涼境，因還欲不回。井甘桐有露，竹迸地多苔。',48,'御定全唐詩/json/814.json','["雨後清涼境，因還欲不回。井甘桐有露，竹迸地多苔。", "幡映宮牆動，香從御苑來。青龍舊經疏，寥落有誰開。"]'),
('yuding-21','京口別崔固','無可','唐','御定全唐诗','yuding','','[]','積雨晴時近，西風葉滿泉。相逢嵩嶽客，共聽楚城蟬。',48,'御定全唐詩/json/814.json','["積雨晴時近，西風葉滿泉。相逢嵩嶽客，共聽楚城蟬。", "宿館橫秋島，歸帆張遠田。別君還寂寞，不似剡中年。"]'),
('yuding-22','中秋夜隴州徐常侍座中詠月','無可','唐','御定全唐诗','yuding','','[]','隴城秋月滿，太守待停歌。與鶴來松杪，開煙出海波。',48,'御定全唐詩/json/814.json','["隴城秋月滿，太守待停歌。與鶴來松杪，開煙出海波。", "氣籠星欲盡，光滿露初多。若遣山僧說，高明不可過。"]'),
('yuding-23','中秋江驛示韋益','無可','唐','御定全唐诗','yuding','','[]','莫惜三更坐，難銷萬里情。同看一片月，俱在廣州城。',48,'御定全唐詩/json/814.json','["莫惜三更坐，難銷萬里情。同看一片月，俱在廣州城。", "淚逐金波滿，魂隨夜鵲驚。支頤鄉思斷，無語到雞鳴。"]'),
('yuding-24','中秋台看月','無可','唐','御定全唐诗','yuding','','[]','海雨洗煙埃，月從空碧來。水光籠草樹，練影掛樓臺。',48,'御定全唐詩/json/814.json','["海雨洗煙埃，月從空碧來。水光籠草樹，練影掛樓臺。", "皓耀迷鯨口，晶熒失蚌胎。宵分憑欄望，應合見蓬萊。"]'),
('yuding-25','中秋夜南樓寄友人','無可','唐','御定全唐诗','yuding','','[]','海月出白浪，湖光射高樓。朗吟無綠酒，賤價買清秋。',48,'御定全唐詩/json/814.json','["海月出白浪，湖光射高樓。朗吟無綠酒，賤價買清秋。", "氣冷魚龍寂，輪高星漢幽。他鄉此夜客，對酌經多愁。"]'),
('yuding-26','吊從兄島','無可','唐','御定全唐诗','yuding','','[]','盡日歎沉淪，孤高碣石人。詩名從蓋代，謫宦竟終身。',48,'御定全唐詩/json/814.json','["盡日歎沉淪，孤高碣石人。詩名從蓋代，謫宦竟終身。", "蜀集重編否，巴儀薄葬新。青門臨舊卷，欲見永無因。"]'),
('yuding-27','題崔駙馬林亭','無可','唐','御定全唐诗','yuding','','[]','宮花野藥半相和，藤蔓參差惜不科。纖草連門留徑細，',40,'御定全唐詩/json/814.json','["宮花野藥半相和，藤蔓參差惜不科。纖草連門留徑細，", "更買太湖千片石，疊成雲頂綠嵾峨。"]'),
('yuding-28','送韓校書赴江西','無可','唐','御定全唐诗','yuding','','[]','車馬東門別，揚帆過楚津。花繁期到幕，雪在已離秦。',72,'御定全唐詩/json/814.json','["車馬東門別，揚帆過楚津。花繁期到幕，雪在已離秦。", "吟落江沙月，行飛驛騎塵。猿聲孤島雨，草色五湖春。", "折葦鳴風岸，遙煙起暮蘋。鄱江連郡府，高興寄何人。"]'),
('yuding-29','送姚中丞赴陝州','無可','唐','御定全唐诗','yuding','','[]','二陝周分地，恩除左掖臣。門闌開幕重，槍甲下天新。',72,'御定全唐詩/json/814.json','["二陝周分地，恩除左掖臣。門闌開幕重，槍甲下天新。", "夾道行霜騎，迎風滿草人。河流銀漢水，城賽鐵牛神。", "意氣思高謝，依違許上陳。何妨向紅旆，自與白雲親。"]'),
('yuding-30','送李使君赴瓊州兼五州招討使','無可','唐','御定全唐诗','yuding','','[]','分竹雄兼使，南方到海行。臨門雙旆引，隔嶺五州迎。',72,'御定全唐詩/json/814.json','["分竹雄兼使，南方到海行。臨門雙旆引，隔嶺五州迎。", "猿鶴同枝宿，蘭蕉夾道生。雲垂前騎失，山豁去帆輕。", "雨霧蒸秋岸，浪濤震夜城。政閑開迥閣，欹枕島風清。"]'),
('yuding-31','送姚明府赴招義縣','無可','唐','御定全唐诗','yuding','','[]','濠梁古縣城，結束赴王程。道路攜家去，波濤隔月行。',72,'御定全唐詩/json/814.json','["濠梁古縣城，結束赴王程。道路攜家去，波濤隔月行。", "車臨芳草下，吏踏落花迎。暮郭山遙見，春洲鳥不驚。", "風煙譙國遠，桑柘楚田平。何以書能化，長淮徹海清。"]'),
('yuding-32','送杜司馬再遊蜀中','無可','唐','御定全唐诗','yuding','','[]','為客應非願，愁成欲別時。還游蜀國去，不惜杜陵期。',72,'御定全唐詩/json/814.json','["為客應非願，愁成欲別時。還游蜀國去，不惜杜陵期。", "劍水啼猿在，關林轉棧遲。日光低峽口，雨勢出蛾眉。", "山迥逢殘角，雲開識遠夷。勿令雙鬢髮，並向錦城衰。"]'),
('yuding-33','贈王將軍','無可','唐','御定全唐诗','yuding','','[]','勳高絕少年，分衛玉階前。雄勇明王重，溫恭執友賢。',120,'御定全唐詩/json/814.json','["勳高絕少年，分衛玉階前。雄勇明王重，溫恭執友賢。", "功書唐史滿，名到虜庭偏。劍彩浮龍影，衣香襲禦煙。", "搜書秋霽閣，走馬夕陽田。急兔投深草，瞋鷹下半天。", "野人盈邸第，朝客醉盤筵。位在將軍列，官隨憲府遷。", "刻心思報國，籲氣欲開邊。選帥如公議，須知少比肩。"]'),
('yuding-34','寄羽林盧大夫將軍','無可','唐','御定全唐诗','yuding','','[]','將軍直禁闈，繡服耀金羈。羽衛九天靜，英豪四塞知。',72,'御定全唐詩/json/814.json','["將軍直禁闈，繡服耀金羈。羽衛九天靜，英豪四塞知。", "望雲回朔雁，隔水射宮麋。舊國無歸思，秋堂夢戰時。", "門風荀氏敵，劍藝霍家推。計日旌旄下，蕭蕭萬馬隨。"]'),
('yuding-35','書事寄萬年厲員外','無可','唐','御定全唐诗','yuding','','[]','帝城皆劇縣，令尹美居東。遂拜趙張下，暫離星象中。',216,'御定全唐詩/json/814.json','["帝城皆劇縣，令尹美居東。遂拜趙張下，暫離星象中。", "擁歸從北闕，送上動南宮。舉起盆中日，驅行草上風。", "不驚盧犬吠，漸見夏台空。紫禁黃山繞，滄溟素滻通。", "封疆親日月，邑裏出王公。逐盜千門啟，興祥五稼豐。", "胥徒迎曉集，賦稅共秋終。條教關天道，歌謠入聖聰。", "土膏寒麥覆，人海晝塵蒙。廨宇松連翠，朝街日散紅。", "文場新桂茂，粉署舊蘭崇。留客把盈爵，抽毫詠早鴻。", "前騶潘嶽貴，故里邵平窮。勸隱蓮峰久，期耕樹穀同。", "鳧飛將去葉，劍氣尚埋豐。何必華陰土，方垂拂拭功。"]'),
('yuding-36','小雪','無可','唐','御定全唐诗','yuding','','[]','片片互玲瓏，飛揚玉漏終。乍微全滿地，漸密更無風。',144,'御定全唐詩/json/814.json','["片片互玲瓏，飛揚玉漏終。乍微全滿地，漸密更無風。", "集物圓方別，連雲遠近同。作膏凝瘠土，呈瑞下深宮。", "氣射重衣透，花窺小隙通。飄秦增舊嶺，發漢攬長空。", "迥冒巢松鶴，孤鳴穴島蟲。過三知臘盡，盈尺賀年豐。", "委積休聞竹，稀疏漸見鴻。蓋沙資澶漫，灑海助沖融。", "草木潛加潤，山河更益雄。因知天地力，覆育有全功。"]'),
('yuding-37','和賓客相國詠雪詩','無可','唐','御定全唐诗','yuding','','[]','近臘千岩白，迎春四氣催。雲陰連海起，風急度山來。',192,'御定全唐詩/json/814.json','["近臘千岩白，迎春四氣催。雲陰連海起，風急度山來。", "盡日隋堤絮，經冬越嶺梅。豔疑歌處散，輕似舞時回。", "道蘊詩傳麗，相如賦騁才。霽添松筱媚，寒積蕙蘭猜。", "暗漲宮池水，平封輦路埃。燭龍初照耀，巢鶴乍裴回。", "簷日瓊先掛，牆風粉旋摧。五門環玉壘，雙闕對瑤台。", "綺席陵寒坐，珠簾遠曙開。靈芝霜下秀，仙桂月中栽。", "卷幌書千帙，援琴酒百杯。垂休編太史，呈瑞表中台。", "皓夜迷三徑，浮光徹九垓。茲辰是豐歲，歌詠屬良哉。"]'),
('yuding-38','中秋夜君山腳下看月','無可','唐','御定全唐诗','yuding','','[]','洶湧吹蒼霧，朦朣吐玉盤。雨師清滓穢，川後掃波瀾。',96,'御定全唐詩/json/814.json','["洶湧吹蒼霧，朦朣吐玉盤。雨師清滓穢，川後掃波瀾。", "氣射繁星滅，光籠八表寒。來驅雲漲晚，路上碧霄寬。", "熠耀遊何在，蟾蜍食漸難。棹飛銀電碎，林映白虹攢。", "水魄連空合，霜輝壓樹幹。夜深高不動，天下仰頭看。"]'),
('yuding-39','哭張籍司業','無可','唐','御定全唐诗','yuding','','[]','先生抱衰疾，不起茂陵間。夕臨諸孤少，荒居吊客還。',72,'御定全唐詩/json/814.json','["先生抱衰疾，不起茂陵間。夕臨諸孤少，荒居吊客還。", "遺文禪東嶽，留語葬鄉山。多雨銘旌故，殘燈素帳閑。", "樂章誰與集，壟樹即堪攀。神理今難問，予將叫帝關。"]'),
('yuding-40','寄題廬山二林寺','無可','唐','御定全唐诗','yuding','','[]','廬岳東南秀，香花惠遠蹤。名齊松嶺峻，氣比沃州濃。',240,'御定全唐詩/json/814.json','["廬岳東南秀，香花惠遠蹤。名齊松嶺峻，氣比沃州濃。", "積岫連何處，幽崖越幾重。雙流湓隱隱，九派棹憧憧。", "山限東西寺，林交旦暮鐘。半天傾瀑溜，數郡見爐峰。", "岩並金繩道，潭分玉像容。江微匡俗路，日杲晉朝松。", "棕徑新苞拆，梅籬故葉壅。嵐光生疊砌，霞焰發高墉。", "窗籟虛聞狖，庭煙黑過龍。定僧仙嶠起，逋客虎溪逢。", "濩落垂楊戶，荒涼種杏封。塔留紅舍利，池吐白芙蓉。", "畫壁披雲見，禪衣對鶴縫。喧經泉滴瀝，沒履草豐茸。", "翠竇欹攀乳，苔橋側杖筇。探奇盈夢想，搜峭滌心胸。", "冥奧終難盡，登臨惜未從。上方薇蕨滿，歸去養乖慵。"]'),
('yuding-41','禦溝水','無可','唐','御定全唐诗','yuding','','[]','鑒禁疏雲數道開，垂風岸柳拂青苔。',32,'御定全唐詩/json/814.json','["鑒禁疏雲數道開，垂風岸柳拂青苔。", "銀波玉沫空池去，曾曆千岩萬壑來。"]'),
('yuding-42','中秋月彩如晝，寄上南海從翁侍禦','無可','唐','御定全唐诗','yuding','','[]','海靜天高景氣殊，鯨睛失彩蚌潛珠。',32,'御定全唐詩/json/814.json','["海靜天高景氣殊，鯨睛失彩蚌潛珠。", "不知今夜越臺上，望見瀛洲方丈無。"]'),
('yuding-0','奉酬於中丞使君郡齋臥病見示一首','皎然','唐','御定全唐诗','yuding','','[]','宿昔祖師教，了空無不可。枯槁未死身，理心寄行坐。',252,'御定全唐詩/json/815.json','["宿昔祖師教，了空無不可。枯槁未死身，理心寄行坐。", "仁公施春令，和風來澤我。生成一草木，大道無負荷。", "論入空王室，明月開心胸。性起妙不染，心行寂無蹤。", "若非禪中侶，君為雷次宗。比聞朝端名，今貽郡齋作。", "真思凝瑤瑟，高情屬雲鶴。抉得驪龍珠，光彩曜掌握。", "若作詩中友，君為謝康樂。盤薄西山氣，貯在君子衿。", "澄澹秋水影，用為字人心。群物如鳧鷖，遊翱愛清深。", "格居第一品，高步淩前躅。精義究天人，四坐聽不足。", "伊昔柳太守，曾賞汀洲蘋。如何五百年，重見江南春。", "公每省往事，詠歌懷昔辰。以茲得高臥，任物化自淳。", "還因訪禪隱，知有雪山人。"]'),
('yuding-1','贈李中丞洪一首','皎然','唐','御定全唐诗','yuding','','[]','深沈閫外略，奕世當榮寄。地裂大將封，家傳介珪瑞。',276,'御定全唐詩/json/815.json','["深沈閫外略，奕世當榮寄。地裂大將封，家傳介珪瑞。", "至今漳河俗，猶受仁人賜。公初鎮惟邢，決勝無精兵。", "重圍逼大敵，六月守孤城。政用仁恕立，恩由賞罰明。", "遂令麾下士，感德不顧生。于時聞王師，諸將兵頗黷。", "天子狩南漢，煙塵滿函穀。純臣獨耿介，下士多反復。", "明公仗忠節，一言感萬夫。物性如蒺藜，化作春蘭敷。", "見說金被爍，終期玉有瑜。移官萬里道，君子情何如。", "伊昔避事心，乃是方袍客。頓了空王旨，仍高致君策。", "安知七十年，一朝值宗伯。言如及清風，醒然開我懷。", "宴息與遊樂，不將衣褐乖。海底取明月，鯨波不可度。", "上有巨蟒吞，下有毒龍護。一與吾師言，乃於中心悟。", "咄哉冥冥子，胡為自塵汙。"]'),
('yuding-2','杼山禪居寄贈東溪吳處士馮一首','皎然','唐','御定全唐诗','yuding','','[]','青雲何潤澤，下有賢人隱。路入菱湖深，跡與黃鶴近。',156,'御定全唐詩/json/815.json','["青雲何潤澤，下有賢人隱。路入菱湖深，跡與黃鶴近。", "野風吹白芷，山月搖清軫。詩祖吳叔庠，致君名不盡。", "身當青山秀，文體多郢聲。澄澈湘水碧，泬寥楚山青。", "時人格不同，至今罕知名。昔賢敦師友，此道君獨行。", "既得廬霍趣，乃高雷遠情。別時春風多，掃盡雪山雪。", "為君中夜起，孤坐石上月。悠然遺塵想，邈矣達性說。", "故人不在茲，幽桂惜未結。"]'),
('yuding-3','妙喜寺高房期靈澈上人不至，重招之一首','皎然','唐','御定全唐诗','yuding','','[]','晨起峰頂心，懷人望空碧。掃雪開寺門，灑水淨僧席。',132,'御定全唐詩/json/815.json','["晨起峰頂心，懷人望空碧。掃雪開寺門，灑水淨僧席。", "言笑形外阻，風儀想中覿。馳心驚葉動，傾耳聞泉滴。", "豈慮咆虎逢，乍疑崩湍隔。前期或不顧，知爾隳常格。", "如今誰山下，秋霖步淅瀝。吾亦聊自得，行禪荷輕策。", "松聲暢幽情，山意導遐跡。舉目無世人，題詩足奇石。", "貧山何所有，特此邀來客。"]'),
('yuding-4','奉和薛員外誼贈湯評事衡反招隱之跡兼見寄十二韻','皎然','唐','御定全唐诗','yuding','','[]','喜友稱高儒，曠懷美無度。近為東田誘，遂耽西山趣。',144,'御定全唐詩/json/815.json','["喜友稱高儒，曠懷美無度。近為東田誘，遂耽西山趣。", "庭有介隱心，得無雲泉誤。府公中司貴，頻貽咫尺素。", "郡佐仙省高，亦贈瓊瑤句。誚茲長往志，紆彼獨游步。", "禪子方外期，夢想山中路。艱難親稼穡，晨夕苦煙霧。", "曷若孟嘗門，日榮國士遇。鏗鏘聆綺瑟，攀折邇瓊樹。", "幽踐隨鹿麋，久期怨蟾兔。情同不系舟，有跡道所惡。"]'),
('yuding-5','答黎士曹黎生前適越後之楚','皎然','唐','御定全唐诗','yuding','','[]','楚木紛如麻，高松自孤直。願得苦寒枝，與君比顏色。',216,'御定全唐詩/json/815.json','["楚木紛如麻，高松自孤直。願得苦寒枝，與君比顏色。", "故鄉眇天末，羈旅滄江隅。委質在忠信，苦心無變渝。", "何繇表名義，贈君金轆轤。何以美知才，投我懸黎珠。", "遽為千里別，南風思越絕。愛君隨海鷗，倚棹宿沙月。", "不棲惡木上，肯蹈巴蛇穴。一上蕭然峰，擬蹤幽人轍。", "晨興獨西望，郢水期溯沿。夜到洞庭月，秋經雲夢天。", "黎生知吾道，此地不潸然。欲寄楚人住，學拏漁子船。", "奈何北風至，攪我窗中弦。遊子動歸思，江蘺亦綿綿。", "篋中封禪書，欲獻無由緣。豈乏晨風翼，翻飛到日邊。"]'),
('yuding-6','答豆盧次方','皎然','唐','御定全唐诗','yuding','','[]','吾愛道交論，為高貴世名。昔稱柴桑令，今聞豆盧生。',168,'御定全唐詩/json/815.json','["吾愛道交論，為高貴世名。昔稱柴桑令，今聞豆盧生。", "彼生清淮氣，獨鐘文中彩。近作公宴詩，如逢何柳在。", "吾用古人耳，采君四坐珍。賢士勝朝暉，溫溫無冬春。", "朝暉爍我肌，賢士清我神。微爾與雲鵠，幽懷何由申。", "別來秋風至，獨坐楚山碧。高月當清冥，禪心正寂曆。", "增波徒相駭，人遠情不隔。有書遺瓊什，以代貂襜褕。", "風教淩越絕，聲名掩吳趨。懸璧安可酬，徙倚還踟躕。"]'),
('yuding-7','答蘇州韋應物郎中','皎然','唐','御定全唐诗','yuding','','[]','詩教殆淪缺，庸音互相傾。忽觀風騷韻，會我夙昔情。',180,'御定全唐詩/json/815.json','["詩教殆淪缺，庸音互相傾。忽觀風騷韻，會我夙昔情。", "蕩漾學海資，郁為詩人英。格將寒松高，氣與秋江清。", "何必鄴中作，可為千載程。受辭分虎竹，萬里臨江城。", "到日掃煩政，況今休黷兵。應憐禪家子，林下寂無營。", "跡隳世上華，心得道中精。脫略文字累，免為外物攖。", "書衣流埃積，硯石駁蘚生。恨未識君子，空傳手中瓊。", "安可誘我性，始願愆素誠。為無鸑鷟音，繼公雲和笙。", "吟之向禪藪，反愧幽松聲。"]'),
('yuding-8','答鄭方回','皎然','唐','御定全唐诗','yuding','','[]','獨禪外念入，中夜不成定。顧我憔悴容，澤君陽春詠。',240,'御定全唐詩/json/815.json','["獨禪外念入，中夜不成定。顧我憔悴容，澤君陽春詠。", "詞貞思且逸，瓊彩何暉映。如聆雲和音，況睹聲名盛。", "琴語掩為聞，山心聲宜聽。是時寒光澈，萬境澄以淨。", "高秋日月清，中氣天地正。遠情偶茲夕，道用增寥夐。", "思君處虛空，一操不可更。時美城北徐，家承谷口鄭。", "軒車未有轍，蒿蘭且同徑。莊生誡近名，夫子罕言命。", "是以耕楚田，曠然殊獨行。萎蕤鸞鳳彩，特達珪璋性。", "通隱嘉黃綺，高儒重荀孟。世汙我未起，道蹇吾猶病。", "逸翮思冥冥，潛鱗樂游泳。宗師許學外，恨不逢孔聖。", "說詩迷頹靡，偶俗傷趨競。此道誰共詮，因君情欲罄。"]'),
('yuding-9','答俞校書冬夜','皎然','唐','御定全唐诗','yuding','','[]','夜閑禪用精，空界亦清迥。子真仙曹吏，好我如宗炳。',120,'御定全唐詩/json/815.json','["夜閑禪用精，空界亦清迥。子真仙曹吏，好我如宗炳。", "一宿覿幽勝，形清煩慮屏。新聲殊激楚，麗句同歌郢。", "遺此感予懷，沈吟忘夕永。月彩散瑤碧，示君禪中境。", "真思在杳冥，浮念寄形影。遙得四明心，何須蹈岑嶺。", "詩情聊作用，空性惟寂靜。若許林下期，看君辭簿領。"]'),
('yuding-10','妙喜寺達公禪齋寄李司直公孫、房都曹德裕…四十二韻','皎然','唐','御定全唐诗','yuding','','[]','我祖傳六經，精義思朝徹。方舟頗周覽，逸書亦備閱。',516,'御定全唐詩/json/815.json','["我祖傳六經，精義思朝徹。方舟頗周覽，逸書亦備閱。", "墨家傷刻薄，儒氏知優劣。弱植庶可凋，苦心未嘗輟。", "中年慕仙術，永願傳其訣。歲駐若木景，日餐瓊禾屑。", "嬋娟羨門子，斯語豈徒設。天上生白榆，葳蕤信好折。", "實可反柔顏，花堪養玄發。求之性分外，業棄金亦竭。", "藥化成白雲，形凋辭素穴。一聞西天旨，初禪已無熱。", "涓子非我宗，然公有真訣。卻尋丘壑趣，始與纓紱別。", "野飯敵膏粱，山楹代藻棁。與君北岩侶，遊寓日常昳。", "靜對春穀泉，晴披陽林雪。境清覺神王，道勝知機滅。", "詣寂長杳冥，忘歸暫採擷。物生豈有心，麗容俟予別。", "桂子何蓂苓，琪葩亦皎潔。此木生意高，亦與眾芳列。", "賞墨識屢換，省躬悟彌切。微尚若不虧，足以全吾節。", "北風吹蕙帶，蕭寥聞蜻蛚。宿昔廬峰期，流芳已再歇。", "不有清屏鑒，使我商弦絕。願寄千里心，月高不可掇。", "優遊邦之直，遠矣踵前烈。立俗忘毀譽，遇物遺巧拙。", "真氣獨翛然，軒裳詎能絏。都曹風韻整，綱紀信明決。", "於交必傾寫，立行豈矜伐。政與清渭同，分流自澄澈。", "裴侯資亮直，中誠豈徒說。古人比明義，清士願交結。", "溫溫躬珪彩，終始聲不缺。顏生炯介士，有志不可越。", "仗義冒險難，持操去淄涅。世論高二賢，賢賢繼前哲。", "四子遭明盛，裒然皆秀傑。理名雖殊跡，悟道寧異轍。", "愛爾竹柏姿，為予寒不折。"]'),
('yuding-11','遙酬袁使君高春暮行縣，過報德寺見懷','皎然','唐','御定全唐诗','yuding','','[]','江春行求瘼，偶與真境期。見說三陵下，前朝開佛祠。',96,'御定全唐詩/json/815.json','["江春行求瘼，偶與真境期。見說三陵下，前朝開佛祠。", "停舟仰麗刹，繡組發香墀。咫尺空界色，天人花落時。", "盛遊限羸疾，悚踴瞻旌旗。峰翠羨閒步，松聲入遙思。", "素高淮陽理，況負東山姿。迨此一登覽，深情見新詩。"]'),
('yuding-12','冬日遙和盧使君幼平、綦毋居士游法華寺高頂臨湖亭','皎然','唐','御定全唐诗','yuding','','[]','仁坊標絕境，廉守躡高蹤。天曉才分刹，風傳欲盡鐘。',84,'御定全唐詩/json/815.json','["仁坊標絕境，廉守躡高蹤。天曉才分刹，風傳欲盡鐘。", "城中歸路遠，湖上碧山重。水照千花界，雲開七葉峰。", "寒芳艾綬滿，空翠白綸濃。逸韻知難繼，佳遊恨不逢。", "仍聞撫禪石，為我久從容。"]'),
('yuding-13','秋日遙和盧使君游何山寺宿敡上人房論涅盤經義','皎然','唐','御定全唐诗','yuding','','[]','江郡當秋景，期將道者同。跡高憐竹寺，夜靜賞蓮宮。',60,'御定全唐詩/json/815.json','["江郡當秋景，期將道者同。跡高憐竹寺，夜靜賞蓮宮。", "古磬清霜下，寒山曉月中。詩情緣境發，法性寄筌空。", "翻譯推南本，何人繼謝公。"]'),
('yuding-14','酬秦山人系題贈','皎然','唐','御定全唐诗','yuding','','[]','出齋步杉影，手自開禪扉。花滿不汙地，雲多從觸衣。',48,'御定全唐詩/json/815.json','["出齋步杉影，手自開禪扉。花滿不汙地，雲多從觸衣。", "思山石蘚淨，款客露葵肥。果得宗居士，論心到極微。"]'),
('yuding-15','奉酬袁使君高寺院新亭對雨','皎然','唐','御定全唐诗','yuding','','[]','茲亭跡素淺，勝事並隨公。法界飄香雨，禪窗灑竹風。',48,'御定全唐詩/json/815.json','["茲亭跡素淺，勝事並隨公。法界飄香雨，禪窗灑竹風。", "浮煙披夕景，高鶴下秋空。冥寂四山久，甯期此會同。"]'),
('yuding-16','奉酬顏使君真卿見過郭中寺寺無山水之賞…以答焉','皎然','唐','御定全唐诗','yuding','','[]','州西柳家寺，禪舍隱人間。證性輕觀水，棲心不買山。',48,'御定全唐詩/json/815.json','["州西柳家寺，禪舍隱人間。證性輕觀水，棲心不買山。", "履聲知客貴，雲影悟身閑。彥會前賢事，方今可得攀。"]'),
('yuding-17','酬烏程楊明府華雨後小亭對月見呈','皎然','唐','御定全唐诗','yuding','','[]','夜涼喜無訟，霽色搖閒情。暑退不因雨，陶家風自清。',48,'御定全唐詩/json/815.json','["夜涼喜無訟，霽色搖閒情。暑退不因雨，陶家風自清。", "凝弦停片景，發詠靜秋聲。何事禪中隱，詩題忽記名。"]'),
('yuding-18','自蘇州訪醫回酬盧士關判官見贈','皎然','唐','御定全唐诗','yuding','','[]','尋醫初疾理，忽憶故山雲。遠訪桑公子，還依柳使君。',48,'御定全唐詩/json/815.json','["尋醫初疾理，忽憶故山雲。遠訪桑公子，還依柳使君。", "周旋承惠愛，佩服比蘭熏。從事因高唱，秋風起處聞。"]'),
('yuding-19','題沈道士新亭','皎然','唐','御定全唐诗','yuding','','[]','何處好攀躋，新亭俯舊溪。坐中千里近，簷下四山低。',48,'御定全唐詩/json/815.json','["何處好攀躋，新亭俯舊溪。坐中千里近，簷下四山低。", "小浦依林曲，回塘繞郭西。桃花春滿地，歸路莫相迷。"]'),
('yuding-20','送盧仲舒移家海陵','皎然','唐','御定全唐诗','yuding','','[]','世故多離散，東西不可嗟。小秦非本國，楚塞複移家。',48,'御定全唐詩/json/815.json','["世故多離散，東西不可嗟。小秦非本國，楚塞複移家。", "海島無鄰里，鹽居少物華。山中吟夜月，相送在天涯。"]'),
('yuding-21','陪盧使君登樓送方巨之還京','皎然','唐','御定全唐诗','yuding','','[]','萬里汀洲上，東樓欲別離。春風潮水漫，正月柳條寒。',48,'御定全唐詩/json/815.json','["萬里汀洲上，東樓欲別離。春風潮水漫，正月柳條寒。", "旅逸逢漁浦，清高愛鳥冠。雲山寧不起，今日向長安。"]'),
('yuding-22','同裴錄事樓上望','皎然','唐','御定全唐诗','yuding','','[]','退食高樓上，湖山向晚晴。桐花落萬井，月影出重城。',48,'御定全唐詩/json/815.json','["退食高樓上，湖山向晚晴。桐花落萬井，月影出重城。", "水竹涼風起，簾幃暑氣清。蕭蕭獨無事，因見蒞人情。"]'),
('yuding-23','寓興','皎然','唐','御定全唐诗','yuding','','[]','天下生白榆，白榆直上連天根。高枝不知幾萬丈，',46,'御定全唐詩/json/815.json','["天下生白榆，白榆直上連天根。高枝不知幾萬丈，", "因問老仙求種法，老仙咍我愚不答。始知此道無所成，"]'),
('yuding-24','寄常一上人','皎然','唐','御定全唐诗','yuding','','[]','雁塞五山臨汗漫，雲州一路出青冥。',32,'御定全唐詩/json/815.json','["雁塞五山臨汗漫，雲州一路出青冥。", "何因請住嘉祥寺，內史新修湖上亭。"]'),
('yuding-25','送秘上人遊京','皎然','唐','御定全唐诗','yuding','','[]','共君方異路，山伴與誰同。日冷行人少，時清古鎮空。',48,'御定全唐詩/json/815.json','["共君方異路，山伴與誰同。日冷行人少，時清古鎮空。", "暖瓶和雪水，鳴錫帶江風。撩亂終南色，遙應入夢中。"]'),
('yuding-26','賦得啼猿送客','皎然','唐','御定全唐诗','yuding','','[]','萬里巴江外，三聲月峽深。何年有此路，幾客共沾襟。',48,'御定全唐詩/json/815.json','["萬里巴江外，三聲月峽深。何年有此路，幾客共沾襟。", "斷壁分垂影，流泉入苦吟。淒涼離別後，聞此更傷心。"]'),
('yuding-27','南樓望月','皎然','唐','御定全唐诗','yuding','','[]','夜月家家望，亭亭愛此樓。纖雲溪上斷，疏柳影中秋。',48,'御定全唐詩/json/815.json','["夜月家家望，亭亭愛此樓。纖雲溪上斷，疏柳影中秋。", "漸映千峰出，遙分萬派流。關山誰複見，應獨起邊愁。"]'),
('yuding-28','尋陸鴻漸不遇','皎然','唐','御定全唐诗','yuding','','[]','移家雖帶郭，野徑入桑麻。近種籬邊菊，秋來未著花。',48,'御定全唐詩/json/815.json','["移家雖帶郭，野徑入桑麻。近種籬邊菊，秋來未著花。", "扣門無犬吠，欲去問西家。報導山中去，歸時每日斜。"]'),
('yuding-29','懷舊山','皎然','唐','御定全唐诗','yuding','','[]','一坐西林寺，從來未下山。不因尋長者，無事到人間。',48,'御定全唐詩/json/815.json','["一坐西林寺，從來未下山。不因尋長者，無事到人間。", "宿雨愁為客，寒花笑未還。空懷舊山月，童子念經閑。"]'),
('yuding-30','宿吳匡山破寺','皎然','唐','御定全唐诗','yuding','','[]','雙峰百戰後，真界滿塵埃。蔓草緣空壁，悲風起故台。',48,'御定全唐詩/json/815.json','["雙峰百戰後，真界滿塵埃。蔓草緣空壁，悲風起故台。", "野花寒更發，山月暝還來。何事池中水，東流獨不回。"]'),
('yuding-31','九月十日','皎然','唐','御定全唐诗','yuding','','[]','愛殺柴桑隱，名溪近訟庭。掃沙開野步，搖舸出閑汀。',48,'御定全唐詩/json/815.json','["愛殺柴桑隱，名溪近訟庭。掃沙開野步，搖舸出閑汀。", "宿簡邀詩伴，餘花在酒瓶。悠然南望意，自有峴山情。"]'),
('yuding-32','秋晚宿破山寺','皎然','唐','御定全唐诗','yuding','','[]','秋風落葉滿空山，古寺殘燈石壁間。',32,'御定全唐詩/json/815.json','["秋風落葉滿空山，古寺殘燈石壁間。", "昔日經行人去盡，寒雲夜夜自飛還。"]'),
('yuding-33','青陽上人院說金陵故事','皎然','唐','御定全唐诗','yuding','','[]','君說南朝全盛日，秣陵才子更多人。',32,'御定全唐詩/json/815.json','["君說南朝全盛日，秣陵才子更多人。", "千年秋色古池館，誰見齊王西邸春。"]'),
('yuding-34','送僧之京師','皎然','唐','御定全唐诗','yuding','','[]','綿綿渺渺楚雲繁，萬里西歸望國門。',32,'御定全唐詩/json/815.json','["綿綿渺渺楚雲繁，萬里西歸望國門。", "禪子初心易淒斷，秋風莫上少陵原。"]'),
('yuding-35','送許丞還洛陽','皎然','唐','御定全唐诗','yuding','','[]','剡茗情來亦好斟，空門一別肯沾襟。',32,'御定全唐詩/json/815.json','["剡茗情來亦好斟，空門一別肯沾襟。", "悲風不動罷瑤軫，忘卻洛陽歸客心。"]'),
('yuding-36','題湖上草堂','皎然','唐','御定全唐诗','yuding','','[]','山居不買剡中山，湖上千峰處處閑。',32,'御定全唐詩/json/815.json','["山居不買剡中山，湖上千峰處處閑。", "芳草白雲留我住，世人何事得相關。"]'),
('yuding-37','酬李司直縱諸公冬日遊妙喜寺題照、昱二上人房…述','皎然','唐','御定全唐诗','yuding','','[]','達賢貴貞隱，常懼跡不滅。遂與永公期，遺身坐林樾。',84,'御定全唐詩/json/815.json','["達賢貴貞隱，常懼跡不滅。遂與永公期，遺身坐林樾。", "華軒何轔轔，為我到幽絕。心境寒草花，空門青山月。", "潘生獨不見，清景屢盈缺。林下常寂寥，人間自離別。", "何時解輕佩，來稅丘中轍。"]'),
('yuding-38','贈烏程李明府伯宜、沈兵曹仲昌','皎然','唐','御定全唐诗','yuding','','[]','水國苦凋瘵，東皋豈遺黍。雲陰無盡時，日出常帶雨。',72,'御定全唐詩/json/815.json','["水國苦凋瘵，東皋豈遺黍。雲陰無盡時，日出常帶雨。", "昨夜西溪漲，扁舟入簷廡。野人同鳥巢，暴客若蜂聚。", "歲晏無鬥粟，寄身欲何所。空羨鸞鶴姿，翩翩自輕舉。"]'),
('yuding-39','奉酬顏使君真卿、王員外圓宿寺兼送員外使回','皎然','唐','御定全唐诗','yuding','','[]','魯公邀省客，貧寺人過少。錦帳惟野花，竹屏有窗筱。',72,'御定全唐詩/json/815.json','["魯公邀省客，貧寺人過少。錦帳惟野花，竹屏有窗筱。", "朝行石色淨，夜聽泉聲小。釋事情已高，依禪境無擾。", "超遙長路首，悵望空林杪。離思從此生，還將此心了。"]'),
('yuding-40','杼山上峰和顏使君真卿、袁侍禦五韻賦得印字…之會','皎然','唐','御定全唐诗','yuding','','[]','道情寄遠嶽，放曠臨千仞。香路延絳騶，華泉寫金印。',60,'御定全唐詩/json/815.json','["道情寄遠嶽，放曠臨千仞。香路延絳騶，華泉寫金印。", "日欹諸天近，雨過三華潤。留客雲外心，忘機松中韻。", "靈嘉早晚期，為布東山信。"]'),
('yuding-41','同薛員外誼喜雨詩兼上楊使君','皎然','唐','御定全唐诗','yuding','','[]','積旱忽飛澍，烝民心亦傾。郊雲不待族，雨色飛江城。',96,'御定全唐詩/json/815.json','["積旱忽飛澍，烝民心亦傾。郊雲不待族，雨色飛江城。", "燋稼濯又發，敗荷滋更榮。時隨霧縠重，乍集柳絲輕。", "一宿恐魚飛，數朝征鸛鳴。毒暑澄為冷，高塵滌還清。", "乃知陰騭數，制在造化情。及此接歡賀，臨風聞頌聲。"]'),
('yuding-42','南湖春泛有客自北至說友人岑元…敘相思之志以寄焉','皎然','唐','御定全唐诗','yuding','','[]','故人隔楚水，日夕望芳洲。春草思眇眇，征雲暮悠悠。',180,'御定全唐詩/json/815.json','["故人隔楚水，日夕望芳洲。春草思眇眇，征雲暮悠悠。", "心期無形影，跡曠成阻修。有客江上至，知君佐雄州。", "鏗鏘佩蒼玉，躞蹀驅絳騶。伊昔中峰心，從來非此流。", "資予長生訣，希彼高山儔。此情今如何，宿昔師吾謀。", "別年謁禪老，更添石室籌。深見人間世，飄如水上漚。", "蟬號齊王邸，月苦隋帝樓。聲華盡冥寞，麋鹿徒呦呦。", "我有一字教，坐然遺此憂。何煩脫珪組，不用辭王侯。", "只在名位中，空門兼可遊。"]'),
('yuding-43','同薛員外誼久旱感懷寄兼呈上楊使君','皎然','唐','御定全唐诗','yuding','','[]','皇天鑒不昧，愐想何亢極。絲雨久愆期，綺霞徒相惑。',132,'御定全唐詩/json/815.json','["皇天鑒不昧，愐想何亢極。絲雨久愆期，綺霞徒相惑。", "陰雲舒又卷，濯枝安可得。涸井不累瓶，幹溪一憑軾。", "赤地芳草死，飆塵驚四塞。戎冠夜刺閨，民荒歲傷國。", "賴以王猷盛，中原無凶慝。楊公當此晨，省災常旰食。", "獨感下堂雨，偏嘉越境域。秋郊天根見，我疆看稼穡。", "請回雲漢詩，為君歌樂職。"]'),
('yuding-44','兵後早春登故鄣南樓望昆山寺白鶴觀示清道人並沈道士','皎然','唐','御定全唐诗','yuding','','[]','新陽故樓上，眇眇傷遐眷。違世情易忘，羈時得無倦。',168,'御定全唐詩/json/815.json','["新陽故樓上，眇眇傷遐眷。違世情易忘，羈時得無倦。", "春歸華柳發，世故陵穀變。擾擾陌上心，悠悠夢中見。", "蒼林有靈境，杳映遙可羨。春日倚東峰，華泉落西甸。", "鐘聲在空碧，幡影搖蔥蒨。緬想山中人，神期如會面。", "別離芳月積，岐路浮雲偏。正□入空門，仙君依苦縣。", "隳形舍簪紱，烹玉思精煉。事外宜我心，人間豈予戀。", "身遺世自薄，道勝名必賤。耳目何所娛，白雲與黃卷。"]'),
('yuding-45','酬烏程楊明府華將赴渭北對月見懷','皎然','唐','御定全唐诗','yuding','','[]','釋印及秋夜，身閑境亦清。風襟自瀟灑，月意何高明。',108,'御定全唐詩/json/815.json','["釋印及秋夜，身閑境亦清。風襟自瀟灑，月意何高明。", "聞說武安君，萬里驅妖精。開府集秀士，先招士林英。", "晉家用元凱，亦是魯諸生。北望撫長劍，感君知已行。", "邊塵昏玉帳，殺氣凝金鐙。大敵折齊俎，一書下聊城。", "翻飛青雲路，宿昔滄洲情。"]'),
('yuding-46','酬邢端公濟春日蘇台有呈袁州李使君…辛陽王三侍禦','皎然','唐','御定全唐诗','yuding','','[]','大賢當佐世，堯時難退身。如何丹霄侶，卻在滄江濱。',96,'御定全唐詩/json/815.json','["大賢當佐世，堯時難退身。如何丹霄侶，卻在滄江濱。", "柳色變又遍，鶯聲聞亦頻。賴逢宜春守，共賞南湖春。", "營道知止足，飾躬無緇磷。家將詩流近，跡與禪僧親。", "放曠臨海門，翱翔望雲津。雖高空王說，不久山中人。"]'),
('yuding-47','奉和裴使君清春夜南堂聽陳山人彈白雪','皎然','唐','御定全唐诗','yuding','','[]','春宵凝麗思，閑坐開南圍。郢客彈白雪，紛綸發金徽。',84,'御定全唐詩/json/815.json','["春宵凝麗思，閑坐開南圍。郢客彈白雪，紛綸發金徽。", "散從天上至，集向瓊台飛。弦上凝颯颯，虛中想霏霏。", "通幽鬼神駭，合道精鑒稀。變態風更入，含情月初歸。", "方知阮太守，一聽識其微。"]'),
('yuding-48','答孟秀才','皎然','唐','御定全唐诗','yuding','','[]','羸疾依小院，空閒趣自深。躡苔憐靜色，掃樹共芳陰。',60,'御定全唐詩/json/815.json','["羸疾依小院，空閒趣自深。躡苔憐靜色，掃樹共芳陰。", "物外好風至，意中佳客尋。虛名誰欲累，世事我無心。", "投贈荷君芷，馨香滿幽襟。"]'),
('yuding-49','酬崔侍禦見贈','皎然','唐','御定全唐诗','yuding','','[]','買得東山后，逢君小隱時。五湖游不厭，柏署跡如遺。',48,'御定全唐詩/json/815.json','["買得東山后，逢君小隱時。五湖游不厭，柏署跡如遺。", "市隱何妨道，禪棲不廢詩。與君為此說，長破小乘疑。"]'),
('yuding-50','贈柳喜得嵩山法門自號嵩山老','皎然','唐','御定全唐诗','yuding','','[]','一見嵩山老，吾生恨太遲。問君年幾許，曾出上皇時。',24,'御定全唐詩/json/815.json','["一見嵩山老，吾生恨太遲。問君年幾許，曾出上皇時。"]'),
('yuding-51','酬李補闕紓','皎然','唐','御定全唐诗','yuding','','[]','不住東林寺，雲泉處處行。近臣那得識，禪客本無名。',24,'御定全唐詩/json/815.json','["不住東林寺，雲泉處處行。近臣那得識，禪客本無名。"]'),
('yuding-52','湖南蘭若示大乘諸公','皎然','唐','御定全唐诗','yuding','','[]','未到無為岸，空憐不系舟。東山白雲意，歲晚尚悠悠。',24,'御定全唐詩/json/815.json','["未到無為岸，空憐不系舟。東山白雲意，歲晚尚悠悠。"]'),
('yuding-53','兵後經永安法空寺寄悟禪師','皎然','唐','御定全唐诗','yuding','','[]','常說人間法自空，何言出世法還同。微蹤舊是香林下，',40,'御定全唐詩/json/815.json','["常說人間法自空，何言出世法還同。微蹤舊是香林下，", "吾知世代相看盡，誰悟浮生似影公。"]'),
('yuding-54','春日杼山寄贈李員外縱','皎然','唐','御定全唐诗','yuding','','[]','南山唯與北山鄰，古樹連拳伴我身。黃鶴有心多不住，',40,'御定全唐詩/json/815.json','["南山唯與北山鄰，古樹連拳伴我身。黃鶴有心多不住，", "欲掇幽芳聊贈遠，郎官那賞石門春。"]'),
('yuding-55','酬秦山人贈別二首','皎然','唐','御定全唐诗','yuding','','[]','知君高隱占賢星，卷葉時時注佛經。姓被名公題舊裏，',81,'御定全唐詩/json/815.json','["知君高隱占賢星，卷葉時時注佛經。姓被名公題舊裏，", "我有主人江太守，如何相伴住禪靈。", "誰知臥病不妨禪，跡寄詩流性似偏。葉示黃金童子愛，", "對此留君還欲別，應思石de訪春泉。"]'),
('yuding-56','山居示靈澈上人','皎然','唐','御定全唐诗','yuding','','[]','晴明路出山初暖，行踏春蕪看茗歸。乍削柳枝聊代劄，',40,'御定全唐詩/json/815.json','["晴明路出山初暖，行踏春蕪看茗歸。乍削柳枝聊代劄，", "外物寂中誰似我，松聲草色共無機。"]'),
('yuding-57','遙和康錄事李侍禦萼小寒食夜重集康氏園林','皎然','唐','御定全唐诗','yuding','','[]','習家寒食會何頻，應恐流芳不待人。已愛治書詩句逸，',40,'御定全唐詩/json/815.json','["習家寒食會何頻，應恐流芳不待人。已愛治書詩句逸，", "誰見柰園時節共，還持綠茗賞殘春。"]'),
('yuding-58','釋裴循春愁','皎然','唐','御定全唐诗','yuding','','[]','蝶舞鶯歌喜歲芳，柳絲嫋嫋蕙帶長。',32,'御定全唐詩/json/815.json','["蝶舞鶯歌喜歲芳，柳絲嫋嫋蕙帶長。", "江南春色共君有，何事君心獨自傷。"]'),
('yuding-59','西白溪期裴方舟不至','皎然','唐','御定全唐诗','yuding','','[]','望君不見複何情，野草閑雲處處生。',32,'御定全唐詩/json/815.json','["望君不見複何情，野草閑雲處處生。", "應向秦時武陵路，花間寂曆一人行。"]'),
('yuding-60','勞山憶棲霞寺道素上人久期不至','皎然','唐','御定全唐诗','yuding','','[]','遠寺蕭蕭獨坐心，山情自得趣何深。泉聲稍滴芙蓉漏，',48,'御定全唐詩/json/815.json','["遠寺蕭蕭獨坐心，山情自得趣何深。泉聲稍滴芙蓉漏，", "貪閑不記前心偈，念別聊為出世吟。更待花開遍山雪，"]'),
('yuding-61','酬秦山人出山見呈','皎然','唐','御定全唐诗','yuding','','[]','手攜酒榼共書幃，回語長松我即歸。',32,'御定全唐詩/json/815.json','["手攜酒榼共書幃，回語長松我即歸。", "若是出山機已息，嶺雲何事背君飛。"]'),
('yuding-62','酬秦山人見尋','皎然','唐','御定全唐诗','yuding','','[]','左右香童不識君，擔簦訪我領鷗群。',32,'御定全唐詩/json/815.json','["左右香童不識君，擔簦訪我領鷗群。", "山僧待客無俗物，唯有窗前片碧雲。"]'),
('yuding-63','宿法華寺簡靈澈上人','皎然','唐','御定全唐诗','yuding','','[]','至道無機但杳冥，孤燈寒竹自青熒。',32,'御定全唐詩/json/815.json','["至道無機但杳冥，孤燈寒竹自青熒。", "不知何處小乘客，一夜風來聞誦經。"]'),
('yuding-64','潛別離','皎然','唐','御定全唐诗','yuding','','[]','烏頭雖黑白有時，唯有潛離與暗別，彼此甘心無後期。',24,'御定全唐詩/json/815.json','["烏頭雖黑白有時，唯有潛離與暗別，彼此甘心無後期。"]'),
('yuding-0','奉酬袁使君高春遊鶺鴒峰蘭若見懷','皎然','唐','御定全唐诗','yuding','','[]','鶺鴒中峰近，高奇古人遺。常欲乞此地，養松掛藤絲。',84,'御定全唐詩/json/816.json','["鶺鴒中峰近，高奇古人遺。常欲乞此地，養松掛藤絲。", "昨聞雙旌出，一川花滿時。恨無翔雲步，遠赴關山期。", "躋險與誰賞，折芳應自怡。遙知忘歸趣，喜得春景遲。", "已見郢人唱，新題石門詩。"]'),
('yuding-1','答裴濟從事','皎然','唐','御定全唐诗','yuding','','[]','遲遲雲鶴意，奮翅知有期。三秉綱紀局，累登清白資。',96,'御定全唐詩/json/816.json','["遲遲雲鶴意，奮翅知有期。三秉綱紀局，累登清白資。", "應懷青塘居，蕙草沒前墀。舊月照秋水，廢田留故陂。", "至今高風在，為君吹桂枝。昨逢洞庭客，果得故人詩。", "何異王內史，來招道林師。欲攜山侶出，難與白雲辭。"]'),
('yuding-2','白雲上人精舍尋杼山禪師兼示崔子向何山道上人','皎然','唐','御定全唐诗','yuding','','[]','望遠涉寒水，懷人在幽境。為高皎皎姿，及愛蒼蒼嶺。',144,'御定全唐詩/json/816.json','["望遠涉寒水，懷人在幽境。為高皎皎姿，及愛蒼蒼嶺。", "果見棲禪子，潺湲灌真頂。積疑一念破，澄息萬緣靜。", "世事花上塵，惠心空中境。清閒誘我性，遂使腸慮屏。", "許共林客遊，欲從山王請。木棲無名樹，水汲忘機井。", "持此一日高，未肯謝箕潁。夕霽山態好，空月生俄頃。", "識妙聆細泉，悟深滌清茗。此心誰得失，笑向西林永。"]'),
('yuding-3','酬薛員外誼苦熱行見寄','皎然','唐','御定全唐诗','yuding','','[]','六月金數伏，茲辰日在庚。炎曦爍肌膚，毒霧昏性情。',120,'御定全唐詩/json/816.json','["六月金數伏，茲辰日在庚。炎曦爍肌膚，毒霧昏性情。", "安得奮輕翮，超遙出雲征。不知天地心，如何匠生成。", "火德燒百卉，瑤草不及榮。省客當此時，忽貽懷中瓊。", "捧玩煩袂滌，嘯歌美風生。遲君佐元氣，調使四序平。", "中令霜不祓，大餘氣常貞。江南詩騷客，休吟苦熱行。"]'),
('yuding-4','采實心竹杖寄贈李萼侍禦','皎然','唐','御定全唐诗','yuding','','[]','竹杖裁碧鮮，步林賞高直。實心去內矯，全節無外飾。',60,'御定全唐詩/json/816.json','["竹杖裁碧鮮，步林賞高直。實心去內矯，全節無外飾。", "行藥聊自持，扶危資爾力。初生在榛莽，孤秀豈封殖。", "幹雪不死枝，贈君期君識。"]'),
('yuding-5','酬薛員外誼見戲一首','皎然','唐','御定全唐诗','yuding','','[]','方知正始作，麗掩碧雲詩。文彩盈懷袖，風規發詠思。',72,'御定全唐詩/json/816.json','["方知正始作，麗掩碧雲詩。文彩盈懷袖，風規發詠思。", "遺弓逢大敵，摩壘怯偏師。頻有移書讓，多慚系組遲。", "淺才迂且拙，虛譽喜還疑。猶倚披沙鑒，長歌向子期。"]'),
('yuding-6','奉酬李中丞洪湖州西亭即事見寄兼呈吳馮處士…長史','皎然','唐','御定全唐诗','yuding','','[]','愛君溪上住，遲月開前扃。山火照書卷，野風吹酒瓶。',84,'御定全唐詩/json/816.json','["愛君溪上住，遲月開前扃。山火照書卷，野風吹酒瓶。", "為誰留此物，意在眼中青。樵子逗煙墅，漁翁宿沙汀。", "主人非楚客，莫謾譏獨醒。宿昔邢城功，道高心已冥。", "貪將到處士，放醉烏家亭。"]'),
('yuding-7','苕溪草堂自大曆三年夏新營洎秋及春…四十三韻','皎然','唐','御定全唐诗','yuding','','[]','萬慮皆可遺，愛山情不易。自從東溪住，始與人群隔。',516,'御定全唐詩/json/816.json','["萬慮皆可遺，愛山情不易。自從東溪住，始與人群隔。", "應物非宿心，遺身是吾策。先民崆峒子，淪景事金液。", "綺裏猶近名，於陵未泯跡。吾師逆流教，禪隱殊古昔。", "洗足臨潺湲，銷聲寄松柏。緗荷采堪服，柔草持可席。", "道心制野猿，法語授幽客。境淨萬象真，寄目皆有益。", "原上無情花，山中聽經石。竹生自蕭散，雲性常潔白。", "卻見羈世人，遠高摩霄翮。達賢觀此意，煩想遂冰蘖。", "伊予戰苦勝，覽境情不溺。智以動念昏，功由無心積。", "形骸爾何有，生死誰所戚。為與勝悟冥，不憂頹齡迫。", "春風自駘蕩，禪地常闃寂。擲劄成柳枝，溉瓶養泉脈。", "道人知止足，盥漱聊自適。學外見古賢，頗令我心惕。", "眇綿雲官世，夢幻羽陵籍。鬼籙徒相矜，九原誰家宅。", "俗情封淺近，至理昧堯蹠。蹈善嗟沈冥，履仁傷堙厄。", "匠心聖亦尤，攻異天見責。試以慧眼觀，斯言諒可覿。", "外事非吾道，忘緣倦所曆。中宵廢耳目，形靜神不役。", "色天夜清迥，花漏時滴瀝。東風吹杉梧，幽月到石壁。", "此中一悟心，可與千載敵。故交徒好我，筐中無咫尺。", "潘生入空門，祖師傳秘賾。湯子自天德，精詣功不僻。", "放世與成名，兩圖在所擇。吾高鴟夷子，身退無瑕摘。", "吾嘉魯仲連，功成棄珪璧。二賢兼彼才，晚節何感激。", "不然作山計，改服我下澤。君隳元亮冠，我脫潛師屐。", "倚臥高松根，共逃金閨籍。"]'),
('yuding-8','答裴集、陽伯明二賢各垂贈二十韻今以一章用酬兩作','皎然','唐','御定全唐诗','yuding','','[]','知音如瓊枝，天生為予有。攀折若無階，何殊天上柳。',240,'御定全唐詩/json/816.json','["知音如瓊枝，天生為予有。攀折若無階，何殊天上柳。", "裴生清通嗣，陽子盛德後。詩名比元長，賦體淩延壽。", "珠生驪龍頷，或生靈蛇口。何似雙瓊章，英英曜吾手。", "白日不可汙，清源肯容垢。持此山上心，待君忘情友。", "且伴丘壑賞，未隨名宦誘。坐石代瓊茵，制荷捐艾綬。", "清宵集我寺，烹茗開禪牖。發論教可垂，正文言不朽。", "白雲供詩用，清吹生座右。不嫌逸令醉，莫試仙壺酒。", "皎皎尋陽隱，千年可為偶。一從漢道平，世事無紛糾。", "星文齊七政，天軸明二鬥。召士揚弓旌，知君在林藪。", "莫學潁陽子，請師高山叟。出處藩我君，還來會厓阜。"]'),
('yuding-9','答豆盧居士春夜遊東園見懷','皎然','唐','御定全唐诗','yuding','','[]','春意賞不足，承夕步東園。事表精慮遠，月中華木繁。',48,'御定全唐詩/json/816.json','["春意賞不足，承夕步東園。事表精慮遠，月中華木繁。", "開襟寄清景，遐想屬空門。安得纚芳屣，看君幽徑萱。"]'),
('yuding-10','寄崔萬芳夔','皎然','唐','御定全唐诗','yuding','','[]','氣殺高隼擊，惜芳步寒林。風搖蒼琅根，霜剪荍y9心。',73,'御定全唐詩/json/816.json','["氣殺高隼擊，惜芳步寒林。風搖蒼琅根，霜剪荍y9心。", "歸思忽眇眇，佳氣亦沉沉。我身豈遐遠，如隔湘漢深。", "事邇智莫及，願乖情不任。遲君忘言侶，一笑開吾襟。"]'),
('yuding-11','訪朱放山人','皎然','唐','御定全唐诗','yuding','','[]','野人未相識，何處異鄉隔。昨逢雲陽信，教向雲陽覓。',60,'御定全唐詩/json/816.json','["野人未相識，何處異鄉隔。昨逢雲陽信，教向雲陽覓。", "空聞天上風，飄颻不可覿。應非矍鑠翁，或是滄浪客。", "早晚從我遊，共攜春山策。"]'),
('yuding-12','晚冬廢溪東寺懷李司直縱','皎然','唐','御定全唐诗','yuding','','[]','廢溪無人跡，益見離思深。歸來始昨日，恍惚驚歲陰。',156,'御定全唐詩/json/816.json','["廢溪無人跡，益見離思深。歸來始昨日，恍惚驚歲陰。", "清想屬遙夜，圓景當空林。宿昔月未改，何如故人心。", "遊從間芳趾，搖落棲寒岑。眇眇湖上別，含情初至今。", "道流安寂寞，世路倦嶇嶔。此意欲誰見，懷賢獨難任。", "徽聲反冥默，夕籟何哀吟。禪念破離夢，吾師誡援琴。", "耿耿已及旦，曷由開此襟。幽期諒未偶，勝境徒自尋。", "安得西歸雲，因之傳素音。"]'),
('yuding-13','兵後與故人別，予西上，至今在揚楚，因有是寄','皎然','唐','御定全唐诗','yuding','','[]','日月不相待，思君魂屢驚。草玄寄揚子，作賦得蕪城。',84,'御定全唐詩/json/816.json','["日月不相待，思君魂屢驚。草玄寄揚子，作賦得蕪城。", "溫溫獨游跡，遙遙相望情。淮上春草歇，楚子秋風生。", "辟士天下盡，君何獨屏營。運開應佐世，業就可成名。", "誰借楚山住，年年事耦耕。"]'),
('yuding-14','因游支硎寺寄邢端公','皎然','唐','御定全唐诗','yuding','','[]','大廈資多士，掄材得豫章。清門推問望，早歲騁康莊。',384,'御定全唐詩/json/816.json','["大廈資多士，掄材得豫章。清門推問望，早歲騁康莊。", "作用方開物，聲名久擅場。丹延分塞郡，宿昔領戎行。", "始馭屏星乘，旋陰蔽茀棠。朝端瞻鶚立，關右仰鷹揚。", "威令兼甯朔，英聲重護羌。三軍成父子，雜虜避封疆。", "身執金吾貴，時遭寶運昌。雍容持漢槊，肅穆衛周堂。", "排難知臣節，攻疑定國章。一言明大義，千載揖休光。", "踐職勳庸列，修躬志行彰。優遊應慕陸，止足定師張。", "中扆懷殊政，南州佇小康。仁為桂江雨，威是柏台霜。", "謇諤言無隱，公忠禍不防。譴深辭紫禁，恩在副朱方。", "切玉鋒休淬，垂天翅罷翔。論文征賈馬，述隱許求羊。", "肘後看金碧，腰間笑水蒼。詩題白羽扇，酒挈綠油囊。", "曠達機何有，深沈器莫量。時應登古寺，佳趣在春岡。", "止水準香砌，鮮雲滿石床。山情何寂樂，塵世自飛揚。", "已遇爐峰社，還思緝蕙房。外心親地主，內學事空王。", "花會宜春淺，禪遊喜夜涼。高明依月境，蕭散躡庭芳。", "得道殊秦佚，隳名似楚狂。餘生於此足，不欲返韶陽。"]'),
('yuding-15','同諸公奉侍祭嶽瀆使大理盧幼平自會稽回經平望…不至','皎然','唐','御定全唐诗','yuding','','[]','望祀崇周典，皇華出漢庭。紫泥頒會計，玄酒薦芳馨。',120,'御定全唐詩/json/816.json','["望祀崇周典，皇華出漢庭。紫泥頒會計，玄酒薦芳馨。", "聖慮多虔肅，齋心合至靈。占祥刊史竹，筮日數堯蓂。", "禮秩加新命，朝章篤理刑。敷誠通北闕，遺愛在南亭。", "苕水思曾泛，磯山憶重經。清風門客仰，佳頌國人聽。", "攀桂留卿月，徵文待使星。春郊回駟牡，遙識故林青。"]'),
('yuding-16','早秋桐廬思歸示道諺上人','皎然','唐','御定全唐诗','yuding','','[]','桐江秋信早，憶在故山時。靜夜風鳴磬，無人竹掃墀。',48,'御定全唐詩/json/816.json','["桐江秋信早，憶在故山時。靜夜風鳴磬，無人竹掃墀。", "猿來觸淨水，鳥下啄寒梨。可即關吾事，歸心自有期。"]'),
('yuding-17','勞勞山居寄呈吳處士','皎然','唐','御定全唐诗','yuding','','[]','山事由來別，只應中老身。寒園掃綻栗，秋浪拾乾薪。',48,'御定全唐詩/json/816.json','["山事由來別，只應中老身。寒園掃綻栗，秋浪拾乾薪。", "領鶴閒書竹，誇雲笑向人。俗家相去遠，野水作東鄰。"]'),
('yuding-18','寄報德寺從上人','皎然','唐','御定全唐诗','yuding','','[]','宗流許身子，物表養高閑。空色清涼寺，秋聲鼓吹山。',48,'御定全唐詩/json/816.json','["宗流許身子，物表養高閑。空色清涼寺，秋聲鼓吹山。", "看心水磬後，行道雨花間。七葉翻章句，時時啟義關。"]'),
('yuding-19','山中月夜寄無錫長官','皎然','唐','御定全唐诗','yuding','','[]','湖上涼風早，雙峰月色秋。遙知秣陵令，今夜在西樓。',48,'御定全唐詩/json/816.json','["湖上涼風早，雙峰月色秋。遙知秣陵令，今夜在西樓。", "別葉蕭蕭下，含霜處處流。如何共清景，異縣不同遊。"]'),
('yuding-20','奉賀顏使君真卿二十八郎隔絕自河北遠歸','皎然','唐','御定全唐诗','yuding','','[]','相失值氛煙，才應掌上年。久離驚貌長，多難喜身全。',48,'御定全唐詩/json/816.json','["相失值氛煙，才應掌上年。久離驚貌長，多難喜身全。", "比信尚書重，如威太守憐。滿庭看玉樹，更有一枝連。"]'),
('yuding-21','題湖上蘭若示清會上人','皎然','唐','御定全唐诗','yuding','','[]','峰心惠忍寺，嵊頂謝公山。何似南湖近，芳洲一畝間。',48,'御定全唐詩/json/816.json','["峰心惠忍寺，嵊頂謝公山。何似南湖近，芳洲一畝間。", "意中雲木秀，事外水堂閑。永日無人到，時看獨鶴還。"]'),
('yuding-22','秋宵書事寄吳憑處士','皎然','唐','御定全唐诗','yuding','','[]','真性在方丈，寂寥無四鄰。秋天月色正，清夜道心真。',48,'御定全唐詩/json/816.json','["真性在方丈，寂寥無四鄰。秋天月色正，清夜道心真。", "大夢觀前事，浮名悟此身。不知庭樹意，榮落感何人。"]'),
('yuding-23','題山壁示道維上人','皎然','唐','御定全唐诗','yuding','','[]','獨居何意足，山色在前門。身野長無事，心冥自不言。',48,'御定全唐詩/json/816.json','["獨居何意足，山色在前門。身野長無事，心冥自不言。", "閑行數亂竹，靜坐照清源。物外從知少，禪徒不耐煩。"]'),
('yuding-24','晚秋登佛川南峰懷裴例','皎然','唐','御定全唐诗','yuding','','[]','登嶺望落日，眇然傷別魂。亭皋秋色遍，遊子在荊門。',48,'御定全唐詩/json/816.json','["登嶺望落日，眇然傷別魂。亭皋秋色遍，遊子在荊門。", "世故東西客，山空斷續猿。此心誰複見，寂寞偶芳蓀。"]'),
('yuding-25','訪陸處士羽','皎然','唐','御定全唐诗','yuding','','[]','太湖東西路，吳主古山前。所思不可見，歸鴻自翩翩。',48,'御定全唐詩/json/816.json','["太湖東西路，吳主古山前。所思不可見，歸鴻自翩翩。", "何山賞春茗，何處弄春泉。莫是滄浪子，悠悠一釣船。"]'),
('yuding-26','酬李侍禦萼題看心道場賦以眉毛腸心牙等五字','皎然','唐','御定全唐诗','yuding','','[]','我法從誰悟，心師是貫花。三塵觀種子，一雨發萌牙。',48,'御定全唐詩/json/816.json','["我法從誰悟，心師是貫花。三塵觀種子，一雨發萌牙。", "定起輪燈缺，宵分印月斜。了空如藏史，始肯會禪家。"]'),
('yuding-27','酬姚補闕南仲雲溪館中戲題隨書見寄','皎然','唐','御定全唐诗','yuding','','[]','寺溪臨使府，風景借仁祠。補袞周官貴，能名漢主思。',48,'御定全唐詩/json/816.json','["寺溪臨使府，風景借仁祠。補袞周官貴，能名漢主思。", "臥雲知獨處，望月憶同時。忽枉緘中贈，瓊瑤滿手持。"]'),
('yuding-28','春夜期裴都曹濟集心上人院不至','皎然','唐','御定全唐诗','yuding','','[]','東林期隱吏，日月為虛盈。遠望浮雲隔，空憐定水清。',48,'御定全唐詩/json/816.json','["東林期隱吏，日月為虛盈。遠望浮雲隔，空憐定水清。", "逍遙方外侶，荏苒府中情。漸聽寒鞞發，淵淵在郡城。"]'),
('yuding-29','和裴少府懷京兄弟','皎然','唐','御定全唐诗','yuding','','[]','宦游三楚外，家在五陵原。涼夜多歸夢，秋風滿故園。',48,'御定全唐詩/json/816.json','["宦游三楚外，家在五陵原。涼夜多歸夢，秋風滿故園。", "北書無遠信，西候獨傷魂。空念青門別，殷勤岐路言。"]'),
('yuding-30','和閻士和望池月答人','皎然','唐','御定全唐诗','yuding','','[]','片月忽臨池，雙蛾憶畫時。光浮空似粉，影散不成眉。',48,'御定全唐詩/json/816.json','["片月忽臨池，雙蛾憶畫時。光浮空似粉，影散不成眉。", "孤枕應驚夢，寒林正入帷。情知兩處望，莫怨獨相思。"]'),
('yuding-31','遙和塵外上人與陸澧夜集山寺問涅盤義兼賞陸生文卷','皎然','唐','御定全唐诗','yuding','','[]','共是竹林賢，心從貝葉傳。說經看月喻，開卷愛珠連。',48,'御定全唐詩/json/816.json','["共是竹林賢，心從貝葉傳。說經看月喻，開卷愛珠連。", "清淨遙城外，蕭疏古塔前。應隨北山子，高頂枕雲眠。"]'),
('yuding-32','春日和盧使君幼平開元寺聽妙奘上人講','皎然','唐','御定全唐诗','yuding','','[]','仁聖垂文在，虛空日月懸。陵遲追哲匠，宗旨發幽詮。',72,'御定全唐詩/json/816.json','["仁聖垂文在，虛空日月懸。陵遲追哲匠，宗旨發幽詮。", "法受諸侯請，心教四子傳。春生雪山草，香下棘林天。", "顧我從今日，聞經悟宿緣。涼山萬里去，應為教猶偏。"]'),
('yuding-33','答李侍禦問','皎然','唐','御定全唐诗','yuding','','[]','入道曾經離亂前，長幹古寺住多年。愛貧唯制蓮花足，',40,'御定全唐詩/json/816.json','["入道曾經離亂前，長幹古寺住多年。愛貧唯制蓮花足，", "身外空名何足問，吾心已出第三禪。"]'),
('yuding-34','奉酬李員外使君嘉佑蘇台屏營居春首有懷','皎然','唐','御定全唐诗','yuding','','[]','昔歲為邦初未識，今朝休沐始相親。移家水巷貧依靜，',40,'御定全唐詩/json/816.json','["昔歲為邦初未識，今朝休沐始相親。移家水巷貧依靜，", "登臨許作煙霞伴，高在方袍間幅巾。"]'),
('yuding-35','和李舍人使君紓題雲明府道室','皎然','唐','御定全唐诗','yuding','','[]','許令如今道姓雲，曾經西嶽事桐君。流霞手把應憐壽，',40,'御定全唐詩/json/816.json','["許令如今道姓雲，曾經西嶽事桐君。流霞手把應憐壽，", "桂陽亦是神仙守，分別無嗟兩地分。"]'),
('yuding-36','奉和陸中丞使君長源寒食日作','皎然','唐','御定全唐诗','yuding','','[]','寒食江天氣最清，庾公晨望動高情。因逢內火千家靜，',40,'御定全唐詩/json/816.json','["寒食江天氣最清，庾公晨望動高情。因逢內火千家靜，", "腰章本郡誰相似，數日臨人政已成。"]'),
('yuding-37','奉酬袁使君送陸灞卻回期道寺院','皎然','唐','御定全唐诗','yuding','','[]','欲別湖上客，暮期西林還。高歌風音表，放舟月色間。',36,'御定全唐詩/json/816.json','["欲別湖上客，暮期西林還。高歌風音表，放舟月色間。", "更人莫報夜，禪閣本無關。"]'),
('yuding-38','招韓武康章','皎然','唐','御定全唐诗','yuding','','[]','山僧雖不飲，酤酒引陶潛。此意無人別，多為俗士嫌。',24,'御定全唐詩/json/816.json','["山僧雖不飲，酤酒引陶潛。此意無人別，多為俗士嫌。"]'),
('yuding-39','秋居法華寺下院望高頂贈如獻上人','皎然','唐','御定全唐诗','yuding','','[]','峰色秋天見，松聲靜夜聞。影孤長不出，行道在寒雲。',24,'御定全唐詩/json/816.json','["峰色秋天見，松聲靜夜聞。影孤長不出，行道在寒雲。"]'),
('yuding-40','贈韋早陸羽','皎然','唐','御定全唐诗','yuding','','[]','只將陶與謝，終日可忘情。不欲多相識，逢人懶道名。',24,'御定全唐詩/json/816.json','["只將陶與謝，終日可忘情。不欲多相識，逢人懶道名。"]'),
('yuding-41','戲呈薛彝','皎然','唐','御定全唐诗','yuding','','[]','山僧不厭野，才子會須狂。何處銷君興，春風擺綠楊。',24,'御定全唐詩/json/816.json','["山僧不厭野，才子會須狂。何處銷君興，春風擺綠楊。"]'),
('yuding-42','贈顏主簿','皎然','唐','御定全唐诗','yuding','','[]','漢家儀禮盛，名教出諸顏。更見尚書後，能文在子山。',24,'御定全唐詩/json/816.json','["漢家儀禮盛，名教出諸顏。更見尚書後，能文在子山。"]'),
('yuding-43','贈融上人','皎然','唐','御定全唐诗','yuding','','[]','常愛西林寺，池中月出時。芭蕉一片葉，書取寄吾師。',24,'御定全唐詩/json/816.json','["常愛西林寺，池中月出時。芭蕉一片葉，書取寄吾師。"]'),
('yuding-44','聽寒更寄朱兵曹巨川','皎然','唐','御定全唐诗','yuding','','[]','欹枕聽寒更，寒更發還住。一夜千萬聲，幾聲到君處。',24,'御定全唐詩/json/816.json','["欹枕聽寒更，寒更發還住。一夜千萬聲，幾聲到君處。"]'),
('yuding-45','早春書懷寄李少府仲宣','皎然','唐','御定全唐诗','yuding','','[]','早年初問法，因悟目中花。忽值胡雛起，芟夷若亂麻。',84,'御定全唐詩/json/816.json','["早年初問法，因悟目中花。忽值胡雛起，芟夷若亂麻。", "脫身投彼岸，吊影念生涯。跡與空門合，心將世路賒。", "東田已蕪沒，南澗益傷嗟。崇替驚人事，凋殘感物華。", "知君過我裏，惆悵舊煙霞。"]'),
('yuding-46','贈和評事判官','皎然','唐','御定全唐诗','yuding','','[]','廷評年少法家流，心似澄江月正秋。學究天人知遠識，',40,'御定全唐詩/json/816.json','["廷評年少法家流，心似澄江月正秋。學究天人知遠識，", "清白比來誰見賞，憐君獨有富人侯。"]'),
('yuding-47','酬秦系山人題贈','皎然','唐','御定全唐诗','yuding','','[]','雲林出空烏未歸，松吹時飄雨浴衣。',32,'御定全唐詩/json/816.json','["雲林出空烏未歸，松吹時飄雨浴衣。", "石語花愁徒自詫，吾心見境盡為非。"]'),
('yuding-48','酬秦系山人戲贈','皎然','唐','御定全唐诗','yuding','','[]','正論禪寂忽狂歌，莫是塵心顛倒多。',32,'御定全唐詩/json/816.json','["正論禪寂忽狂歌，莫是塵心顛倒多。", "白足行花曾不染，黃囊貯酒欲如何。"]'),
('yuding-49','貽李湯','皎然','唐','御定全唐诗','yuding','','[]','茅氏常論七真記，壺公愛說三山事。甯知梅福在人間，',48,'御定全唐詩/json/816.json','["茅氏常論七真記，壺公愛說三山事。甯知梅福在人間，", "山中玉筍是仙藥，袖裏素書題養生。願隨黃鶴一輕舉，"]'),
('yuding-50','述祖德贈湖上諸沈','皎然','唐','御定全唐诗','yuding','','[]','我祖文章有盛名，千年海內重嘉聲。雪飛梁苑操奇賦，',88,'御定全唐詩/json/816.json','["我祖文章有盛名，千年海內重嘉聲。雪飛梁苑操奇賦，", "初看甲乙矜言語，對客偏能鴝鵒舞。飽用黃金無所求，", "歲晚高歌悲苦寒，空堂危坐百憂攢。昔時軒蓋金陵下，", "誰見予心獨飄泊，依山寄水似浮雲。"]'),
('yuding-51','舟行懷閻士和','皎然','唐','御定全唐诗','yuding','','[]','二月湖南春草遍，橫山渡口花如霰。',32,'御定全唐詩/json/816.json','["二月湖南春草遍，橫山渡口花如霰。", "相思一日在孤舟，空見歸雲兩三片。"]'),
('yuding-52','贈張道士','皎然','唐','御定全唐诗','yuding','','[]','玉京真子名太一，因服日華心如日。',32,'御定全唐詩/json/816.json','["玉京真子名太一，因服日華心如日。", "此心不許世人知，只向仙宮未曾出。"]'),
('yuding-53','戲呈吳馮','皎然','唐','御定全唐诗','yuding','','[]','世人不知心是道，只言道在他方妙。',32,'御定全唐詩/json/816.json','["世人不知心是道，只言道在他方妙。", "還如瞽者望長安，長安在西向東笑。"]'),
('yuding-54','宿山寺寄李中丞洪','皎然','唐','御定全唐诗','yuding','','[]','偶來中峰宿，閑坐見真境。寂寂孤月心，亭亭圓泉影。',44,'御定全唐詩/json/816.json','["偶來中峰宿，閑坐見真境。寂寂孤月心，亭亭圓泉影。", "□□□滿山，花落始知靜。從他半夜愁猿驚，"]'),
('yuding-55','戲贈吳馮','皎然','唐','御定全唐诗','yuding','','[]','予讀古人書，遂識古人面。不是識古人，邪正心自見。',48,'御定全唐詩/json/816.json','["予讀古人書，遂識古人面。不是識古人，邪正心自見。", "貴義輕財求俗譽，一錢與人便驕倨。昨朝為火今為冰，"]'),
('yuding-56','感興贈烏程李明府伯宜兼簡諸秀才','皎然','唐','御定全唐诗','yuding','','[]','門前峴山近，無路可登陟。徒愛峴山高，仰之常歎息。',36,'御定全唐詩/json/816.json','["門前峴山近，無路可登陟。徒愛峴山高，仰之常歎息。", "不如松與桂，生在重岩側。"]'),
('yuding-57','晚秋宿李軍道所居','皎然','唐','御定全唐诗','yuding','','[]','清溪路不遙，都尉每相招。落日休戎馬，秋風罷射雕。',48,'御定全唐詩/json/816.json','["清溪路不遙，都尉每相招。落日休戎馬，秋風罷射雕。", "朮花生野徑，柏實滿寒條。永夜依山府，禪心共寂寥。"]'),
('yuding-58','送陸判官歸杭州','皎然','唐','御定全唐诗','yuding','','[]','芳草潛州路，乘軺憶再旋。餘花故林下，殘月舊池邊。',48,'御定全唐詩/json/816.json','["芳草潛州路，乘軺憶再旋。餘花故林下，殘月舊池邊。", "峰色雲端寺，潮聲海上天。明朝富春渚，應見謝公船。"]');
